INSERT INTO public.training_library (age_group, training_number, exercises)
VALUES
  ('O8', 1, '{"session_a": [{"type": "warming_up", "title": "GEWOON TIKKERTJE", "content": "Methodiek\nElke speler heeft een bal aan zijn voet, behalve de tikker. De \ntikker probeert zo veel mogelijk spelers te tikken.\nVariatie:\n- De tikker heeft ook een bal.\n- De tikker kan spelers aftikken door hun bal weg te schoppen\nOpgelet!\nJe mag weer deelnemen als een \"vrije speler\" je weer \"vrij\" getikt \nheeft.Materialen\nDuur spel:10-15 min\nDuur ronde: 1 a 2 min\nAantal: 6-8 of meer spelers\nPylonen: 4 om het speelveld af te bakenen.\nBallen: voor iedere speler een balAanwijzingen\nWedstrijdopties:\nOptie 1: Tel het aantal getikte spelers.\nOptie 2: De getikte speler gaat aan de kant \nstaan.\nOptie 3: De getikte speler wordt de nieuwe \ntikker."}, {"type": "techniek", "title": "STAP 1: VAKGOOIEN", "content": "Methodiek\nIs een spel waarbij men probeert foutloos het hele vakkentraject \naf te leggen.\nA. Speler 1 staat bij de pylon, op 2 mtr. afstand, midden voor de \nvakken en gooit met een inworp de bal op speler 2.\nB. Speler 2 staat in het midden van het eerste vak en vangt de bal \nin de handen.\n- na elke geslaagde poging schuift de speler een vak op.\nOpgelet!\n- wie is het eerst klaar!\nVariatie:\n- aangooiafstand vergrotenMaterialen\nAantal spelers: 2\nAantal pylonen:11\nAantal ballen: 1\nAfstand tussen de pylonen: 1 meter\nDoordraaien:\n- wisselen van functie naar eigen inzicht.Aanwijzingen\n- gezicht naar de persoon naar wie hij gaat \ngooien.\n- beiden voeten houden contact met de \ngrond.\n- de bal achter het hoofd loslaten\n- beide handen op de bal houden.\n- voeten in de richting van het gooien."}, {"type": "partijvorm", "title": "PARTIJVORM 4:4 + 2 KEEPERS", "content": "Methodiek\nVier aanvallers moeten d.m.v. samenspel/ individuele actie 4 \nverdedigers uitspelen, om daarna in het tegenoverstaande doel te \nscoren.\nDe verdedigers kunnen de afgepakte bal scoren door hetzelfde \naan de andere kant van het vak te doen.\nOpgelet! \nBal buiten het veld, dan start het andere team de partij opnieuw.\nVariatie in uitvoering:\nMet 3 teams wisselen naar eigen inzicht.Materialen\nAantal spelers:8(12)+2(3) keepers\nAantal ballen: 5\nAantal pylonen: 4\nAfstand tussen pylonen:\nF-pupillen: 25m bij 20m\nE-pupillen: 30m bij 25m\nD-pupillen: 30m bij 25m\nC-junioren: 35m bij 30m\nB-,A-junioren: 40m bij 35m\nDoel: 2\nF- en E-pupillen: 5m bij 2m\nD-,C-,B-,A-junioren: 7.32m bij 2.44\nDoordraaien: \nHet winnende team blijft staan en het \nverliezende team wisselt met het 3e team.\nAls er na twee minuten nog niet is gescoord, dan \nwordt de partij die het langst in het veld staat \ngewisseld.Aanwijzingen\nBij de aanval coachen op:\n- het samenspelen vanuit een ruit vorm, \nwaarbij gebruik gemaakt moet worden van \nde vrije positie van de keeper (overtalsituatie)\n- het creëren van een twee tegen een situatie\n- het zo breed en diep mogelijk staan van de \ntwee buitenste spelers.\n- het rekening houden bij balverlies met \nomschakeling, ook bij het innemen van een \naanvallende positie.\nBij het verdedigen coachen op:\n- het knijpen, daar waar nodig\n- het coachen van elkaar ( het initiatief ligt bij \nde achterste speler).\n- het rekening houden bij balverovering met \nomschakeling.\nKeepers coachen op:\n- het altijd aanspeelbaar zijn bij balbezit\n- het coachen bij het verdedigen van je \nmedespelers\nOpmerkingen:\n- bij een partij op scherp mag men de bal vrij \nraken\n- accenten leggen op: individuele actie; \nscoren onder druk; snelle omschakeling;\n- in de organisatie aandacht voor: genoeg \nballen om het veld; strakke felle coaching"}], "session_b": [{"type": "warming_up", "title": "CLUBS / LANDENSPEL", "content": "Methodiek\nElke speler heeft een bal en dribbelt in het rond.\nIn de hoeken van het veld zijn vierkanten, die de namen dragen \nvan een voetbalclub of een land.\nBij het noemen van de naam van de club of het land moeten de \nspelers zo snel mogelijk naar het desbetreffende vak dribbelen en \ndaar met de voet op de bal blijven staan.\nDe laatst aangekomen speler krijgt een strafpunt.\nWinnaar is degene met de minste strafpunten.\nVariatie in aanbieden:\n- Met Kerst, Pasen of Sinterklaas gebruik je deze themagerichte \nnamen.\n- Spelers moeten de bal stoppen door b.v. op de bal te gaan zitten \nof iets anders te doen.Materialen\nAantal spelers: 4-10\nAantal ballen: elke speler 1 bal\nAantal pylonen: 16\nVeldafmeting: 20 bij 20 meter (incl. hoekvakken \nvan 4 bij 4 meter)Aanwijzingen\nSpelers coachen op:\n- De bal dichtbij je houden.\n- Probeer de bal zoveel mogelijk aan te raken.\n- Probeer bij iedere stap de bal een keer aan \nte raken.\n- Door het vele bal contact kunnen spelers \ngemakkelijker de bal sturen.\n- De bal moet onder de voet gestopt worden"}, {"type": "techniek", "title": "PENALTY SCHIETEN", "content": "Methodiek\nIn het doel staan twee pylonen. De afstand tusssen de pylon en de \npaal is 2 meter.\nDe spelers proberen de bal in de rechter- of linkerhoek te schieten \ntussen de pylon en de paal.\nWie schiet de meeste penalties tussen de pylon en de paal?\nVariatie in uitvoering:\n- de afstand tussen de pylon en de paal verkleinen.\n- een keeper op doel zetten.Materialen\nAantal spelers: 4- 8 + (2 keepers)\nAantal ballen: ieder speler een bal\nAantal pylonen: 6\nSchietafstand:\nF- pupillen: 7m\nE-pupillen: 8m\nD-,C-,B-,A-junioren: 11m\nDoelen: 2\nF- en E-pupillen: 5m bij 2m\nD-,C-,B-,A-junioren: 7.32m bij 2.44m\nDoordraaien:\n- elke speler haalt, nadat hij geschoten heeft, \nzijn eigen bal op en sluit achter in de andere rij \naan.Aanwijzingen\nSpelers coachen op:\n- geef de bal de juiste snelheid mee.\n- bal in het hart raken.\n- spanning in de voet.\n- standbeen iets voorbij de bal, bal blijft laag."}, {"type": "partijvorm", "title": "PARTIJVORM 4:4 + 2 KEEPERS", "content": "Methodiek\nVier aanvallers moeten d.m.v. samenspel/ individuele actie 4 \nverdedigers uitspelen, om daarna in het tegenoverstaande doel te \nscoren.\nDe verdedigers kunnen de afgepakte bal scoren door hetzelfde \naan de andere kant van het vak te doen.\nOpgelet! \nBal buiten het veld, dan start het andere team de partij opnieuw.\nVariatie in uitvoering:\nMet 3 teams wisselen naar eigen inzicht.Materialen\nAantal spelers:8(12)+2(3) keepers\nAantal ballen: 5\nAantal pylonen: 4\nAfstand tussen pylonen:\nF-pupillen: 25m bij 20m\nE-pupillen: 30m bij 25m\nD-pupillen: 30m bij 25m\nC-junioren: 35m bij 30m\nB-,A-junioren: 40m bij 35m\nDoel: 2\nF- en E-pupillen: 5m bij 2m\nD-,C-,B-,A-junioren: 7.32m bij 2.44\nDoordraaien: \nHet winnende team blijft staan en het \nverliezende team wisselt met het 3e team.\nAls er na twee minuten nog niet is gescoord, dan \nwordt de partij die het langst in het veld staat \ngewisseld.Aanwijzingen\nBij de aanval coachen op:\n- het samenspelen vanuit een ruit vorm, \nwaarbij gebruik gemaakt moet worden van \nde vrije positie van de keeper (overtalsituatie)\n- het creëren van een twee tegen een situatie\n- het zo breed en diep mogelijk staan van de \ntwee buitenste spelers.\n- het rekening houden bij balverlies met \nomschakeling, ook bij het innemen van een \naanvallende positie.\nBij het verdedigen coachen op:\n- het knijpen, daar waar nodig\n- het coachen van elkaar ( het initiatief ligt bij \nde achterste speler).\n- het rekening houden bij balverovering met \nomschakeling.\nKeepers coachen op:\n- het altijd aanspeelbaar zijn bij balbezit\n- het coachen bij het verdedigen van je \nmedespelers\nOpmerkingen:\n- bij een partij op scherp mag men de bal vrij \nraken\n- accenten leggen op: individuele actie; \nscoren onder druk; snelle omschakeling;\n- in de organisatie aandacht voor: genoeg \nballen om het veld; strakke felle coaching"}]}'::jsonb),
  ('O8', 2, '{"session_a": [{"type": "warming_up", "title": "POORT TIKKERTJE", "content": "Methodiek\n1 speler probeert als tikker de anderen te tikken. Een getikte speler blijft \nwijdbeens staan. Elke \"vrije speler\" kan hen weer \"vrij\" tikken door de bal onder \nhun poortje door te spelen en direct weer onder controle mee te nemen.Materialen\nDuur:10-15 min\nDuur ronde: 1 a 2 min\nAantal: 6-8 of meer spelers\nPylonen: 4 om het speelveld af te bakenen.\nBallen: iedere speler een bal."}, {"type": "techniek", "title": "STAP 1: HOEDJE TRAP", "content": "Methodiek\n2 ploegen, waarvan elke speler een bal heeft, proberen de over \nhet hele veld verspreid staande rode en gele hoedjes van de \npylonen te schieten.\nDe ploeg die dit het eerst voor elkaar krijgt, is de winnaar.\nVariatie:\n- inzet van een verdediger, die probeert de bal van de \ntegenstander te onderscheppen, voordat deze het hoedje raakt.Materialen\nAantal spelers: 6-10\nAantal hoedjes: 10 rode en 10 gele.\nAantal ballen: elke speler 1 bal.\nHesjes: 2 kleuren en voldoende voor iedere partij.\nAantal pylonen: 24 (4 voor het speelveld en 20 \nvoor het spel)\nAfstand tussen de pylonen:\n- Speelveld: 10 bij 10 meter\n- Pylonen met hoedjes naar eigen inzicht.Aanwijzingen\nSpelers coachen op:\n- met de binnenkant van de voet schieten\n- van dichtbij schieten\n- niet te zacht schieten\n- de bal snel pakken en de volgende \nomschieten."}, {"type": "partijvorm", "title": "PARTIJVORM 5:5 (2)", "content": "Methodiek\nVijf aanvallers moeten d.m.v. samenspel/ individuele actie 5 \nverdedigers uitspelen, om daarna in het tegenoverstaande doel te \nscoren.\nDe verdedigers kunnen de afgepakte bal scoren door hetzelfde \naan de andere kant van het vak te doen.\nOpgelet! \nBal buiten het veld, dan start het andere team de partij opnieuw.\nVariatie in uitvoering:\nMet 3 teams wisselen naar eigen inzicht.Materialen\nAantal spelers: 10(15)+2(3) keepers\nAantal ballen: 5\nAantal pylonen: 4\nAfstand tussen pylonen:\nF-pupillen: 30m bij 25m\nE-pupillen: 30m bij 25m\nDoel: 2\nF- en E-junioren: 5m bij 2m\nDoordraaien: \n- het winnende team blijft staan en het \nverliezende team wisselt met het 3e team.\n- geen score na twee minuten, dan wordt de \nlangst staande partij gewisseld.Aanwijzingen\nBij de aanval coachen op:\n- het samenspelen vanuit een diamantvorm\n- het uiteen bewegen bij balbezit\n- het voorkomen van buitenspel\n- het maken van keuzes ( 1:1 of overspelen) \naan de bal\n- het rekening houden met omschakeling bij \nbalverlies en ook bij het innemen van een \naanvallende positie.\nBij het verdedigen coachen op:\n- het knijpen, daar waar nodig\n- het gebruik maken van de buitenspelregel\n- het coachen van elkaar (het initiatief ligt bij \nde achterste speler)\n- het rekening houden met omschakeling bij \nbalverovering.\nKeepers coachen op:\n- het altijd aanspeelbaar zijn bij balbezit\n- het coachen van je medespelers bij het \nverdedigen.\nOpmerkingen:\n- bij een partij op scherp mag men de bal vrij \nraken\n- leg accenten op: de individuele actie, het \nscoren onder druk, een snelle omschakeling, \nde conditionele (anaeroob- lactisch)/ mentale \nfactoren\n- houdt in de organisatie ook aandacht voor: \ngenoeg ballen om het veld, een strakke felle \ncoaching."}], "session_b": [{"type": "warming_up", "title": "FLUIT / NUMMERSPEL", "content": "Methodiek\nElke speler dribbelt met een bal door het vak. De trainer gebruikt de vooraf aan \ngegeven tekens.\nBij het fluiten of het roepen van een nummer moeten de spelers de daarbij \nbehorende afgesproken tekens uitvoeren, zoals:\n- Naar de zijkant dribbelen\n- Een kapbeweging maken\n- De bal stil leggen onder de voet\n- Een versnelling maken met de bal aan de voet\n- De bal hooghouden.\n- Op de bal zitten\n- Wisselen van bal met een andere speler.\nOpgelet!\nMaak er een puntenspel van.\nWie behaalt de minste strafpunten?Materialen\nTijd: 10-15 min\nRonde tijden: 1 a 2 min\nPylonen: 4 pylonen om het speelveld uit te zetten\nBallen: iedere speler heeft een bal."}, {"type": "techniek", "title": "IN STROOMVORM (1)", "content": "Methodiek\nDeze vorm wordt uitgevoerd met twee rijen spelers.\nA. Speler 1 of 2 speelt de bal met de binnenkant van de buitenste \nvoet in op de trainer en loopt daarna achter zijn bal aan.\nB. De trainer neemt de bal aan en legt de bal stil voor de \ninlopende speler 1 of 2.\nC. Speler 1 of 2 schiet vervolgens de stilliggende bal op doel, etc.\nVariatie in uitvoering: \nNa elk schot wisselen van rij.Materialen\nAantal spelers: 8- 10\nAantal ballen: elke speler heeft een bal\nAantal pylonen: 2\nDoelen: 1\nF-t/m E-pupillen: 5m bij 2m\nD-t/m A-junioren: 7.32m bij 2.44m\nAfstand trainer tot het doel:\n1 ste jaars F-pupillen: 5 m\n2e jaars F-pupillen: 8 m\n1e jaars E-pupillen: 10 m\n2e jaars E-pupillen: 12 m\nD-pupillen: 14 m\nC-,B-,A-junioren: >16 m\nDoordraaien:\nElke speler haalt, nadat hij geschoten heeft, zijn \neigen bal op en sluit weer achter in de rij aan.Aanwijzingen\nSpelers coachen op:\n- Bal in het hart raken\n- Spanning in de voet\n- Raakvlak: Binnenkant of volle wreef, \nafhankelijk van de situatie.\n- Standbeen iets voorbij de bal, bal blijft laag.\n- Standbeen iets achter de bal, bal aan de \nonderkant raken, bal gaat omhoog.\n- De overgang van het aan komen lopen naar \nhet schieten moet vloeiend verlopen."}, {"type": "partijvorm", "title": "PARTIJVORM 5:5 (2)", "content": "Methodiek\nVijf aanvallers moeten d.m.v. samenspel/ individuele actie 5 \nverdedigers uitspelen, om daarna in het tegenoverstaande doel te \nscoren.\nDe verdedigers kunnen de afgepakte bal scoren door hetzelfde \naan de andere kant van het vak te doen.\nOpgelet! \nBal buiten het veld, dan start het andere team de partij opnieuw.\nVariatie in uitvoering:\nMet 3 teams wisselen naar eigen inzicht.Materialen\nAantal spelers: 10(15)+2(3) keepers\nAantal ballen: 5\nAantal pylonen: 4\nAfstand tussen pylonen:\nF-pupillen: 30m bij 25m\nE-pupillen: 30m bij 25m\nDoel: 2\nF- en E-junioren: 5m bij 2m\nDoordraaien: \n- het winnende team blijft staan en het \nverliezende team wisselt met het 3e team.\n- geen score na twee minuten, dan wordt de \nlangst staande partij gewisseld.Aanwijzingen\nBij de aanval coachen op:\n- het samenspelen vanuit een diamantvorm\n- het uiteen bewegen bij balbezit\n- het voorkomen van buitenspel\n- het maken van keuzes ( 1:1 of overspelen) \naan de bal\n- het rekening houden met omschakeling bij \nbalverlies en ook bij het innemen van een \naanvallende positie.\nBij het verdedigen coachen op:\n- het knijpen, daar waar nodig\n- het gebruik maken van de buitenspelregel\n- het coachen van elkaar (het initiatief ligt bij \nde achterste speler)\n- het rekening houden met omschakeling bij \nbalverovering.\nKeepers coachen op:\n- het altijd aanspeelbaar zijn bij balbezit\n- het coachen van je medespelers bij het \nverdedigen.\nOpmerkingen:\n- bij een partij op scherp mag men de bal vrij \nraken\n- leg accenten op: de individuele actie, het \nscoren onder druk, een snelle omschakeling, \nde conditionele (anaeroob- lactisch)/ mentale \nfactoren\n- houdt in de organisatie ook aandacht voor: \ngenoeg ballen om het veld, een strakke felle \ncoaching."}]}'::jsonb),
  ('O8', 3, '{"session_a": [{"type": "warming_up", "title": "OVERLOOPSPEL", "content": "Methodiek\nAlle spelers staan, op één speler na, met een bal aan de voet aan één zijde van \nhet speelveld.\nDe tikker staat ook met een bal aan de voet in het speelveld.\nOp een teken moeten de spelers de bal naar de overkant dribbelen. De tikker \nprobeert nu met de bal zoveel mogelijk spelers onderweg af te tikken.\nWie tikt de meeste spelers af in 2 beurten?\nOpgelet!\n- als je de bal niet bij je houdt dan ben je ook af.\nVariatie:\n- ook de tikker heeft de bal aan de voet\n- opvoeren van het aantal beurten. Materialen\nDuur:10-15 min\nDuur ronde: 1 a 2 min\nAantal: 6-12 spelers\nPylonen: 4 om het speelveld af te bakenen."}, {"type": "techniek", "title": "STAP 1: JEU DE VOETBAL", "content": "Methodiek\nDeze oefening wordt gespeelt met 2 spelers, die ieder met 3 \nballen bij een hoedje staan op de achterlijn.\nZij proberen nu de bal vanaf het hoedje zo dicht mogelijk, bij de, \nop 12 - 15 mtr. afstand geplaatste pylon, te spelen.\nDe winnaar is degene die de meeste ballen dichtbij de pylon weet \nte krijgen.\nVariatie:\n- afstand vergrotenMaterialen\nAantal spelers: 2\nAantal ballen: elke speler heeft 3 ballen\nHoedje: per tweetal 1 hoedje\nAantal pylonen: per tweetal één pylon\nAfstand tussen pylon en hoedje: 12-15 meterAanwijzingen\nSpelers coachen op:\n- schieten met de binnenkant van de voet.\n- standbeen in de richting van de pylon \nplaatsen\n- het schietbeen op de bal richten.\n- let goed op welke bal bij welke speler hoort"}, {"type": "partijvorm", "title": "PARTIJVORM 4:4 + 2 KEEPERS", "content": "Methodiek\nVier aanvallers moeten d.m.v. samenspel/ individuele actie 4 \nverdedigers uitspelen, om daarna in het tegenoverstaande doel te \nscoren.\nDe verdedigers kunnen de afgepakte bal scoren door hetzelfde \naan de andere kant van het vak te doen.\nOpgelet! \nBal buiten het veld, dan start het andere team de partij opnieuw.\nVariatie in uitvoering:\nMet 3 teams wisselen naar eigen inzicht.Materialen\nAantal spelers:8(12)+2(3) keepers\nAantal ballen: 5\nAantal pylonen: 4\nAfstand tussen pylonen:\nF-pupillen: 25m bij 20m\nE-pupillen: 30m bij 25m\nD-pupillen: 30m bij 25m\nC-junioren: 35m bij 30m\nB-,A-junioren: 40m bij 35m\nDoel: 2\nF- en E-pupillen: 5m bij 2m\nD-,C-,B-,A-junioren: 7.32m bij 2.44\nDoordraaien: \nHet winnende team blijft staan en het \nverliezende team wisselt met het 3e team.\nAls er na twee minuten nog niet is gescoord, dan \nwordt de partij die het langst in het veld staat \ngewisseld.Aanwijzingen\nBij de aanval coachen op:\n- het samenspelen vanuit een ruit vorm, \nwaarbij gebruik gemaakt moet worden van \nde vrije positie van de keeper (overtalsituatie)\n- het creëren van een twee tegen een situatie\n- het zo breed en diep mogelijk staan van de \ntwee buitenste spelers.\n- het rekening houden bij balverlies met \nomschakeling, ook bij het innemen van een \naanvallende positie.\nBij het verdedigen coachen op:\n- het knijpen, daar waar nodig\n- het coachen van elkaar ( het initiatief ligt bij \nde achterste speler).\n- het rekening houden bij balverovering met \nomschakeling.\nKeepers coachen op:\n- het altijd aanspeelbaar zijn bij balbezit\n- het coachen bij het verdedigen van je \nmedespelers\nOpmerkingen:\n- bij een partij op scherp mag men de bal vrij \nraken\n- accenten leggen op: individuele actie; \nscoren onder druk; snelle omschakeling;\n- in de organisatie aandacht voor: genoeg \nballen om het veld; strakke felle coaching"}], "session_b": [{"type": "warming_up", "title": "LIJNEN SPEL", "content": "Methodiek\nDe spelers staan met de bal aan de voet op een door de trainer \naangegeven lijn van het 16- meter gebied. Op zijn teken dribbelen \nde spelers naar een door de trainer aangegeven andere lijn.\nOpgelet!\nGeen 16- meter gebied beschikbaar, maak dan gebruik van \nverschillend gekleurde pylonen of hoedjes om daarmee lijnen te \nvormen\nMaak bij de\" jongste jeugd\" gebruik van nummers.\nVariatie:\n- Geef elke speler bij aanvang 3 punten en haal bij de laatste \ntelkens 1 punt af. Winnaar is ook nu weer degene die over blijft.\n- Laatste valt steeds af en winnaar is degene die over blijft (alleen \ndoen als afsluiting van een training).Materialen\nAantal spelers: 4-14\nAantal pylonen: 10 (om eventueel de lijnen aan \nte geven)\nAantal ballen: elke speler 1 balAanwijzingen\nSpelers coachen op:\n- Draai eerst proef.\n- De bal moet wel steeds op de lijn onder de \nvoet stil liggen."}, {"type": "techniek", "title": "PARCOURS DRIBBELEN EN AFWERKEN", "content": "Methodiek\nDe spelers slalommen dribbelend het hele parcours door en werk \naf op doel.\nVariatie in aanbieden:\n- Varieer in uitvoeringssnelheid\n- Varieer onderlinge afstand pylonen.\n- Voer de oefening in wedstrijdvorm uit.Materialen\nAantal spelers: 4-10\nAantal ballen: elke speler 1 bal\nAantal pylonen: 8\nDoelen: 2\nOnderlinge afstand pylonen: 2 a 3 meterAanwijzingen\nSpelers coachen op:\n- Houdt de bal dichtbij je, maar niet onder je.\n- Probeer de bal zoveel mogelijk te raken.\n- Probeer de bal bij iedere stap te raken, dan \nkun je de bal ook beter sturen."}, {"type": "partijvorm", "title": "PARTIJVORM 4:4 + 2 KEEPERS", "content": "Methodiek\nVier aanvallers moeten d.m.v. samenspel/ individuele actie 4 \nverdedigers uitspelen, om daarna in het tegenoverstaande doel te \nscoren.\nDe verdedigers kunnen de afgepakte bal scoren door hetzelfde \naan de andere kant van het vak te doen.\nOpgelet! \nBal buiten het veld, dan start het andere team de partij opnieuw.\nVariatie in uitvoering:\nMet 3 teams wisselen naar eigen inzicht.Materialen\nAantal spelers:8(12)+2(3) keepers\nAantal ballen: 5\nAantal pylonen: 4\nAfstand tussen pylonen:\nF-pupillen: 25m bij 20m\nE-pupillen: 30m bij 25m\nD-pupillen: 30m bij 25m\nC-junioren: 35m bij 30m\nB-,A-junioren: 40m bij 35m\nDoel: 2\nF- en E-pupillen: 5m bij 2m\nD-,C-,B-,A-junioren: 7.32m bij 2.44\nDoordraaien: \nHet winnende team blijft staan en het \nverliezende team wisselt met het 3e team.\nAls er na twee minuten nog niet is gescoord, dan \nwordt de partij die het langst in het veld staat \ngewisseld.Aanwijzingen\nBij de aanval coachen op:\n- het samenspelen vanuit een ruit vorm, \nwaarbij gebruik gemaakt moet worden van \nde vrije positie van de keeper (overtalsituatie)\n- het creëren van een twee tegen een situatie\n- het zo breed en diep mogelijk staan van de \ntwee buitenste spelers.\n- het rekening houden bij balverlies met \nomschakeling, ook bij het innemen van een \naanvallende positie.\nBij het verdedigen coachen op:\n- het knijpen, daar waar nodig\n- het coachen van elkaar ( het initiatief ligt bij \nde achterste speler).\n- het rekening houden bij balverovering met \nomschakeling.\nKeepers coachen op:\n- het altijd aanspeelbaar zijn bij balbezit\n- het coachen bij het verdedigen van je \nmedespelers\nOpmerkingen:\n- bij een partij op scherp mag men de bal vrij \nraken\n- accenten leggen op: individuele actie; \nscoren onder druk; snelle omschakeling;\n- in de organisatie aandacht voor: genoeg \nballen om het veld; strakke felle coaching"}]}'::jsonb),
  ('O8', 4, '{"session_a": [{"type": "warming_up", "title": "DRIBBELTIKKERTJE", "content": "Methodiek\nAlle spelers, behalve de tikker, dribbelen met de bal aan de voet in het speelveld. \nDe tikker heeft zijn bal in de handen en moet nu met zijn bal proberen de bal van \neen dribbelende speler te tikken.\nAls dit is lukt, wordt de afgetikte speler de nieuwe tikker, etc. Materialen\nDuur:10-15 min\nDuur ronde: 1 a 2 min\nAantal: 6-12 spelers\nPylonen: 4 om het speelveld af te bakenen.\nAantal ballen: zoveel als nodig is voor het spel."}, {"type": "techniek", "title": "STAP 1: KEGELEN 1", "content": "Methodiek\n2 ploegen, iedere speler met 1 bal, proberen vanaf de achterlijn \nvan hun deel van het vak, de in het midden van het veld \ngeplaatste rode en gele hoedjes, van de pylonen te schieten.\nDe ploeg die dit het eerst voor elkaar krijgt, is de winnaar.\nVariatie:\n- inzet van een verdediger, die probeert de bal van de \ntegenstander te onderscheppen, voordat deze het hoedje raakt.Materialen\nAantal spelers: 6-10\nAantal hoedjes: 10 rode en 10 gele.\nAantal ballen: elke speler 1 bal.\nHesjes: 2 kleuren en voldoende voor iedere partij\nAantal pylonen: 24 (4 voor het speelveld en 20 \nvoor het spel)\nAfstand tussen de pylonen:\n- speelveld 25 bij 15 meter\n- pylonen met hoedjes naar eigen inzicht.Aanwijzingen\nSpelers coachen op:\n- met de binnenkant van de voet schieten.\n- van dichtbij schieten.\n- niet te zacht schieten.\n- de bal snel pakken en de volgende \nomschieten."}, {"type": "partijvorm", "title": "PARTIJVORM 5:5 (2)", "content": "Methodiek\nVijf aanvallers moeten d.m.v. samenspel/ individuele actie 5 \nverdedigers uitspelen, om daarna in het tegenoverstaande doel te \nscoren.\nDe verdedigers kunnen de afgepakte bal scoren door hetzelfde \naan de andere kant van het vak te doen.\nOpgelet! \nBal buiten het veld, dan start het andere team de partij opnieuw.\nVariatie in uitvoering:\nMet 3 teams wisselen naar eigen inzicht.Materialen\nAantal spelers: 10(15)+2(3) keepers\nAantal ballen: 5\nAantal pylonen: 4\nAfstand tussen pylonen:\nF-pupillen: 30m bij 25m\nE-pupillen: 30m bij 25m\nDoel: 2\nF- en E-junioren: 5m bij 2m\nDoordraaien: \n- het winnende team blijft staan en het \nverliezende team wisselt met het 3e team.\n- geen score na twee minuten, dan wordt de \nlangst staande partij gewisseld.Aanwijzingen\nBij de aanval coachen op:\n- het samenspelen vanuit een diamantvorm\n- het uiteen bewegen bij balbezit\n- het voorkomen van buitenspel\n- het maken van keuzes ( 1:1 of overspelen) \naan de bal\n- het rekening houden met omschakeling bij \nbalverlies en ook bij het innemen van een \naanvallende positie.\nBij het verdedigen coachen op:\n- het knijpen, daar waar nodig\n- het gebruik maken van de buitenspelregel\n- het coachen van elkaar (het initiatief ligt bij \nde achterste speler)\n- het rekening houden met omschakeling bij \nbalverovering.\nKeepers coachen op:\n- het altijd aanspeelbaar zijn bij balbezit\n- het coachen van je medespelers bij het \nverdedigen.\nOpmerkingen:\n- bij een partij op scherp mag men de bal vrij \nraken\n- leg accenten op: de individuele actie, het \nscoren onder druk, een snelle omschakeling, \nde conditionele (anaeroob- lactisch)/ mentale \nfactoren\n- houdt in de organisatie ook aandacht voor: \ngenoeg ballen om het veld, een strakke felle \ncoaching."}], "session_b": [{"type": "warming_up", "title": "OVERSTEEK SPEL", "content": "Methodiek\nAlle spelers staan met de bal aan de voet aan één kant van het \nveld en één speler staat zonder bal in het midden. Op een teken \nvan de trainer mogen de spelers proberen het veld over te steken. \nDe tikker moet vervolgens proberen de ballen van de spelers \nbuiten het veld te schieten.\nDe spelers van een weggeschoten bal gaan ook in het midden \nstaan om de bal af te pakken.\nVariatie:\n- De spelers moeten zelf hun weggetrapte bal ophalen en weer bij \nde groep aansluiten.\n- Weggeschoten bal ophalen en dan wachten om te zien wie er \nover blijft. De winnaar mag de nieuwe tikker zijn of aanwijzen.\n- Twee of meerdere afpakkers.Materialen\nTijd: 10-15 min\nPylonen: \n4 pylonen om het speelveld uit te zetten.\n2 pylonen/hoedjes om de middenlijn uit te zetten.\nBallen: iedere speler een bal op de tikker na die \nde ballen gaat afpakken.Aanwijzingen\n- Zorg dat de spelers de bal dicht bij zich \nhouden zodat ze de bal goed kunnen sturen.\n- Laat de spelers telkens op het teken van de \ntrainer starten."}, {"type": "techniek", "title": "PENALTY SCHIETEN", "content": "Methodiek\nIn het doel staan twee pylonen. De afstand tusssen de pylon en de \npaal is 2 meter.\nDe spelers proberen de bal in de rechter- of linkerhoek te schieten \ntussen de pylon en de paal.\nWie schiet de meeste penalties tussen de pylon en de paal?\nVariatie in uitvoering:\n- de afstand tussen de pylon en de paal verkleinen.\n- een keeper op doel zetten.Materialen\nAantal spelers: 4- 8 + (2 keepers)\nAantal ballen: ieder speler een bal\nAantal pylonen: 6\nSchietafstand:\nF- pupillen: 7m\nE-pupillen: 8m\nD-,C-,B-,A-junioren: 11m\nDoelen: 2\nF- en E-pupillen: 5m bij 2m\nD-,C-,B-,A-junioren: 7.32m bij 2.44m\nDoordraaien:\n- elke speler haalt, nadat hij geschoten heeft, \nzijn eigen bal op en sluit achter in de andere rij \naan.Aanwijzingen\nSpelers coachen op:\n- geef de bal de juiste snelheid mee.\n- bal in het hart raken.\n- spanning in de voet.\n- standbeen iets voorbij de bal, bal blijft laag."}, {"type": "partijvorm", "title": "PARTIJVORM 5:5 (2)", "content": "Methodiek\nVijf aanvallers moeten d.m.v. samenspel/ individuele actie 5 \nverdedigers uitspelen, om daarna in het tegenoverstaande doel te \nscoren.\nDe verdedigers kunnen de afgepakte bal scoren door hetzelfde \naan de andere kant van het vak te doen.\nOpgelet! \nBal buiten het veld, dan start het andere team de partij opnieuw.\nVariatie in uitvoering:\nMet 3 teams wisselen naar eigen inzicht.Materialen\nAantal spelers: 10(15)+2(3) keepers\nAantal ballen: 5\nAantal pylonen: 4\nAfstand tussen pylonen:\nF-pupillen: 30m bij 25m\nE-pupillen: 30m bij 25m\nDoel: 2\nF- en E-junioren: 5m bij 2m\nDoordraaien: \n- het winnende team blijft staan en het \nverliezende team wisselt met het 3e team.\n- geen score na twee minuten, dan wordt de \nlangst staande partij gewisseld.Aanwijzingen\nBij de aanval coachen op:\n- het samenspelen vanuit een diamantvorm\n- het uiteen bewegen bij balbezit\n- het voorkomen van buitenspel\n- het maken van keuzes ( 1:1 of overspelen) \naan de bal\n- het rekening houden met omschakeling bij \nbalverlies en ook bij het innemen van een \naanvallende positie.\nBij het verdedigen coachen op:\n- het knijpen, daar waar nodig\n- het gebruik maken van de buitenspelregel\n- het coachen van elkaar (het initiatief ligt bij \nde achterste speler)\n- het rekening houden met omschakeling bij \nbalverovering.\nKeepers coachen op:\n- het altijd aanspeelbaar zijn bij balbezit\n- het coachen van je medespelers bij het \nverdedigen.\nOpmerkingen:\n- bij een partij op scherp mag men de bal vrij \nraken\n- leg accenten op: de individuele actie, het \nscoren onder druk, een snelle omschakeling, \nde conditionele (anaeroob- lactisch)/ mentale \nfactoren\n- houdt in de organisatie ook aandacht voor: \ngenoeg ballen om het veld, een strakke felle \ncoaching."}]}'::jsonb),
  ('O8', 5, '{"session_a": [{"type": "warming_up", "title": "KETTINGTIKKERTJE", "content": "Methodiek\nBij dit spel staan alle spelers, met een bal aan de voet, in een vak. Twee spelers \nzijn de tikkers en moeten proberen de spelers uit te tikken door hun bal uit het \nspel te schieten.\nDe eerst afgetikte speler pakt, nadat zijn bal is uitgeschoten de hand van de \ntikker vast. Elke volgende afgetikte speler sluit daarna aan om zo een ketting te \nvormen. \nWelke verdediger behaalt de langste ketting (ofwel wie werken het beste samen?)\nOpmerking: \n- als tijdens het tkken de ketting breekt, dan mag de afgetikte speler gewoon \ndoorspelen.\nLet op: \n- de kettinggrootte mag niet groter worden dan 4 spelers (bij het vaststellen van \nhet resultaat wordt dan het totaal aantal afgetikte spelers geteld).Materialen\nPylonen: 4 pylonen om het speelveld uit te zetten.\nBallen: op een speler na heeft iedere speler een bal\nSpeeltijd: 10- 15 minuten"}, {"type": "techniek", "title": "STAP 1: KONINGEN", "content": "Methodiek\nTweetallen, staan op 10 - 15 mtr. afstand tegenover elkaar naast \neen 1 mtr. breed doeltje. Zij moeten proberen in het doeltje van \nde tegenoverstaande speler te scoren. \nWie de meeste goals maakt, binnen een bepaalde tijd of bepaald \naantal keer, is de \"koning\"!Materialen\nAantal spelers: 2-10 \nAantal doeltjes: per tweetal 1 doeltje\nAantal ballen: per tweetal 1 bal\nDoelgrootte: 1 meter\nAfstand tussen de doeltjes: 10-15 meterAanwijzingen\nSpelers coachen op:\n- schieten met de binnenkant van de voet\n- speelbeen loodrecht op de speelrichting\n- voetzool parallel met de grond."}, {"type": "partijvorm", "title": "PARTIJVORM 4:4 + 2 KEEPERS", "content": "Methodiek\nVier aanvallers moeten d.m.v. samenspel/ individuele actie 4 \nverdedigers uitspelen, om daarna in het tegenoverstaande doel te \nscoren.\nDe verdedigers kunnen de afgepakte bal scoren door hetzelfde \naan de andere kant van het vak te doen.\nOpgelet! \nBal buiten het veld, dan start het andere team de partij opnieuw.\nVariatie in uitvoering:\nMet 3 teams wisselen naar eigen inzicht.Materialen\nAantal spelers:8(12)+2(3) keepers\nAantal ballen: 5\nAantal pylonen: 4\nAfstand tussen pylonen:\nF-pupillen: 25m bij 20m\nE-pupillen: 30m bij 25m\nD-pupillen: 30m bij 25m\nC-junioren: 35m bij 30m\nB-,A-junioren: 40m bij 35m\nDoel: 2\nF- en E-pupillen: 5m bij 2m\nD-,C-,B-,A-junioren: 7.32m bij 2.44\nDoordraaien: \nHet winnende team blijft staan en het \nverliezende team wisselt met het 3e team.\nAls er na twee minuten nog niet is gescoord, dan \nwordt de partij die het langst in het veld staat \ngewisseld.Aanwijzingen\nBij de aanval coachen op:\n- het samenspelen vanuit een ruit vorm, \nwaarbij gebruik gemaakt moet worden van \nde vrije positie van de keeper (overtalsituatie)\n- het creëren van een twee tegen een situatie\n- het zo breed en diep mogelijk staan van de \ntwee buitenste spelers.\n- het rekening houden bij balverlies met \nomschakeling, ook bij het innemen van een \naanvallende positie.\nBij het verdedigen coachen op:\n- het knijpen, daar waar nodig\n- het coachen van elkaar ( het initiatief ligt bij \nde achterste speler).\n- het rekening houden bij balverovering met \nomschakeling.\nKeepers coachen op:\n- het altijd aanspeelbaar zijn bij balbezit\n- het coachen bij het verdedigen van je \nmedespelers\nOpmerkingen:\n- bij een partij op scherp mag men de bal vrij \nraken\n- accenten leggen op: individuele actie; \nscoren onder druk; snelle omschakeling;\n- in de organisatie aandacht voor: genoeg \nballen om het veld; strakke felle coaching"}], "session_b": [{"type": "warming_up", "title": "PAPEGAAIEN", "content": "Methodiek\nElk tweetal heeft één bal. Eén speler, zonder bal, loopt voorop en \nbepaald de koers door het vak. De andere speler, met bal, \nprobeert hem overal te volgen.\nOpgelet!\nBewaak de onderlinge afstand van circa 2 mtr.Materialen\nTijd: 10-15 min\nRonde tijden: 1 a 2 min\nPylonen: 4 pylonen om het speelveld uit te zetten\nBallen: per tweetal een balAanwijzingen\n- Maak makkelijke loopacties en maak het \nlater moeilijker\n- Maak het speelveld groter/ kleiner om het \nvoor de spelers makkelijker/ moeilijker te \nmaken. \n- Een kleiner speelveld is moeilijker omdat de \nspelers dichter op elkaar lopen."}, {"type": "techniek", "title": "IN STROOMVORM (1)", "content": "Methodiek\nDeze vorm wordt uitgevoerd met twee rijen spelers.\nA. Speler 1 of 2 speelt de bal met de binnenkant van de buitenste \nvoet in op de trainer en loopt daarna achter zijn bal aan.\nB. De trainer neemt de bal aan en legt de bal stil voor de \ninlopende speler 1 of 2.\nC. Speler 1 of 2 schiet vervolgens de stilliggende bal op doel, etc.\nVariatie in uitvoering: \nNa elk schot wisselen van rij.Materialen\nAantal spelers: 8- 10\nAantal ballen: elke speler heeft een bal\nAantal pylonen: 2\nDoelen: 1\nF-t/m E-pupillen: 5m bij 2m\nD-t/m A-junioren: 7.32m bij 2.44m\nAfstand trainer tot het doel:\n1 ste jaars F-pupillen: 5 m\n2e jaars F-pupillen: 8 m\n1e jaars E-pupillen: 10 m\n2e jaars E-pupillen: 12 m\nD-pupillen: 14 m\nC-,B-,A-junioren: >16 m\nDoordraaien:\nElke speler haalt, nadat hij geschoten heeft, zijn \neigen bal op en sluit weer achter in de rij aan.Aanwijzingen\nSpelers coachen op:\n- Bal in het hart raken\n- Spanning in de voet\n- Raakvlak: Binnenkant of volle wreef, \nafhankelijk van de situatie.\n- Standbeen iets voorbij de bal, bal blijft laag.\n- Standbeen iets achter de bal, bal aan de \nonderkant raken, bal gaat omhoog.\n- De overgang van het aan komen lopen naar \nhet schieten moet vloeiend verlopen."}, {"type": "partijvorm", "title": "PARTIJVORM 4:4 + 2 KEEPERS", "content": "Methodiek\nVier aanvallers moeten d.m.v. samenspel/ individuele actie 4 \nverdedigers uitspelen, om daarna in het tegenoverstaande doel te \nscoren.\nDe verdedigers kunnen de afgepakte bal scoren door hetzelfde \naan de andere kant van het vak te doen.\nOpgelet! \nBal buiten het veld, dan start het andere team de partij opnieuw.\nVariatie in uitvoering:\nMet 3 teams wisselen naar eigen inzicht.Materialen\nAantal spelers:8(12)+2(3) keepers\nAantal ballen: 5\nAantal pylonen: 4\nAfstand tussen pylonen:\nF-pupillen: 25m bij 20m\nE-pupillen: 30m bij 25m\nD-pupillen: 30m bij 25m\nC-junioren: 35m bij 30m\nB-,A-junioren: 40m bij 35m\nDoel: 2\nF- en E-pupillen: 5m bij 2m\nD-,C-,B-,A-junioren: 7.32m bij 2.44\nDoordraaien: \nHet winnende team blijft staan en het \nverliezende team wisselt met het 3e team.\nAls er na twee minuten nog niet is gescoord, dan \nwordt de partij die het langst in het veld staat \ngewisseld.Aanwijzingen\nBij de aanval coachen op:\n- het samenspelen vanuit een ruit vorm, \nwaarbij gebruik gemaakt moet worden van \nde vrije positie van de keeper (overtalsituatie)\n- het creëren van een twee tegen een situatie\n- het zo breed en diep mogelijk staan van de \ntwee buitenste spelers.\n- het rekening houden bij balverlies met \nomschakeling, ook bij het innemen van een \naanvallende positie.\nBij het verdedigen coachen op:\n- het knijpen, daar waar nodig\n- het coachen van elkaar ( het initiatief ligt bij \nde achterste speler).\n- het rekening houden bij balverovering met \nomschakeling.\nKeepers coachen op:\n- het altijd aanspeelbaar zijn bij balbezit\n- het coachen bij het verdedigen van je \nmedespelers\nOpmerkingen:\n- bij een partij op scherp mag men de bal vrij \nraken\n- accenten leggen op: individuele actie; \nscoren onder druk; snelle omschakeling;\n- in de organisatie aandacht voor: genoeg \nballen om het veld; strakke felle coaching"}]}'::jsonb),
  ('O8', 6, '{"session_a": [{"type": "warming_up", "title": "PANNA GAME", "content": "Methodiek\nElke speler, op een na heeft een bal. Op een teken van de trainer \nmoeten de speler zonder bal, binnen een vooraf aangegeven tijd, \nzoveel mogelijk ballen van de andere spelers buiten het speelveld \nte trappen.\nElke speler moet zijn weggetrapte bal direct weer ophalen en op \nde plaats waar de bal is uitgeschoten gaan staan met de benen \nwijd en de bal boven hun hoofd in hun handen. De andere spelers \ndie nog niet zijn uitgeschoten kunnen hun medespelers vrij maken \ndoor de bal door de benen van de afgeschoten spelers te spelen. \nAls de tijd voorbij is wordt het aantal spelers dat nog met hun bal \nboven hun hoofd staan geteld. Het spel is voorbij als de \nverdedigers alle spelers met de bal boven hun hoofd hebben \nstaan.\nWie haalt het hoogste aantal?\nVariatie:\n- meer verdedigers of minder verdedigers.Materialen\nTijd: 10-15 min\nRonde tijden: 1 a 2 min\nPylonen: 4 pylonen om het speelveld uit te zetten\nBallen: Op een speler na heeft iedere speler een \nbal.Aanwijzingen\nVoor de verdedigers:\n- samenwerken en samen afspreken waar je \nde ballen gaat uitschieten. Want waar je de \nballen uitschiet daar moeten de spelers gaan \nstaan met hun bal. Uiteindelijk krijg je dan \neen grote groep spelers bij elkaar waardoor 1 \nof 2 spelers deze kunnen verdedigen en de \nandere kunnen de rest gaan uitschieten. (dit \nis de enige mogelijkheid om iederee af te \nkrijgen.)\nVoor de aanvallers:\n- kijken waar de verdedigers zijn. Op snelheid \nde verdedigers passeren en proberen je \nmedespelers vrij proberen te maken."}, {"type": "techniek", "title": "STAP 1: RAAK DE BAL", "content": "Methodiek\n2 ploegen, waarvan elke speler een bal heeft, staan tegenover \nelkaar op de achterlijn met in het midden een \"opvallende bal\". \nDe 2 groepen proberen de \"opvallende bal\" vanaf hun achterlijn \nover de lijn van de tegenstander te schieten.\n- het team dat de bal het eerst over de lijn van de tegenstander \nkrijgt scoort 1 punt\n- na elke score wordt de bal weer in het midden gelegd en start \nhet spel opnieuw.Materialen\nAantal spelers: 6-10\nAantal ballen: elke speler 1 bal en 1 \"opvallende \nbal\".\nAantal pylonen: 4 \nAfstand tussen de pylonen: 20 bij 15 meterAanwijzingen\nSpelers coachen op:\n- schieten met de binnenkant van de voet\n- standbeen in de richting van de bal\n- het schietbeen op de bal richten\n- gaat de bal uit dan komt die terug in het \nmidden ten hoogte van de plek waar de bal \nuit ging."}, {"type": "partijvorm", "title": "PARTIJVORM 5:5 (2)", "content": "Methodiek\nVijf aanvallers moeten d.m.v. samenspel/ individuele actie 5 \nverdedigers uitspelen, om daarna in het tegenoverstaande doel te \nscoren.\nDe verdedigers kunnen de afgepakte bal scoren door hetzelfde \naan de andere kant van het vak te doen.\nOpgelet! \nBal buiten het veld, dan start het andere team de partij opnieuw.\nVariatie in uitvoering:\nMet 3 teams wisselen naar eigen inzicht.Materialen\nAantal spelers: 10(15)+2(3) keepers\nAantal ballen: 5\nAantal pylonen: 4\nAfstand tussen pylonen:\nF-pupillen: 30m bij 25m\nE-pupillen: 30m bij 25m\nDoel: 2\nF- en E-junioren: 5m bij 2m\nDoordraaien: \n- het winnende team blijft staan en het \nverliezende team wisselt met het 3e team.\n- geen score na twee minuten, dan wordt de \nlangst staande partij gewisseld.Aanwijzingen\nBij de aanval coachen op:\n- het samenspelen vanuit een diamantvorm\n- het uiteen bewegen bij balbezit\n- het voorkomen van buitenspel\n- het maken van keuzes ( 1:1 of overspelen) \naan de bal\n- het rekening houden met omschakeling bij \nbalverlies en ook bij het innemen van een \naanvallende positie.\nBij het verdedigen coachen op:\n- het knijpen, daar waar nodig\n- het gebruik maken van de buitenspelregel\n- het coachen van elkaar (het initiatief ligt bij \nde achterste speler)\n- het rekening houden met omschakeling bij \nbalverovering.\nKeepers coachen op:\n- het altijd aanspeelbaar zijn bij balbezit\n- het coachen van je medespelers bij het \nverdedigen.\nOpmerkingen:\n- bij een partij op scherp mag men de bal vrij \nraken\n- leg accenten op: de individuele actie, het \nscoren onder druk, een snelle omschakeling, \nde conditionele (anaeroob- lactisch)/ mentale \nfactoren\n- houdt in de organisatie ook aandacht voor: \ngenoeg ballen om het veld, een strakke felle \ncoaching."}], "session_b": [{"type": "warming_up", "title": "SIGNAAL SPEL", "content": "Methodiek\nAlle spelers staan met een bal naast elkaar in één rij voor de \ntrainer. Vooraf spreekt de trainer met de spelers bepaalde tekens \naf. Op een teken van de trainer voeren de spelers bijbehorende \nopdracht uit.\nVoorbeelden zijn:\n- dribbelen op de plaats door de bal links rechts te tikken\n- dribbelen naar links of rechts.\n- voor uit of achteruit te dribbelen.\n- voeten beurtlinks links rechts op de bal zetten.\n- etc.Materialen\nTijd: 10-15 min\nPylonen: gebruik hiervoor de ruimte die u voor u \ntraining ter beschikking heeft.\nBallen: voor iedere speler een bal.Aanwijzingen\n- zorg dat elke speler voldoende ruimte heeft \nvoor het uitvoeren van de oefening.\n- houdt controle over de bal. Let er op dat de \nspelers de bal dichtbij zich houden.\n- doe eerst oefeningen zonder bal."}, {"type": "techniek", "title": "PARCOURS DRIBBELEN EN AFWERKEN", "content": "Methodiek\nDe spelers slalommen dribbelend het hele parcours door en werk \naf op doel.\nVariatie in aanbieden:\n- Varieer in uitvoeringssnelheid\n- Varieer onderlinge afstand pylonen.\n- Voer de oefening in wedstrijdvorm uit.Materialen\nAantal spelers: 4-10\nAantal ballen: elke speler 1 bal\nAantal pylonen: 8\nDoelen: 2\nOnderlinge afstand pylonen: 2 a 3 meterAanwijzingen\nSpelers coachen op:\n- Houdt de bal dichtbij je, maar niet onder je.\n- Probeer de bal zoveel mogelijk te raken.\n- Probeer de bal bij iedere stap te raken, dan \nkun je de bal ook beter sturen."}, {"type": "partijvorm", "title": "PARTIJVORM 5:5 (2)", "content": "Methodiek\nVijf aanvallers moeten d.m.v. samenspel/ individuele actie 5 \nverdedigers uitspelen, om daarna in het tegenoverstaande doel te \nscoren.\nDe verdedigers kunnen de afgepakte bal scoren door hetzelfde \naan de andere kant van het vak te doen.\nOpgelet! \nBal buiten het veld, dan start het andere team de partij opnieuw.\nVariatie in uitvoering:\nMet 3 teams wisselen naar eigen inzicht.Materialen\nAantal spelers: 10(15)+2(3) keepers\nAantal ballen: 5\nAantal pylonen: 4\nAfstand tussen pylonen:\nF-pupillen: 30m bij 25m\nE-pupillen: 30m bij 25m\nDoel: 2\nF- en E-junioren: 5m bij 2m\nDoordraaien: \n- het winnende team blijft staan en het \nverliezende team wisselt met het 3e team.\n- geen score na twee minuten, dan wordt de \nlangst staande partij gewisseld.Aanwijzingen\nBij de aanval coachen op:\n- het samenspelen vanuit een diamantvorm\n- het uiteen bewegen bij balbezit\n- het voorkomen van buitenspel\n- het maken van keuzes ( 1:1 of overspelen) \naan de bal\n- het rekening houden met omschakeling bij \nbalverlies en ook bij het innemen van een \naanvallende positie.\nBij het verdedigen coachen op:\n- het knijpen, daar waar nodig\n- het gebruik maken van de buitenspelregel\n- het coachen van elkaar (het initiatief ligt bij \nde achterste speler)\n- het rekening houden met omschakeling bij \nbalverovering.\nKeepers coachen op:\n- het altijd aanspeelbaar zijn bij balbezit\n- het coachen van je medespelers bij het \nverdedigen.\nOpmerkingen:\n- bij een partij op scherp mag men de bal vrij \nraken\n- leg accenten op: de individuele actie, het \nscoren onder druk, een snelle omschakeling, \nde conditionele (anaeroob- lactisch)/ mentale \nfactoren\n- houdt in de organisatie ook aandacht voor: \ngenoeg ballen om het veld, een strakke felle \ncoaching."}]}'::jsonb),
  ('O8', 7, '{"session_a": [{"type": "warming_up", "title": "GEWOON TIKKERTJE", "content": "Methodiek\nElke speler heeft een bal aan zijn voet, behalve de tikker. De \ntikker probeert zo veel mogelijk spelers te tikken.\nVariatie:\n- De tikker heeft ook een bal.\n- De tikker kan spelers aftikken door hun bal weg te schoppen\nOpgelet!\nJe mag weer deelnemen als een \"vrije speler\" je weer \"vrij\" getikt \nheeft.Materialen\nDuur spel:10-15 min\nDuur ronde: 1 a 2 min\nAantal: 6-8 of meer spelers\nPylonen: 4 om het speelveld af te bakenen.\nBallen: voor iedere speler een balAanwijzingen\nWedstrijdopties:\nOptie 1: Tel het aantal getikte spelers.\nOptie 2: De getikte speler gaat aan de kant \nstaan.\nOptie 3: De getikte speler wordt de nieuwe \ntikker."}, {"type": "techniek", "title": "STAP 1: VAK SCHIETEN", "content": "Methodiek\n2 ploegen, waarvan elke speler een bal heeft, staan achter elkaar \nbij het eerste hoedje. Vanaf dit punt moeten zij om beurten de bal \nin het vak proberen te spelen.\n- lukt dit, dan behaald men 1 punt. Bij 3 punten schuift men op \nnaar het tweede hoedje. Idem naar het derde en vierde hoedje.\nOpgelet!\n- bij drie opeenvolgende missers gaat men 1 plaats terug\n- winnaar is degene die het hele traject het eerst heeft afgelegd.\nVariatie:\n- bal met het andere been spelen.\n- vak vergroten/ verkleinen.\n- afstand naar het vak vergroten/ verkleinen.\nVariatie op organisatie vormen:\n- vanaf de middencircel in een klein vierkant proberen te schieten\n- vanaf de 16 meterlijn in een vierkant schieten\n- vanaf de 5 meterlijn de bal het dichst bij de 16 meter schieten \nen andersom.Materialen\nAantal spelers: 6-8\nAantal ballen: elke speler 1 bal.\nAantal pylonen: 8 (2 x 4 voor vierkant)\nAfstand tussen de pylonen: Vierkant 3 bij 2 meter\nHoedjes: 8 (2 x 4)\n1ste hoedje op 10 m\n2e hoedje op 15 m\n3e hoedje op 20 m\n4e hoedje op 25 mAanwijzingen\nSpelers coachen op:\n- schieten met de binnenkant van de voet\n- standbeen in de richting van het vak\n- het schietbeen hier loodrecht op gericht \nhouden."}, {"type": "partijvorm", "title": "PARTIJVORM 4:4 + 2 KEEPERS", "content": "Methodiek\nVier aanvallers moeten d.m.v. samenspel/ individuele actie 4 \nverdedigers uitspelen, om daarna in het tegenoverstaande doel te \nscoren.\nDe verdedigers kunnen de afgepakte bal scoren door hetzelfde \naan de andere kant van het vak te doen.\nOpgelet! \nBal buiten het veld, dan start het andere team de partij opnieuw.\nVariatie in uitvoering:\nMet 3 teams wisselen naar eigen inzicht.Materialen\nAantal spelers:8(12)+2(3) keepers\nAantal ballen: 5\nAantal pylonen: 4\nAfstand tussen pylonen:\nF-pupillen: 25m bij 20m\nE-pupillen: 30m bij 25m\nD-pupillen: 30m bij 25m\nC-junioren: 35m bij 30m\nB-,A-junioren: 40m bij 35m\nDoel: 2\nF- en E-pupillen: 5m bij 2m\nD-,C-,B-,A-junioren: 7.32m bij 2.44\nDoordraaien: \nHet winnende team blijft staan en het \nverliezende team wisselt met het 3e team.\nAls er na twee minuten nog niet is gescoord, dan \nwordt de partij die het langst in het veld staat \ngewisseld.Aanwijzingen\nBij de aanval coachen op:\n- het samenspelen vanuit een ruit vorm, \nwaarbij gebruik gemaakt moet worden van \nde vrije positie van de keeper (overtalsituatie)\n- het creëren van een twee tegen een situatie\n- het zo breed en diep mogelijk staan van de \ntwee buitenste spelers.\n- het rekening houden bij balverlies met \nomschakeling, ook bij het innemen van een \naanvallende positie.\nBij het verdedigen coachen op:\n- het knijpen, daar waar nodig\n- het coachen van elkaar ( het initiatief ligt bij \nde achterste speler).\n- het rekening houden bij balverovering met \nomschakeling.\nKeepers coachen op:\n- het altijd aanspeelbaar zijn bij balbezit\n- het coachen bij het verdedigen van je \nmedespelers\nOpmerkingen:\n- bij een partij op scherp mag men de bal vrij \nraken\n- accenten leggen op: individuele actie; \nscoren onder druk; snelle omschakeling;\n- in de organisatie aandacht voor: genoeg \nballen om het veld; strakke felle coaching"}], "session_b": [{"type": "warming_up", "title": "DRIBBEL KAP (RECHTHOEK)", "content": "Methodiek\nElke speler heeft een bal en dribbelt de bal naar het midden van \nde linker pylonen van het eerste vierkant. Daar aangekomen \nneemt hij de bal met een kapbeweging mee naar de eerste \nrechter pylon.\nIdem, in het tweede vierkant.\nDaarna dribbelt hij de bal terug en sluit achter in de rij aan.\nVariatie in aanbieden:\nVarieer de snelheid.Materialen\nAantal spelers: 4-14\nAantal ballen: elke speler 1 bal\nAantal pylonen: 6\nAfstand tussen de pylonen: 12 á 15 meter.Aanwijzingen\nSpelers coachen op:\n- Houdt de bal dichtbij je, maar niet onder je.\n- Let goed op de uitvoering van de techniek.\n- De volgende speler kan starten als de \nvoorgaande speler start met het tweede deel."}, {"type": "techniek", "title": "PENALTY SCHIETEN", "content": "Methodiek\nIn het doel staan twee pylonen. De afstand tusssen de pylon en de \npaal is 2 meter.\nDe spelers proberen de bal in de rechter- of linkerhoek te schieten \ntussen de pylon en de paal.\nWie schiet de meeste penalties tussen de pylon en de paal?\nVariatie in uitvoering:\n- de afstand tussen de pylon en de paal verkleinen.\n- een keeper op doel zetten.Materialen\nAantal spelers: 4- 8 + (2 keepers)\nAantal ballen: ieder speler een bal\nAantal pylonen: 6\nSchietafstand:\nF- pupillen: 7m\nE-pupillen: 8m\nD-,C-,B-,A-junioren: 11m\nDoelen: 2\nF- en E-pupillen: 5m bij 2m\nD-,C-,B-,A-junioren: 7.32m bij 2.44m\nDoordraaien:\n- elke speler haalt, nadat hij geschoten heeft, \nzijn eigen bal op en sluit achter in de andere rij \naan.Aanwijzingen\nSpelers coachen op:\n- geef de bal de juiste snelheid mee.\n- bal in het hart raken.\n- spanning in de voet.\n- standbeen iets voorbij de bal, bal blijft laag."}, {"type": "partijvorm", "title": "PARTIJVORM 4:4 + 2 KEEPERS", "content": "Methodiek\nVier aanvallers moeten d.m.v. samenspel/ individuele actie 4 \nverdedigers uitspelen, om daarna in het tegenoverstaande doel te \nscoren.\nDe verdedigers kunnen de afgepakte bal scoren door hetzelfde \naan de andere kant van het vak te doen.\nOpgelet! \nBal buiten het veld, dan start het andere team de partij opnieuw.\nVariatie in uitvoering:\nMet 3 teams wisselen naar eigen inzicht.Materialen\nAantal spelers:8(12)+2(3) keepers\nAantal ballen: 5\nAantal pylonen: 4\nAfstand tussen pylonen:\nF-pupillen: 25m bij 20m\nE-pupillen: 30m bij 25m\nD-pupillen: 30m bij 25m\nC-junioren: 35m bij 30m\nB-,A-junioren: 40m bij 35m\nDoel: 2\nF- en E-pupillen: 5m bij 2m\nD-,C-,B-,A-junioren: 7.32m bij 2.44\nDoordraaien: \nHet winnende team blijft staan en het \nverliezende team wisselt met het 3e team.\nAls er na twee minuten nog niet is gescoord, dan \nwordt de partij die het langst in het veld staat \ngewisseld.Aanwijzingen\nBij de aanval coachen op:\n- het samenspelen vanuit een ruit vorm, \nwaarbij gebruik gemaakt moet worden van \nde vrije positie van de keeper (overtalsituatie)\n- het creëren van een twee tegen een situatie\n- het zo breed en diep mogelijk staan van de \ntwee buitenste spelers.\n- het rekening houden bij balverlies met \nomschakeling, ook bij het innemen van een \naanvallende positie.\nBij het verdedigen coachen op:\n- het knijpen, daar waar nodig\n- het coachen van elkaar ( het initiatief ligt bij \nde achterste speler).\n- het rekening houden bij balverovering met \nomschakeling.\nKeepers coachen op:\n- het altijd aanspeelbaar zijn bij balbezit\n- het coachen bij het verdedigen van je \nmedespelers\nOpmerkingen:\n- bij een partij op scherp mag men de bal vrij \nraken\n- accenten leggen op: individuele actie; \nscoren onder druk; snelle omschakeling;\n- in de organisatie aandacht voor: genoeg \nballen om het veld; strakke felle coaching"}]}'::jsonb),
  ('O8', 8, '{"session_a": [{"type": "warming_up", "title": "POORT TIKKERTJE", "content": "Methodiek\n1 speler probeert als tikker de anderen te tikken. Een getikte speler blijft \nwijdbeens staan. Elke \"vrije speler\" kan hen weer \"vrij\" tikken door de bal onder \nhun poortje door te spelen en direct weer onder controle mee te nemen.Materialen\nDuur:10-15 min\nDuur ronde: 1 a 2 min\nAantal: 6-8 of meer spelers\nPylonen: 4 om het speelveld af te bakenen.\nBallen: iedere speler een bal.\nDRIBBELEN MET DE BAL, MET LINKS, RECHTS EN TUSSEN DE VOETEN\nMethodiek\nElke speler heeft een bal. De spelers dribbelen de bal met links, \nrechts en tussen de voeten, het uitgezette vierkant rond.\nA. Dribbelen met de buitenkant van de linker voet.\nB. Dribbelen met de bal tussen de voeten; links rechts heen en \nweer.\nC. Dribbelen met de buitenkant van rechter voet.\nD. Dribbelen met de bal tussen de voeten; links rechts heen en \nweer.\nVariatie:\n- Varieer onderlinge afstand pylonen\n- Varieer in uitvoeringssnelheid.Materialen\nAantal spelers: 4-10\nAantal ballen: elke speler 1 bal\nAantal pylonen: 4\nOnderling afstand pylonen: 10 a 12 meterAanwijzingen\nSpelers coachen op:\n- De bal dichtbij je houden, maar niet onder \nje.\n- Probeer de bal zoveel mogelijk te raken.\n- Probeer de bal bij iedere stap te raken, dan \nkun je de bal ook beter sturen."}, {"type": "techniek", "title": "STAP 1: VAK SCHIETEN MET DRIBBELEN", "content": "Methodiek\n2 ploegen, bestaande uit 3 spelers met bal, staan bij de eerste \npylon.\nA. - de spelers moeten vanaf dit punt met de bal dribbelen naar \nde tweede pylon.\nB. - vervolgens in één keer schieten in het vak.\nLukt dit, dan behaald men 1 punt.\nOpgelet!\n- dribbelen en schieten moet in één beweging\n- winnaar is de ploeg met de meeste punten.\nVariatie:\n- bal met het andere been spelen\n- vak vergroten/ verkleinen\n- afstand naar het vak vergroten/ verkleinen.Materialen\nAantal spelers: 6-10\nAantal ballen: elke speler 1 bal\nAantal pylonen: 12\nAfstand tussen de pylonen:\n- Vierkant 3 bij 2 meter\n- Schietafstand:10, 15 of 20 meter\n- Dribbelafstand; 6 meterAanwijzingen\nSpelers coachen op:\n- schieten met de binnenkant van de voet\n- speelbeen loodrecht op de speelrichting\n- de overgang van de dribbel naar het \nschieten moet vloeiend verlopen."}, {"type": "partijvorm", "title": "PARTIJVORM 5:5 (2)", "content": "Methodiek\nVijf aanvallers moeten d.m.v. samenspel/ individuele actie 5 \nverdedigers uitspelen, om daarna in het tegenoverstaande doel te \nscoren.\nDe verdedigers kunnen de afgepakte bal scoren door hetzelfde \naan de andere kant van het vak te doen.\nOpgelet! \nBal buiten het veld, dan start het andere team de partij opnieuw.\nVariatie in uitvoering:\nMet 3 teams wisselen naar eigen inzicht.Materialen\nAantal spelers: 10(15)+2(3) keepers\nAantal ballen: 5\nAantal pylonen: 4\nAfstand tussen pylonen:\nF-pupillen: 30m bij 25m\nE-pupillen: 30m bij 25m\nDoel: 2\nF- en E-junioren: 5m bij 2m\nDoordraaien: \n- het winnende team blijft staan en het \nverliezende team wisselt met het 3e team.\n- geen score na twee minuten, dan wordt de \nlangst staande partij gewisseld.Aanwijzingen\nBij de aanval coachen op:\n- het samenspelen vanuit een diamantvorm\n- het uiteen bewegen bij balbezit\n- het voorkomen van buitenspel\n- het maken van keuzes ( 1:1 of overspelen) \naan de bal\n- het rekening houden met omschakeling bij \nbalverlies en ook bij het innemen van een \naanvallende positie.\nBij het verdedigen coachen op:\n- het knijpen, daar waar nodig\n- het gebruik maken van de buitenspelregel\n- het coachen van elkaar (het initiatief ligt bij \nde achterste speler)\n- het rekening houden met omschakeling bij \nbalverovering.\nKeepers coachen op:\n- het altijd aanspeelbaar zijn bij balbezit\n- het coachen van je medespelers bij het \nverdedigen.\nOpmerkingen:\n- bij een partij op scherp mag men de bal vrij \nraken\n- leg accenten op: de individuele actie, het \nscoren onder druk, een snelle omschakeling, \nde conditionele (anaeroob- lactisch)/ mentale \nfactoren\n- houdt in de organisatie ook aandacht voor: \ngenoeg ballen om het veld, een strakke felle \ncoaching."}], "session_b": [{"type": "warming_up", "title": "POORT TIKKERTJE", "content": "Methodiek\n1 speler probeert als tikker de anderen te tikken. Een getikte speler blijft \nwijdbeens staan. Elke \"vrije speler\" kan hen weer \"vrij\" tikken door de bal onder \nhun poortje door te spelen en direct weer onder controle mee te nemen.Materialen\nDuur:10-15 min\nDuur ronde: 1 a 2 min\nAantal: 6-8 of meer spelers\nPylonen: 4 om het speelveld af te bakenen.\nBallen: iedere speler een bal.\nDRIBBELEN MET DE BAL, MET LINKS, RECHTS EN TUSSEN DE VOETEN\nMethodiek\nElke speler heeft een bal. De spelers dribbelen de bal met links, \nrechts en tussen de voeten, het uitgezette vierkant rond.\nA. Dribbelen met de buitenkant van de linker voet.\nB. Dribbelen met de bal tussen de voeten; links rechts heen en \nweer.\nC. Dribbelen met de buitenkant van rechter voet.\nD. Dribbelen met de bal tussen de voeten; links rechts heen en \nweer.\nVariatie:\n- Varieer onderlinge afstand pylonen\n- Varieer in uitvoeringssnelheid.Materialen\nAantal spelers: 4-10\nAantal ballen: elke speler 1 bal\nAantal pylonen: 4\nOnderling afstand pylonen: 10 a 12 meterAanwijzingen\nSpelers coachen op:\n- De bal dichtbij je houden, maar niet onder \nje.\n- Probeer de bal zoveel mogelijk te raken.\n- Probeer de bal bij iedere stap te raken, dan \nkun je de bal ook beter sturen."}, {"type": "techniek", "title": "IN STROOMVORM (1)", "content": "Methodiek\nDeze vorm wordt uitgevoerd met twee rijen spelers.\nA. Speler 1 of 2 speelt de bal met de binnenkant van de buitenste \nvoet in op de trainer en loopt daarna achter zijn bal aan.\nB. De trainer neemt de bal aan en legt de bal stil voor de \ninlopende speler 1 of 2.\nC. Speler 1 of 2 schiet vervolgens de stilliggende bal op doel, etc.\nVariatie in uitvoering: \nNa elk schot wisselen van rij.Materialen\nAantal spelers: 8- 10\nAantal ballen: elke speler heeft een bal\nAantal pylonen: 2\nDoelen: 1\nF-t/m E-pupillen: 5m bij 2m\nD-t/m A-junioren: 7.32m bij 2.44m\nAfstand trainer tot het doel:\n1 ste jaars F-pupillen: 5 m\n2e jaars F-pupillen: 8 m\n1e jaars E-pupillen: 10 m\n2e jaars E-pupillen: 12 m\nD-pupillen: 14 m\nC-,B-,A-junioren: >16 m\nDoordraaien:\nElke speler haalt, nadat hij geschoten heeft, zijn \neigen bal op en sluit weer achter in de rij aan.Aanwijzingen\nSpelers coachen op:\n- Bal in het hart raken\n- Spanning in de voet\n- Raakvlak: Binnenkant of volle wreef, \nafhankelijk van de situatie.\n- Standbeen iets voorbij de bal, bal blijft laag.\n- Standbeen iets achter de bal, bal aan de \nonderkant raken, bal gaat omhoog.\n- De overgang van het aan komen lopen naar \nhet schieten moet vloeiend verlopen."}, {"type": "partijvorm", "title": "PARTIJVORM 5:5 (2)", "content": "Methodiek\nVijf aanvallers moeten d.m.v. samenspel/ individuele actie 5 \nverdedigers uitspelen, om daarna in het tegenoverstaande doel te \nscoren.\nDe verdedigers kunnen de afgepakte bal scoren door hetzelfde \naan de andere kant van het vak te doen.\nOpgelet! \nBal buiten het veld, dan start het andere team de partij opnieuw.\nVariatie in uitvoering:\nMet 3 teams wisselen naar eigen inzicht.Materialen\nAantal spelers: 10(15)+2(3) keepers\nAantal ballen: 5\nAantal pylonen: 4\nAfstand tussen pylonen:\nF-pupillen: 30m bij 25m\nE-pupillen: 30m bij 25m\nDoel: 2\nF- en E-junioren: 5m bij 2m\nDoordraaien: \n- het winnende team blijft staan en het \nverliezende team wisselt met het 3e team.\n- geen score na twee minuten, dan wordt de \nlangst staande partij gewisseld.Aanwijzingen\nBij de aanval coachen op:\n- het samenspelen vanuit een diamantvorm\n- het uiteen bewegen bij balbezit\n- het voorkomen van buitenspel\n- het maken van keuzes ( 1:1 of overspelen) \naan de bal\n- het rekening houden met omschakeling bij \nbalverlies en ook bij het innemen van een \naanvallende positie.\nBij het verdedigen coachen op:\n- het knijpen, daar waar nodig\n- het gebruik maken van de buitenspelregel\n- het coachen van elkaar (het initiatief ligt bij \nde achterste speler)\n- het rekening houden met omschakeling bij \nbalverovering.\nKeepers coachen op:\n- het altijd aanspeelbaar zijn bij balbezit\n- het coachen van je medespelers bij het \nverdedigen.\nOpmerkingen:\n- bij een partij op scherp mag men de bal vrij \nraken\n- leg accenten op: de individuele actie, het \nscoren onder druk, een snelle omschakeling, \nde conditionele (anaeroob- lactisch)/ mentale \nfactoren\n- houdt in de organisatie ook aandacht voor: \ngenoeg ballen om het veld, een strakke felle \ncoaching."}]}'::jsonb),
  ('O8', 9, '{"session_a": [{"type": "warming_up", "title": "OVERLOOPSPEL", "content": "Methodiek\nAlle spelers staan, op één speler na, met een bal aan de voet aan één zijde van \nhet speelveld.\nDe tikker staat ook met een bal aan de voet in het speelveld.\nOp een teken moeten de spelers de bal naar de overkant dribbelen. De tikker \nprobeert nu met de bal zoveel mogelijk spelers onderweg af te tikken.\nWie tikt de meeste spelers af in 2 beurten?\nOpgelet!\n- als je de bal niet bij je houdt dan ben je ook af.\nVariatie:\n- ook de tikker heeft de bal aan de voet\n- opvoeren van het aantal beurten. Materialen\nDuur:10-15 min\nDuur ronde: 1 a 2 min\nAantal: 6-12 spelers\nPylonen: 4 om het speelveld af te bakenen."}, {"type": "techniek", "title": "STAP 1: VOETBAL CURLING", "content": "Methodiek\nVerdeel het speelveld in 5 vakken van elk 1 meter breed. De \nspelers schieten de bal op een afstand van 10 meter vanaf het \nmiddelste vak. \nHet behaalde aantal punten van de 3 pogingen wordt bij elkaar \nopgeteld.\nT.b.v. puntentelling:\n- middelste vak 5 punten\n- de vakken daarnaast 3 punten\n- buitenste vak 1 punt\n- daarbuiten 0\n- winnaar is degene met de meeste punten.\nVariatie:\n- schietafstand vergroten tot 15 en/ of 20 meter.Materialen\nAantal spelers: 2-4\nAantal pylonen: 20\nAantal ballen: elke speler 1 bal\nSchietafstand: 10, 15 en 20 meterAanwijzingen\nSpelers coachen op:\n- schieten met de binnenkant van de voet.\n- standbeen in de richting van het vak.\n- het schietbeen hier loodrecht op gericht \nhouden."}, {"type": "partijvorm", "title": "PARTIJVORM 4:4 + 2 KEEPERS", "content": "Methodiek\nVier aanvallers moeten d.m.v. samenspel/ individuele actie 4 \nverdedigers uitspelen, om daarna in het tegenoverstaande doel te \nscoren.\nDe verdedigers kunnen de afgepakte bal scoren door hetzelfde \naan de andere kant van het vak te doen.\nOpgelet! \nBal buiten het veld, dan start het andere team de partij opnieuw.\nVariatie in uitvoering:\nMet 3 teams wisselen naar eigen inzicht.Materialen\nAantal spelers:8(12)+2(3) keepers\nAantal ballen: 5\nAantal pylonen: 4\nAfstand tussen pylonen:\nF-pupillen: 25m bij 20m\nE-pupillen: 30m bij 25m\nD-pupillen: 30m bij 25m\nC-junioren: 35m bij 30m\nB-,A-junioren: 40m bij 35m\nDoel: 2\nF- en E-pupillen: 5m bij 2m\nD-,C-,B-,A-junioren: 7.32m bij 2.44\nDoordraaien: \nHet winnende team blijft staan en het \nverliezende team wisselt met het 3e team.\nAls er na twee minuten nog niet is gescoord, dan \nwordt de partij die het langst in het veld staat \ngewisseld.Aanwijzingen\nBij de aanval coachen op:\n- het samenspelen vanuit een ruit vorm, \nwaarbij gebruik gemaakt moet worden van \nde vrije positie van de keeper (overtalsituatie)\n- het creëren van een twee tegen een situatie\n- het zo breed en diep mogelijk staan van de \ntwee buitenste spelers.\n- het rekening houden bij balverlies met \nomschakeling, ook bij het innemen van een \naanvallende positie.\nBij het verdedigen coachen op:\n- het knijpen, daar waar nodig\n- het coachen van elkaar ( het initiatief ligt bij \nde achterste speler).\n- het rekening houden bij balverovering met \nomschakeling.\nKeepers coachen op:\n- het altijd aanspeelbaar zijn bij balbezit\n- het coachen bij het verdedigen van je \nmedespelers\nOpmerkingen:\n- bij een partij op scherp mag men de bal vrij \nraken\n- accenten leggen op: individuele actie; \nscoren onder druk; snelle omschakeling;\n- in de organisatie aandacht voor: genoeg \nballen om het veld; strakke felle coaching"}], "session_b": [{"type": "warming_up", "title": "DRIBBELKONING", "content": "Methodiek\nElke speler heeft een bal en dribbelt door het vierkant. Twee \n\"balafpakkers\" proberen de ballen van de andere spelers de bal \nuit het vak te schieten.\nBal kwijt, dan wordt je ook \"balafpakker\".\nDe speler die overblijft is dribbelkoning.\nVariatie:\nBij een te kleine groep volstaat 1 \"balafpakker\".Materialen\nAantal spelers: 6-8\nAantal ballen: elke speler 1 bal, behalve 2 \nbalafpakkers\nHesjes: de balafpakkers\nAantal pylonen: 4\nAfstand tussen de pylonen: speelveld: ongeveer \n10 bij 15 meterAanwijzingen\nSpelers coachen op:\n- De bal dichtbij je houden.\n- De bal goed afschermen.\n- Een andere kant opgaan als de afpakker \nnaar je toekomt."}, {"type": "techniek", "title": "PARCOURS DRIBBELEN EN AFWERKEN", "content": "Methodiek\nDe spelers slalommen dribbelend het hele parcours door en werk \naf op doel.\nVariatie in aanbieden:\n- Varieer in uitvoeringssnelheid\n- Varieer onderlinge afstand pylonen.\n- Voer de oefening in wedstrijdvorm uit.Materialen\nAantal spelers: 4-10\nAantal ballen: elke speler 1 bal\nAantal pylonen: 8\nDoelen: 2\nOnderlinge afstand pylonen: 2 a 3 meterAanwijzingen\nSpelers coachen op:\n- Houdt de bal dichtbij je, maar niet onder je.\n- Probeer de bal zoveel mogelijk te raken.\n- Probeer de bal bij iedere stap te raken, dan \nkun je de bal ook beter sturen."}, {"type": "partijvorm", "title": "PARTIJVORM 4:4 + 2 KEEPERS", "content": "Methodiek\nVier aanvallers moeten d.m.v. samenspel/ individuele actie 4 \nverdedigers uitspelen, om daarna in het tegenoverstaande doel te \nscoren.\nDe verdedigers kunnen de afgepakte bal scoren door hetzelfde \naan de andere kant van het vak te doen.\nOpgelet! \nBal buiten het veld, dan start het andere team de partij opnieuw.\nVariatie in uitvoering:\nMet 3 teams wisselen naar eigen inzicht.Materialen\nAantal spelers:8(12)+2(3) keepers\nAantal ballen: 5\nAantal pylonen: 4\nAfstand tussen pylonen:\nF-pupillen: 25m bij 20m\nE-pupillen: 30m bij 25m\nD-pupillen: 30m bij 25m\nC-junioren: 35m bij 30m\nB-,A-junioren: 40m bij 35m\nDoel: 2\nF- en E-pupillen: 5m bij 2m\nD-,C-,B-,A-junioren: 7.32m bij 2.44\nDoordraaien: \nHet winnende team blijft staan en het \nverliezende team wisselt met het 3e team.\nAls er na twee minuten nog niet is gescoord, dan \nwordt de partij die het langst in het veld staat \ngewisseld.Aanwijzingen\nBij de aanval coachen op:\n- het samenspelen vanuit een ruit vorm, \nwaarbij gebruik gemaakt moet worden van \nde vrije positie van de keeper (overtalsituatie)\n- het creëren van een twee tegen een situatie\n- het zo breed en diep mogelijk staan van de \ntwee buitenste spelers.\n- het rekening houden bij balverlies met \nomschakeling, ook bij het innemen van een \naanvallende positie.\nBij het verdedigen coachen op:\n- het knijpen, daar waar nodig\n- het coachen van elkaar ( het initiatief ligt bij \nde achterste speler).\n- het rekening houden bij balverovering met \nomschakeling.\nKeepers coachen op:\n- het altijd aanspeelbaar zijn bij balbezit\n- het coachen bij het verdedigen van je \nmedespelers\nOpmerkingen:\n- bij een partij op scherp mag men de bal vrij \nraken\n- accenten leggen op: individuele actie; \nscoren onder druk; snelle omschakeling;\n- in de organisatie aandacht voor: genoeg \nballen om het veld; strakke felle coaching"}]}'::jsonb),
  ('O8', 10, '{"session_a": [{"type": "warming_up", "title": "DRIBBELTIKKERTJE", "content": "Methodiek\nAlle spelers, behalve de tikker, dribbelen met de bal aan de voet in het speelveld. \nDe tikker heeft zijn bal in de handen en moet nu met zijn bal proberen de bal van \neen dribbelende speler te tikken.\nAls dit is lukt, wordt de afgetikte speler de nieuwe tikker, etc. Materialen\nDuur:10-15 min\nDuur ronde: 1 a 2 min\nAantal: 6-12 spelers\nPylonen: 4 om het speelveld af te bakenen.\nAantal ballen: zoveel als nodig is voor het spel."}, {"type": "techniek", "title": "STAP 1: DOOR DE BENEN SCHIETEN", "content": "Methodiek\nTweetallen, staan op 10 - 15 mtr. afstand tegenover elkaar met \nhun benen wijdt. Zij moeten proberen tussen de benen door van \nhun maatje te scoren. Wie de meeste goals maakt, binnen een \nbepaalde tijd of bepaald aantal keer, is de \"winnaar\".Materialen\nAantal spelers: 2-10 \nAantal ballen: per tweetal 1 bal\nAfstand tussen de spelers: 10-15 meterAanwijzingen\nSpelers coachen op:\n- schieten met de binnenkant van de voet.\n- speelbeen loodrecht op de speelrichting.\n- voetzool parallel met de grond."}, {"type": "partijvorm", "title": "PARTIJVORM 5:5 (2)", "content": "Methodiek\nVijf aanvallers moeten d.m.v. samenspel/ individuele actie 5 \nverdedigers uitspelen, om daarna in het tegenoverstaande doel te \nscoren.\nDe verdedigers kunnen de afgepakte bal scoren door hetzelfde \naan de andere kant van het vak te doen.\nOpgelet! \nBal buiten het veld, dan start het andere team de partij opnieuw.\nVariatie in uitvoering:\nMet 3 teams wisselen naar eigen inzicht.Materialen\nAantal spelers: 10(15)+2(3) keepers\nAantal ballen: 5\nAantal pylonen: 4\nAfstand tussen pylonen:\nF-pupillen: 30m bij 25m\nE-pupillen: 30m bij 25m\nDoel: 2\nF- en E-junioren: 5m bij 2m\nDoordraaien: \n- het winnende team blijft staan en het \nverliezende team wisselt met het 3e team.\n- geen score na twee minuten, dan wordt de \nlangst staande partij gewisseld.Aanwijzingen\nBij de aanval coachen op:\n- het samenspelen vanuit een diamantvorm\n- het uiteen bewegen bij balbezit\n- het voorkomen van buitenspel\n- het maken van keuzes ( 1:1 of overspelen) \naan de bal\n- het rekening houden met omschakeling bij \nbalverlies en ook bij het innemen van een \naanvallende positie.\nBij het verdedigen coachen op:\n- het knijpen, daar waar nodig\n- het gebruik maken van de buitenspelregel\n- het coachen van elkaar (het initiatief ligt bij \nde achterste speler)\n- het rekening houden met omschakeling bij \nbalverovering.\nKeepers coachen op:\n- het altijd aanspeelbaar zijn bij balbezit\n- het coachen van je medespelers bij het \nverdedigen.\nOpmerkingen:\n- bij een partij op scherp mag men de bal vrij \nraken\n- leg accenten op: de individuele actie, het \nscoren onder druk, een snelle omschakeling, \nde conditionele (anaeroob- lactisch)/ mentale \nfactoren\n- houdt in de organisatie ook aandacht voor: \ngenoeg ballen om het veld, een strakke felle \ncoaching."}], "session_b": [{"type": "warming_up", "title": "KONINGSPEL MET STOPPEN VAN DE BAL", "content": "Methodiek\nElke speler heeft een bal en op een teken van de trainer dribbelen \nde spelers de bal vanuit het beginvak naar het eindvak aan de \noverkant. Onderweg probeert de \"balafpakker\" de ballen van de \nandere spelers uit het vierkant te schieten.\nBal kwijt dan wordt je ook \"balafpakker\".\nWinnaar is de speler die overblijft.\nVariatie in aanbieden:\n- Elke speler start met 3 punten. \n- Bij balverlies gaat er telkens 1 punt af. \n- Bij 0 punten is de speler af.\nWinnaar is degene die over blijft.Materialen\nAantal spelers: 6-8\nHoedjes: 6\nAantal ballen: elke speler 1 bal, behalve de \nbalafpakker\nAantal pylonen: 6\nAfstand tussen de pylonen: speelveld: ongeveer \n10 bij 15 meterAanwijzingen\nSpelers coachen op:\n- De bal dichtbij je houden.\n- De bal goed afschermen.\n- Een andere kant opgaan als de tikker naar \nje toekomt.\n- Probeer snel de overkant te bereiken.\n- Afkappen over de achterlijn."}, {"type": "techniek", "title": "IN STROOMVORM (3)", "content": "Methodiek\nDeze vorm wordt uitgevoerd met twee rijen spelers.\nA. Speler 1 of 2 dribbelt de bal tot voorbij de 1e pylon en speelt \ndan de bal, met de binnenkant van de buitenste voet, in op de \ntrainer. Daarna loopt hij om de 2e pylon richting de trainer.\nB. De trainer heeft inmiddels de bal stil gelegd voor de inlopende \nspeler 1 of 2\nC. Speler 1 of 2 schiet vervolgens de stilliggende bal op doel.\nVariatie in uitvoering: \nNa elk schot wisselen van rij.Materialen\nAantal spelers: 8- 10\nAantal ballen: voor iedere speler een bal\nAantal pylonen: 6\nDoelen: 1\nF-t/m E-pupillen: 5m bij 2m\nD-t/m A-junioren: 7.32m bij 2.44m\nAfstand trainer tot het doel:\n1 ste jaars F-pupillen: 5 m\n2e jaars F-pupillen: 8 m\n1e jaars E-pupillen: 10 m\n2e jaars E-pupillen: 12 m\nD-pupillen: 14 m\nC-,B-,A-junioren: >16 m\nDoordraaien:\n- De spelers staan in twee groepen verdeeld aan \nweerszijden op circa 5mtr. van het doel.\n- Nadat een speler geschoten heeft haalt hij zijn \neigen bal op en sluit weer achter in de rij aan.Aanwijzingen\nSpelers coachen op:\n- Bal in het hart raken\n- Spanning in de voet\n- Raakvlak: Binnenkant of volle wreef, \nafhankelijk van de situatie.\n- Standbeen iets voorbij de bal, bal blijft laag.\n- Standbeen iets achter de bal, bal aan de \nonderkant raken, bal gaat omhoog.\n- De overgang van het aan komen lopen naar \nhet schieten moet vloeiend verlopen."}, {"type": "partijvorm", "title": "PARTIJVORM 5:5 (2)", "content": "Methodiek\nVijf aanvallers moeten d.m.v. samenspel/ individuele actie 5 \nverdedigers uitspelen, om daarna in het tegenoverstaande doel te \nscoren.\nDe verdedigers kunnen de afgepakte bal scoren door hetzelfde \naan de andere kant van het vak te doen.\nOpgelet! \nBal buiten het veld, dan start het andere team de partij opnieuw.\nVariatie in uitvoering:\nMet 3 teams wisselen naar eigen inzicht.Materialen\nAantal spelers: 10(15)+2(3) keepers\nAantal ballen: 5\nAantal pylonen: 4\nAfstand tussen pylonen:\nF-pupillen: 30m bij 25m\nE-pupillen: 30m bij 25m\nDoel: 2\nF- en E-junioren: 5m bij 2m\nDoordraaien: \n- het winnende team blijft staan en het \nverliezende team wisselt met het 3e team.\n- geen score na twee minuten, dan wordt de \nlangst staande partij gewisseld.Aanwijzingen\nBij de aanval coachen op:\n- het samenspelen vanuit een diamantvorm\n- het uiteen bewegen bij balbezit\n- het voorkomen van buitenspel\n- het maken van keuzes ( 1:1 of overspelen) \naan de bal\n- het rekening houden met omschakeling bij \nbalverlies en ook bij het innemen van een \naanvallende positie.\nBij het verdedigen coachen op:\n- het knijpen, daar waar nodig\n- het gebruik maken van de buitenspelregel\n- het coachen van elkaar (het initiatief ligt bij \nde achterste speler)\n- het rekening houden met omschakeling bij \nbalverovering.\nKeepers coachen op:\n- het altijd aanspeelbaar zijn bij balbezit\n- het coachen van je medespelers bij het \nverdedigen.\nOpmerkingen:\n- bij een partij op scherp mag men de bal vrij \nraken\n- leg accenten op: de individuele actie, het \nscoren onder druk, een snelle omschakeling, \nde conditionele (anaeroob- lactisch)/ mentale \nfactoren\n- houdt in de organisatie ook aandacht voor: \ngenoeg ballen om het veld, een strakke felle \ncoaching."}]}'::jsonb),
  ('O8', 11, '{"session_a": [{"type": "warming_up", "title": "KETTINGTIKKERTJE", "content": "Methodiek\nBij dit spel staan alle spelers, met een bal aan de voet, in een vak. Twee spelers \nzijn de tikkers en moeten proberen de spelers uit te tikken door hun bal uit het \nspel te schieten.\nDe eerst afgetikte speler pakt, nadat zijn bal is uitgeschoten de hand van de \ntikker vast. Elke volgende afgetikte speler sluit daarna aan om zo een ketting te \nvormen. \nWelke verdediger behaalt de langste ketting (ofwel wie werken het beste samen?)\nOpmerking: \n- als tijdens het tkken de ketting breekt, dan mag de afgetikte speler gewoon \ndoorspelen.\nLet op: \n- de kettinggrootte mag niet groter worden dan 4 spelers (bij het vaststellen van \nhet resultaat wordt dan het totaal aantal afgetikte spelers geteld).Materialen\nPylonen: 4 pylonen om het speelveld uit te zetten.\nBallen: op een speler na heeft iedere speler een bal\nSpeeltijd: 10- 15 minuten"}, {"type": "techniek", "title": "STAP 1: PYLONEN KONING", "content": "Methodiek\nTweetallen staan op 10 - 15 mtr. afstand tegenover elkaar achter \nhun pylon. Zij moeten proberen elkaars pylon omver te schieten.\n- wie de meeste pylonen raakt, heeft gewonnenMaterialen\nAantal spelers: 2-10 \nAantal doeltjes: elke speler een pylon\nAantal ballen: per tweetal 1 bal\nAfstand tussen de doeltjes: 10-15 meterAanwijzingen\nSpelers coachen op:\n- schieten met de binnenkant van de voet\n- speelbeen loodrecht op de speelrichting\n- voetzool parallel met de grond."}, {"type": "partijvorm", "title": "PARTIJVORM 4:4 + 2 KEEPERS", "content": "Methodiek\nVier aanvallers moeten d.m.v. samenspel/ individuele actie 4 \nverdedigers uitspelen, om daarna in het tegenoverstaande doel te \nscoren.\nDe verdedigers kunnen de afgepakte bal scoren door hetzelfde \naan de andere kant van het vak te doen.\nOpgelet! \nBal buiten het veld, dan start het andere team de partij opnieuw.\nVariatie in uitvoering:\nMet 3 teams wisselen naar eigen inzicht.Materialen\nAantal spelers:8(12)+2(3) keepers\nAantal ballen: 5\nAantal pylonen: 4\nAfstand tussen pylonen:\nF-pupillen: 25m bij 20m\nE-pupillen: 30m bij 25m\nD-pupillen: 30m bij 25m\nC-junioren: 35m bij 30m\nB-,A-junioren: 40m bij 35m\nDoel: 2\nF- en E-pupillen: 5m bij 2m\nD-,C-,B-,A-junioren: 7.32m bij 2.44\nDoordraaien: \nHet winnende team blijft staan en het \nverliezende team wisselt met het 3e team.\nAls er na twee minuten nog niet is gescoord, dan \nwordt de partij die het langst in het veld staat \ngewisseld.Aanwijzingen\nBij de aanval coachen op:\n- het samenspelen vanuit een ruit vorm, \nwaarbij gebruik gemaakt moet worden van \nde vrije positie van de keeper (overtalsituatie)\n- het creëren van een twee tegen een situatie\n- het zo breed en diep mogelijk staan van de \ntwee buitenste spelers.\n- het rekening houden bij balverlies met \nomschakeling, ook bij het innemen van een \naanvallende positie.\nBij het verdedigen coachen op:\n- het knijpen, daar waar nodig\n- het coachen van elkaar ( het initiatief ligt bij \nde achterste speler).\n- het rekening houden bij balverovering met \nomschakeling.\nKeepers coachen op:\n- het altijd aanspeelbaar zijn bij balbezit\n- het coachen bij het verdedigen van je \nmedespelers\nOpmerkingen:\n- bij een partij op scherp mag men de bal vrij \nraken\n- accenten leggen op: individuele actie; \nscoren onder druk; snelle omschakeling;\n- in de organisatie aandacht voor: genoeg \nballen om het veld; strakke felle coaching"}], "session_b": [{"type": "warming_up", "title": "PARCOURS DRIBBELEN", "content": "Methodiek\nDe spelers slalommen dribbelend het hele parcours door.\nVariatie in aanbieden:\n- Varieer in uitvoeringssnelheid\n- Varieer onderlinge afstand pylonen.\n- Voer de oefening in wedstrijdvorm uit.Materialen\nAantal spelers: 4-10\nAantal ballen: elke speler 1 bal\nAantal pylonen: 8\nOnderlinge afstand pylonen: 2 a 3 meterAanwijzingen\nSpelers coachen op:\n- Houdt de bal dichtbij je, maar niet onder je.\n- Probeer de bal zoveel mogelijk te raken.\n- Probeer de bal bij iedere stap te raken, dan \nkun je de bal ook beter sturen."}, {"type": "techniek", "title": "IN STROOMVORM (1)", "content": "Methodiek\nDeze vorm wordt uitgevoerd met twee rijen spelers.\nA. Speler 1 of 2 speelt de bal met de binnenkant van de buitenste \nvoet in op de trainer en loopt daarna achter zijn bal aan.\nB. De trainer neemt de bal aan en legt de bal stil voor de \ninlopende speler 1 of 2.\nC. Speler 1 of 2 schiet vervolgens de stilliggende bal op doel, etc.\nVariatie in uitvoering: \nNa elk schot wisselen van rij.Materialen\nAantal spelers: 8- 10\nAantal ballen: elke speler heeft een bal\nAantal pylonen: 2\nDoelen: 1\nF-t/m E-pupillen: 5m bij 2m\nD-t/m A-junioren: 7.32m bij 2.44m\nAfstand trainer tot het doel:\n1 ste jaars F-pupillen: 5 m\n2e jaars F-pupillen: 8 m\n1e jaars E-pupillen: 10 m\n2e jaars E-pupillen: 12 m\nD-pupillen: 14 m\nC-,B-,A-junioren: >16 m\nDoordraaien:\nElke speler haalt, nadat hij geschoten heeft, zijn \neigen bal op en sluit weer achter in de rij aan.Aanwijzingen\nSpelers coachen op:\n- Bal in het hart raken\n- Spanning in de voet\n- Raakvlak: Binnenkant of volle wreef, \nafhankelijk van de situatie.\n- Standbeen iets voorbij de bal, bal blijft laag.\n- Standbeen iets achter de bal, bal aan de \nonderkant raken, bal gaat omhoog.\n- De overgang van het aan komen lopen naar \nhet schieten moet vloeiend verlopen."}, {"type": "partijvorm", "title": "PARTIJVORM 4:4 + 2 KEEPERS", "content": "Methodiek\nVier aanvallers moeten d.m.v. samenspel/ individuele actie 4 \nverdedigers uitspelen, om daarna in het tegenoverstaande doel te \nscoren.\nDe verdedigers kunnen de afgepakte bal scoren door hetzelfde \naan de andere kant van het vak te doen.\nOpgelet! \nBal buiten het veld, dan start het andere team de partij opnieuw.\nVariatie in uitvoering:\nMet 3 teams wisselen naar eigen inzicht.Materialen\nAantal spelers:8(12)+2(3) keepers\nAantal ballen: 5\nAantal pylonen: 4\nAfstand tussen pylonen:\nF-pupillen: 25m bij 20m\nE-pupillen: 30m bij 25m\nD-pupillen: 30m bij 25m\nC-junioren: 35m bij 30m\nB-,A-junioren: 40m bij 35m\nDoel: 2\nF- en E-pupillen: 5m bij 2m\nD-,C-,B-,A-junioren: 7.32m bij 2.44\nDoordraaien: \nHet winnende team blijft staan en het \nverliezende team wisselt met het 3e team.\nAls er na twee minuten nog niet is gescoord, dan \nwordt de partij die het langst in het veld staat \ngewisseld.Aanwijzingen\nBij de aanval coachen op:\n- het samenspelen vanuit een ruit vorm, \nwaarbij gebruik gemaakt moet worden van \nde vrije positie van de keeper (overtalsituatie)\n- het creëren van een twee tegen een situatie\n- het zo breed en diep mogelijk staan van de \ntwee buitenste spelers.\n- het rekening houden bij balverlies met \nomschakeling, ook bij het innemen van een \naanvallende positie.\nBij het verdedigen coachen op:\n- het knijpen, daar waar nodig\n- het coachen van elkaar ( het initiatief ligt bij \nde achterste speler).\n- het rekening houden bij balverovering met \nomschakeling.\nKeepers coachen op:\n- het altijd aanspeelbaar zijn bij balbezit\n- het coachen bij het verdedigen van je \nmedespelers\nOpmerkingen:\n- bij een partij op scherp mag men de bal vrij \nraken\n- accenten leggen op: individuele actie; \nscoren onder druk; snelle omschakeling;\n- in de organisatie aandacht voor: genoeg \nballen om het veld; strakke felle coaching"}]}'::jsonb),
  ('O8', 12, '{"session_a": [{"type": "warming_up", "title": "PANNA GAME", "content": "Methodiek\nElke speler, op een na heeft een bal. Op een teken van de trainer \nmoeten de speler zonder bal, binnen een vooraf aangegeven tijd, \nzoveel mogelijk ballen van de andere spelers buiten het speelveld \nte trappen.\nElke speler moet zijn weggetrapte bal direct weer ophalen en op \nde plaats waar de bal is uitgeschoten gaan staan met de benen \nwijd en de bal boven hun hoofd in hun handen. De andere spelers \ndie nog niet zijn uitgeschoten kunnen hun medespelers vrij maken \ndoor de bal door de benen van de afgeschoten spelers te spelen. \nAls de tijd voorbij is wordt het aantal spelers dat nog met hun bal \nboven hun hoofd staan geteld. Het spel is voorbij als de \nverdedigers alle spelers met de bal boven hun hoofd hebben \nstaan.\nWie haalt het hoogste aantal?\nVariatie:\n- meer verdedigers of minder verdedigers.Materialen\nTijd: 10-15 min\nRonde tijden: 1 a 2 min\nPylonen: 4 pylonen om het speelveld uit te zetten\nBallen: Op een speler na heeft iedere speler een \nbal.Aanwijzingen\nVoor de verdedigers:\n- samenwerken en samen afspreken waar je \nde ballen gaat uitschieten. Want waar je de \nballen uitschiet daar moeten de spelers gaan \nstaan met hun bal. Uiteindelijk krijg je dan \neen grote groep spelers bij elkaar waardoor 1 \nof 2 spelers deze kunnen verdedigen en de \nandere kunnen de rest gaan uitschieten. (dit \nis de enige mogelijkheid om iederee af te \nkrijgen.)\nVoor de aanvallers:\n- kijken waar de verdedigers zijn. Op snelheid \nde verdedigers passeren en proberen je \nmedespelers vrij proberen te maken."}, {"type": "techniek", "title": "HEEN/TERUG (ENE EN ANDERE BEEN) IN LIJNVORM", "content": "Methodiek\nA. Speler 1 speelt naar speler 2:\n- speler 1 speelt de bal met de binnenkant van de linker- of \nrechter voet\n- speler 2 neemt de bal met de binnenkant van de linker- of \nrechter voet aan.\nB. Speler 2 speelt naar speler 1:\n- speler 2 speelt de bal met de binnenkant van de linker- of \nrechter voet.\n- speler 1 neemt de bal met de binnenkant van de linker- of \nrechter voet aan, etc.\nVariatie:\n- direct terugspelen.\nOpgelet!\n- spreek in kindertaal\n- speel de bal met de voet waarmee je aanneemt terugs of speel \nde bal met de andere voet terug of speel de bal direct terug met \nde voet waar je de bal op krijgt.Materialen\nAantal spelers: 2\nAantal ballen: 1 \nAantal pylonen: 2\nAfstand van pylonen: 1e en 2e jaars F-pupillen: \n2/3 m.Aanwijzingen\nAannemen:\n- bal moet binnen je bereik voor je liggen\n- houd snelheid na de aanname voor de \nvolgende actie\nSpelen binnenkant voet:\n- speel de bal met de juiste snelheid en op \nhet goede been aan\n- speel strak en met gevoel in\n- laat het schietbeen doorzwaaien\n- raak de bal in het hart\n- houd spanning in de voet."}, {"type": "partijvorm", "title": "PARTIJVORM 5:5 (2)", "content": "Methodiek\nVijf aanvallers moeten d.m.v. samenspel/ individuele actie 5 \nverdedigers uitspelen, om daarna in het tegenoverstaande doel te \nscoren.\nDe verdedigers kunnen de afgepakte bal scoren door hetzelfde \naan de andere kant van het vak te doen.\nOpgelet! \nBal buiten het veld, dan start het andere team de partij opnieuw.\nVariatie in uitvoering:\nMet 3 teams wisselen naar eigen inzicht.Materialen\nAantal spelers: 10(15)+2(3) keepers\nAantal ballen: 5\nAantal pylonen: 4\nAfstand tussen pylonen:\nF-pupillen: 30m bij 25m\nE-pupillen: 30m bij 25m\nDoel: 2\nF- en E-junioren: 5m bij 2m\nDoordraaien: \n- het winnende team blijft staan en het \nverliezende team wisselt met het 3e team.\n- geen score na twee minuten, dan wordt de \nlangst staande partij gewisseld.Aanwijzingen\nBij de aanval coachen op:\n- het samenspelen vanuit een diamantvorm\n- het uiteen bewegen bij balbezit\n- het voorkomen van buitenspel\n- het maken van keuzes ( 1:1 of overspelen) \naan de bal\n- het rekening houden met omschakeling bij \nbalverlies en ook bij het innemen van een \naanvallende positie.\nBij het verdedigen coachen op:\n- het knijpen, daar waar nodig\n- het gebruik maken van de buitenspelregel\n- het coachen van elkaar (het initiatief ligt bij \nde achterste speler)\n- het rekening houden met omschakeling bij \nbalverovering.\nKeepers coachen op:\n- het altijd aanspeelbaar zijn bij balbezit\n- het coachen van je medespelers bij het \nverdedigen.\nOpmerkingen:\n- bij een partij op scherp mag men de bal vrij \nraken\n- leg accenten op: de individuele actie, het \nscoren onder druk, een snelle omschakeling, \nde conditionele (anaeroob- lactisch)/ mentale \nfactoren\n- houdt in de organisatie ook aandacht voor: \ngenoeg ballen om het veld, een strakke felle \ncoaching."}], "session_b": [{"type": "warming_up", "title": "PARCOURS DRIBBELEN/DRIJVEN", "content": "Methodiek\nDe spelers slalommen dribbelend het hele parcours door en het \nrechte stuk leggen ze dribbelend/ drijvend af.\nVariatie in aanbieden:\n- Varieer in uitvoeringssnelheid\n- Varieer onderlinge afstand pylonen.\n- Voer de oefening in wedstrijdvorm uit.\nLet op!\nSpeler 2 start wanneer speler 1 voorbij de tweede pylon is, enz.Materialen\nAantal spelers: 4-10 spelers\nAantal pylonen: 7\nAantal ballen: elke speler 1 bal\nOnderlinge afstand pylonen: 3 a 5 meterAanwijzingen\nSpelers coachen op:\n- Houdt de bal dichtbij je, maar niet onder je.\n- Probeer de bal zoveel mogelijk te raken.\n- Probeer de bal bij iedere stap te raken, dan \nkun je de bal ook beter sturen.\n- Bij het drijven op het rechte stuk mag de \nbal iets verder vooruit gespeeld worden. Niet \nte ver, behoud wel de controle over de bal."}, {"type": "techniek", "title": "PARCOURS DRIBBELEN EN AFWERKEN", "content": "Methodiek\nDe spelers slalommen dribbelend het hele parcours door en werk \naf op doel.\nVariatie in aanbieden:\n- Varieer in uitvoeringssnelheid\n- Varieer onderlinge afstand pylonen.\n- Voer de oefening in wedstrijdvorm uit.Materialen\nAantal spelers: 4-10\nAantal ballen: elke speler 1 bal\nAantal pylonen: 8\nDoelen: 2\nOnderlinge afstand pylonen: 2 a 3 meterAanwijzingen\nSpelers coachen op:\n- Houdt de bal dichtbij je, maar niet onder je.\n- Probeer de bal zoveel mogelijk te raken.\n- Probeer de bal bij iedere stap te raken, dan \nkun je de bal ook beter sturen."}, {"type": "partijvorm", "title": "PARTIJVORM 5:5 (2)", "content": "Methodiek\nVijf aanvallers moeten d.m.v. samenspel/ individuele actie 5 \nverdedigers uitspelen, om daarna in het tegenoverstaande doel te \nscoren.\nDe verdedigers kunnen de afgepakte bal scoren door hetzelfde \naan de andere kant van het vak te doen.\nOpgelet! \nBal buiten het veld, dan start het andere team de partij opnieuw.\nVariatie in uitvoering:\nMet 3 teams wisselen naar eigen inzicht.Materialen\nAantal spelers: 10(15)+2(3) keepers\nAantal ballen: 5\nAantal pylonen: 4\nAfstand tussen pylonen:\nF-pupillen: 30m bij 25m\nE-pupillen: 30m bij 25m\nDoel: 2\nF- en E-junioren: 5m bij 2m\nDoordraaien: \n- het winnende team blijft staan en het \nverliezende team wisselt met het 3e team.\n- geen score na twee minuten, dan wordt de \nlangst staande partij gewisseld.Aanwijzingen\nBij de aanval coachen op:\n- het samenspelen vanuit een diamantvorm\n- het uiteen bewegen bij balbezit\n- het voorkomen van buitenspel\n- het maken van keuzes ( 1:1 of overspelen) \naan de bal\n- het rekening houden met omschakeling bij \nbalverlies en ook bij het innemen van een \naanvallende positie.\nBij het verdedigen coachen op:\n- het knijpen, daar waar nodig\n- het gebruik maken van de buitenspelregel\n- het coachen van elkaar (het initiatief ligt bij \nde achterste speler)\n- het rekening houden met omschakeling bij \nbalverovering.\nKeepers coachen op:\n- het altijd aanspeelbaar zijn bij balbezit\n- het coachen van je medespelers bij het \nverdedigen.\nOpmerkingen:\n- bij een partij op scherp mag men de bal vrij \nraken\n- leg accenten op: de individuele actie, het \nscoren onder druk, een snelle omschakeling, \nde conditionele (anaeroob- lactisch)/ mentale \nfactoren\n- houdt in de organisatie ook aandacht voor: \ngenoeg ballen om het veld, een strakke felle \ncoaching."}]}'::jsonb),
  ('O8', 13, '{"session_a": [{"type": "warming_up", "title": "GEWOON TIKKERTJE", "content": "Methodiek\nElke speler heeft een bal aan zijn voet, behalve de tikker. De \ntikker probeert zo veel mogelijk spelers te tikken.\nVariatie:\n- De tikker heeft ook een bal.\n- De tikker kan spelers aftikken door hun bal weg te schoppen\nOpgelet!\nJe mag weer deelnemen als een \"vrije speler\" je weer \"vrij\" getikt \nheeft.Materialen\nDuur spel:10-15 min\nDuur ronde: 1 a 2 min\nAantal: 6-8 of meer spelers\nPylonen: 4 om het speelveld af te bakenen.\nBallen: voor iedere speler een balAanwijzingen\nWedstrijdopties:\nOptie 1: Tel het aantal getikte spelers.\nOptie 2: De getikte speler gaat aan de kant \nstaan.\nOptie 3: De getikte speler wordt de nieuwe \ntikker."}, {"type": "techniek", "title": "STAP 1: HOEDJE TRAP", "content": "Methodiek\n2 ploegen, waarvan elke speler een bal heeft, proberen de over \nhet hele veld verspreid staande rode en gele hoedjes van de \npylonen te schieten.\nDe ploeg die dit het eerst voor elkaar krijgt, is de winnaar.\nVariatie:\n- inzet van een verdediger, die probeert de bal van de \ntegenstander te onderscheppen, voordat deze het hoedje raakt.Materialen\nAantal spelers: 6-10\nAantal hoedjes: 10 rode en 10 gele.\nAantal ballen: elke speler 1 bal.\nHesjes: 2 kleuren en voldoende voor iedere partij.\nAantal pylonen: 24 (4 voor het speelveld en 20 \nvoor het spel)\nAfstand tussen de pylonen:\n- Speelveld: 10 bij 10 meter\n- Pylonen met hoedjes naar eigen inzicht.Aanwijzingen\nSpelers coachen op:\n- met de binnenkant van de voet schieten\n- van dichtbij schieten\n- niet te zacht schieten\n- de bal snel pakken en de volgende \nomschieten."}, {"type": "partijvorm", "title": "PARTIJVORM 4:4 + 2 KEEPERS", "content": "Methodiek\nVier aanvallers moeten d.m.v. samenspel/ individuele actie 4 \nverdedigers uitspelen, om daarna in het tegenoverstaande doel te \nscoren.\nDe verdedigers kunnen de afgepakte bal scoren door hetzelfde \naan de andere kant van het vak te doen.\nOpgelet! \nBal buiten het veld, dan start het andere team de partij opnieuw.\nVariatie in uitvoering:\nMet 3 teams wisselen naar eigen inzicht.Materialen\nAantal spelers:8(12)+2(3) keepers\nAantal ballen: 5\nAantal pylonen: 4\nAfstand tussen pylonen:\nF-pupillen: 25m bij 20m\nE-pupillen: 30m bij 25m\nD-pupillen: 30m bij 25m\nC-junioren: 35m bij 30m\nB-,A-junioren: 40m bij 35m\nDoel: 2\nF- en E-pupillen: 5m bij 2m\nD-,C-,B-,A-junioren: 7.32m bij 2.44\nDoordraaien: \nHet winnende team blijft staan en het \nverliezende team wisselt met het 3e team.\nAls er na twee minuten nog niet is gescoord, dan \nwordt de partij die het langst in het veld staat \ngewisseld.Aanwijzingen\nBij de aanval coachen op:\n- het samenspelen vanuit een ruit vorm, \nwaarbij gebruik gemaakt moet worden van \nde vrije positie van de keeper (overtalsituatie)\n- het creëren van een twee tegen een situatie\n- het zo breed en diep mogelijk staan van de \ntwee buitenste spelers.\n- het rekening houden bij balverlies met \nomschakeling, ook bij het innemen van een \naanvallende positie.\nBij het verdedigen coachen op:\n- het knijpen, daar waar nodig\n- het coachen van elkaar ( het initiatief ligt bij \nde achterste speler).\n- het rekening houden bij balverovering met \nomschakeling.\nKeepers coachen op:\n- het altijd aanspeelbaar zijn bij balbezit\n- het coachen bij het verdedigen van je \nmedespelers\nOpmerkingen:\n- bij een partij op scherp mag men de bal vrij \nraken\n- accenten leggen op: individuele actie; \nscoren onder druk; snelle omschakeling;\n- in de organisatie aandacht voor: genoeg \nballen om het veld; strakke felle coaching"}], "session_b": [{"type": "warming_up", "title": "VOLGSPEL", "content": "Methodiek\nElk tweetal heeft een bal. De speler \"met bal\" probeert de speler \n\"zonder bal\" op een afstand van ca 1 - 2 mtr. overal binnen het \nvierkant te volgen.\nVariatie in aanbieden:\nMaak gebruik van tempowisselingen\nSpeler met bal loopt vooropMaterialen\nAantal spelers: 4-10\nAantal ballen: per tweetal 1 bal\nAantal pylonen: 4\nOnderlinge afstand pylonen: ongeveer 10 bij 15 \nmeter\nDoordraaien: \nWisselen van functie na een aantal minuten.Aanwijzingen\nSpelers coachen op:\n- Probeer zo goed mogelijk de voorste man te \nvolgen.\n- Houdt de bal dichtbij je, maar niet onder je.\n- Probeer de bal zoveel mogelijk te raken.\n- Probeer de bal bij elke stap te raken, dan \nkun je de bal ook beter sturen"}, {"type": "techniek", "title": "PENALTY SCHIETEN", "content": "Methodiek\nIn het doel staan twee pylonen. De afstand tusssen de pylon en de \npaal is 2 meter.\nDe spelers proberen de bal in de rechter- of linkerhoek te schieten \ntussen de pylon en de paal.\nWie schiet de meeste penalties tussen de pylon en de paal?\nVariatie in uitvoering:\n- de afstand tussen de pylon en de paal verkleinen.\n- een keeper op doel zetten.Materialen\nAantal spelers: 4- 8 + (2 keepers)\nAantal ballen: ieder speler een bal\nAantal pylonen: 6\nSchietafstand:\nF- pupillen: 7m\nE-pupillen: 8m\nD-,C-,B-,A-junioren: 11m\nDoelen: 2\nF- en E-pupillen: 5m bij 2m\nD-,C-,B-,A-junioren: 7.32m bij 2.44m\nDoordraaien:\n- elke speler haalt, nadat hij geschoten heeft, \nzijn eigen bal op en sluit achter in de andere rij \naan.Aanwijzingen\nSpelers coachen op:\n- geef de bal de juiste snelheid mee.\n- bal in het hart raken.\n- spanning in de voet.\n- standbeen iets voorbij de bal, bal blijft laag."}, {"type": "partijvorm", "title": "PARTIJVORM 4:4 + 2 KEEPERS", "content": "Methodiek\nVier aanvallers moeten d.m.v. samenspel/ individuele actie 4 \nverdedigers uitspelen, om daarna in het tegenoverstaande doel te \nscoren.\nDe verdedigers kunnen de afgepakte bal scoren door hetzelfde \naan de andere kant van het vak te doen.\nOpgelet! \nBal buiten het veld, dan start het andere team de partij opnieuw.\nVariatie in uitvoering:\nMet 3 teams wisselen naar eigen inzicht.Materialen\nAantal spelers:8(12)+2(3) keepers\nAantal ballen: 5\nAantal pylonen: 4\nAfstand tussen pylonen:\nF-pupillen: 25m bij 20m\nE-pupillen: 30m bij 25m\nD-pupillen: 30m bij 25m\nC-junioren: 35m bij 30m\nB-,A-junioren: 40m bij 35m\nDoel: 2\nF- en E-pupillen: 5m bij 2m\nD-,C-,B-,A-junioren: 7.32m bij 2.44\nDoordraaien: \nHet winnende team blijft staan en het \nverliezende team wisselt met het 3e team.\nAls er na twee minuten nog niet is gescoord, dan \nwordt de partij die het langst in het veld staat \ngewisseld.Aanwijzingen\nBij de aanval coachen op:\n- het samenspelen vanuit een ruit vorm, \nwaarbij gebruik gemaakt moet worden van \nde vrije positie van de keeper (overtalsituatie)\n- het creëren van een twee tegen een situatie\n- het zo breed en diep mogelijk staan van de \ntwee buitenste spelers.\n- het rekening houden bij balverlies met \nomschakeling, ook bij het innemen van een \naanvallende positie.\nBij het verdedigen coachen op:\n- het knijpen, daar waar nodig\n- het coachen van elkaar ( het initiatief ligt bij \nde achterste speler).\n- het rekening houden bij balverovering met \nomschakeling.\nKeepers coachen op:\n- het altijd aanspeelbaar zijn bij balbezit\n- het coachen bij het verdedigen van je \nmedespelers\nOpmerkingen:\n- bij een partij op scherp mag men de bal vrij \nraken\n- accenten leggen op: individuele actie; \nscoren onder druk; snelle omschakeling;\n- in de organisatie aandacht voor: genoeg \nballen om het veld; strakke felle coaching"}]}'::jsonb),
  ('O8', 14, '{"session_a": [{"type": "warming_up", "title": "POORT TIKKERTJE", "content": "Methodiek\n1 speler probeert als tikker de anderen te tikken. Een getikte speler blijft \nwijdbeens staan. Elke \"vrije speler\" kan hen weer \"vrij\" tikken door de bal onder \nhun poortje door te spelen en direct weer onder controle mee te nemen.Materialen\nDuur:10-15 min\nDuur ronde: 1 a 2 min\nAantal: 6-8 of meer spelers\nPylonen: 4 om het speelveld af te bakenen.\nBallen: iedere speler een bal."}, {"type": "techniek", "title": "STAP 1: JEU DE VOETBAL", "content": "Methodiek\nDeze oefening wordt gespeelt met 2 spelers, die ieder met 3 \nballen bij een hoedje staan op de achterlijn.\nZij proberen nu de bal vanaf het hoedje zo dicht mogelijk, bij de, \nop 12 - 15 mtr. afstand geplaatste pylon, te spelen.\nDe winnaar is degene die de meeste ballen dichtbij de pylon weet \nte krijgen.\nVariatie:\n- afstand vergrotenMaterialen\nAantal spelers: 2\nAantal ballen: elke speler heeft 3 ballen\nHoedje: per tweetal 1 hoedje\nAantal pylonen: per tweetal één pylon\nAfstand tussen pylon en hoedje: 12-15 meterAanwijzingen\nSpelers coachen op:\n- schieten met de binnenkant van de voet.\n- standbeen in de richting van de pylon \nplaatsen\n- het schietbeen op de bal richten.\n- let goed op welke bal bij welke speler hoort"}, {"type": "partijvorm", "title": "PARTIJVORM 5:5 (2)", "content": "Methodiek\nVijf aanvallers moeten d.m.v. samenspel/ individuele actie 5 \nverdedigers uitspelen, om daarna in het tegenoverstaande doel te \nscoren.\nDe verdedigers kunnen de afgepakte bal scoren door hetzelfde \naan de andere kant van het vak te doen.\nOpgelet! \nBal buiten het veld, dan start het andere team de partij opnieuw.\nVariatie in uitvoering:\nMet 3 teams wisselen naar eigen inzicht.Materialen\nAantal spelers: 10(15)+2(3) keepers\nAantal ballen: 5\nAantal pylonen: 4\nAfstand tussen pylonen:\nF-pupillen: 30m bij 25m\nE-pupillen: 30m bij 25m\nDoel: 2\nF- en E-junioren: 5m bij 2m\nDoordraaien: \n- het winnende team blijft staan en het \nverliezende team wisselt met het 3e team.\n- geen score na twee minuten, dan wordt de \nlangst staande partij gewisseld.Aanwijzingen\nBij de aanval coachen op:\n- het samenspelen vanuit een diamantvorm\n- het uiteen bewegen bij balbezit\n- het voorkomen van buitenspel\n- het maken van keuzes ( 1:1 of overspelen) \naan de bal\n- het rekening houden met omschakeling bij \nbalverlies en ook bij het innemen van een \naanvallende positie.\nBij het verdedigen coachen op:\n- het knijpen, daar waar nodig\n- het gebruik maken van de buitenspelregel\n- het coachen van elkaar (het initiatief ligt bij \nde achterste speler)\n- het rekening houden met omschakeling bij \nbalverovering.\nKeepers coachen op:\n- het altijd aanspeelbaar zijn bij balbezit\n- het coachen van je medespelers bij het \nverdedigen.\nOpmerkingen:\n- bij een partij op scherp mag men de bal vrij \nraken\n- leg accenten op: de individuele actie, het \nscoren onder druk, een snelle omschakeling, \nde conditionele (anaeroob- lactisch)/ mentale \nfactoren\n- houdt in de organisatie ook aandacht voor: \ngenoeg ballen om het veld, een strakke felle \ncoaching."}], "session_b": [{"type": "warming_up", "title": "LIJNORGANISATIE IN WEDSTRIJDVORM", "content": "Methodiek\nEén van de stappen van de onderstaande technieken dient, heen \nen terug tussen de lange zijden van de rechthoek, uitgevoerd te \nworden.\n- Heen d.m.v. Tippen voorwaarts, Aaien links of Lambada\n- Terug d.m.v. Tippen achterwaarts, Aaien rechts of Lambada\nWie doet dit het snelst? \nOpgelet! \nDeze oefening kan pas toegepast worden bij voldoende \nbeheersing van de technieken.\nDe technieken moeten wel goed worden uitgevoerd.Materialen\nAantal spelers: 1-8\nAantal ballen: elke speler 1 bal \nAantal pylonen: 2-16 (per speler twee pylonen)\nTwee rijen pylonen op een onderlinge afstand \nvan 8 mtr.\nOrganisatie:\nDe trainer geeft eerst een beeld van de oefening \nen controleert daarna de uitvoering.Aanwijzingen\nVoor de beschrijving van de techniek zie \ntechnieklijst."}, {"type": "techniek", "title": "IN STROOMVORM (1)", "content": "Methodiek\nDeze vorm wordt uitgevoerd met twee rijen spelers.\nA. Speler 1 of 2 speelt de bal met de binnenkant van de buitenste \nvoet in op de trainer en loopt daarna achter zijn bal aan.\nB. De trainer neemt de bal aan en legt de bal stil voor de \ninlopende speler 1 of 2.\nC. Speler 1 of 2 schiet vervolgens de stilliggende bal op doel, etc.\nVariatie in uitvoering: \nNa elk schot wisselen van rij.Materialen\nAantal spelers: 8- 10\nAantal ballen: elke speler heeft een bal\nAantal pylonen: 2\nDoelen: 1\nF-t/m E-pupillen: 5m bij 2m\nD-t/m A-junioren: 7.32m bij 2.44m\nAfstand trainer tot het doel:\n1 ste jaars F-pupillen: 5 m\n2e jaars F-pupillen: 8 m\n1e jaars E-pupillen: 10 m\n2e jaars E-pupillen: 12 m\nD-pupillen: 14 m\nC-,B-,A-junioren: >16 m\nDoordraaien:\nElke speler haalt, nadat hij geschoten heeft, zijn \neigen bal op en sluit weer achter in de rij aan.Aanwijzingen\nSpelers coachen op:\n- Bal in het hart raken\n- Spanning in de voet\n- Raakvlak: Binnenkant of volle wreef, \nafhankelijk van de situatie.\n- Standbeen iets voorbij de bal, bal blijft laag.\n- Standbeen iets achter de bal, bal aan de \nonderkant raken, bal gaat omhoog.\n- De overgang van het aan komen lopen naar \nhet schieten moet vloeiend verlopen."}, {"type": "partijvorm", "title": "PARTIJVORM 5:5 (2)", "content": "Methodiek\nVijf aanvallers moeten d.m.v. samenspel/ individuele actie 5 \nverdedigers uitspelen, om daarna in het tegenoverstaande doel te \nscoren.\nDe verdedigers kunnen de afgepakte bal scoren door hetzelfde \naan de andere kant van het vak te doen.\nOpgelet! \nBal buiten het veld, dan start het andere team de partij opnieuw.\nVariatie in uitvoering:\nMet 3 teams wisselen naar eigen inzicht.Materialen\nAantal spelers: 10(15)+2(3) keepers\nAantal ballen: 5\nAantal pylonen: 4\nAfstand tussen pylonen:\nF-pupillen: 30m bij 25m\nE-pupillen: 30m bij 25m\nDoel: 2\nF- en E-junioren: 5m bij 2m\nDoordraaien: \n- het winnende team blijft staan en het \nverliezende team wisselt met het 3e team.\n- geen score na twee minuten, dan wordt de \nlangst staande partij gewisseld.Aanwijzingen\nBij de aanval coachen op:\n- het samenspelen vanuit een diamantvorm\n- het uiteen bewegen bij balbezit\n- het voorkomen van buitenspel\n- het maken van keuzes ( 1:1 of overspelen) \naan de bal\n- het rekening houden met omschakeling bij \nbalverlies en ook bij het innemen van een \naanvallende positie.\nBij het verdedigen coachen op:\n- het knijpen, daar waar nodig\n- het gebruik maken van de buitenspelregel\n- het coachen van elkaar (het initiatief ligt bij \nde achterste speler)\n- het rekening houden met omschakeling bij \nbalverovering.\nKeepers coachen op:\n- het altijd aanspeelbaar zijn bij balbezit\n- het coachen van je medespelers bij het \nverdedigen.\nOpmerkingen:\n- bij een partij op scherp mag men de bal vrij \nraken\n- leg accenten op: de individuele actie, het \nscoren onder druk, een snelle omschakeling, \nde conditionele (anaeroob- lactisch)/ mentale \nfactoren\n- houdt in de organisatie ook aandacht voor: \ngenoeg ballen om het veld, een strakke felle \ncoaching."}]}'::jsonb),
  ('O8', 15, '{"session_a": [{"type": "warming_up", "title": "OVERLOOPSPEL", "content": "Methodiek\nAlle spelers staan, op één speler na, met een bal aan de voet aan één zijde van \nhet speelveld.\nDe tikker staat ook met een bal aan de voet in het speelveld.\nOp een teken moeten de spelers de bal naar de overkant dribbelen. De tikker \nprobeert nu met de bal zoveel mogelijk spelers onderweg af te tikken.\nWie tikt de meeste spelers af in 2 beurten?\nOpgelet!\n- als je de bal niet bij je houdt dan ben je ook af.\nVariatie:\n- ook de tikker heeft de bal aan de voet\n- opvoeren van het aantal beurten. Materialen\nDuur:10-15 min\nDuur ronde: 1 a 2 min\nAantal: 6-12 spelers\nPylonen: 4 om het speelveld af te bakenen."}, {"type": "techniek", "title": "STAP 1: KEGELEN 2", "content": "Methodiek\n2 ploegen, iedere speler met 1 bal, staan ieder in hun \"eigen vak\" \ntegenover elkaar, met op de achterlijn pylonen met daarop rode \nof gele hoedjes.\nDe spelers moeten, vanaf hun achterlijn, de gele of rode hoedjes \nvan de pylonen schieten.\n- de ploeg die dit het eerst voor elkaar krijgt, is winnaar.Materialen\nAantal spelers: 6-10\nAantal hoedjes: 10 rode en 10 gele.\nAantal ballen: elke speler 1 bal.\nHesjes: 2 kleuren en voldoende voor iedere partij\nAantal pylonen: 24 (4 voor het speelveld en 20 \nvoor het spel)\nAfstand tussen de pylonen:\n- speelveld 25 bij 15 meter\n- pylonen met hoedjes naar eigen inzichtAanwijzingen\nSpelers coachen op:\n- met de binnenkant van de voet schieten\n- niet te zacht schieten\n- langs de pillonen schieten\n- minder pylonen maakt het voor de spelers \nmakkelijker\n- meer pylonen maakt het voor de spelers \nmoeilijker."}, {"type": "partijvorm", "title": "PARTIJVORM 4:4 + 2 KEEPERS", "content": "Methodiek\nVier aanvallers moeten d.m.v. samenspel/ individuele actie 4 \nverdedigers uitspelen, om daarna in het tegenoverstaande doel te \nscoren.\nDe verdedigers kunnen de afgepakte bal scoren door hetzelfde \naan de andere kant van het vak te doen.\nOpgelet! \nBal buiten het veld, dan start het andere team de partij opnieuw.\nVariatie in uitvoering:\nMet 3 teams wisselen naar eigen inzicht.Materialen\nAantal spelers:8(12)+2(3) keepers\nAantal ballen: 5\nAantal pylonen: 4\nAfstand tussen pylonen:\nF-pupillen: 25m bij 20m\nE-pupillen: 30m bij 25m\nD-pupillen: 30m bij 25m\nC-junioren: 35m bij 30m\nB-,A-junioren: 40m bij 35m\nDoel: 2\nF- en E-pupillen: 5m bij 2m\nD-,C-,B-,A-junioren: 7.32m bij 2.44\nDoordraaien: \nHet winnende team blijft staan en het \nverliezende team wisselt met het 3e team.\nAls er na twee minuten nog niet is gescoord, dan \nwordt de partij die het langst in het veld staat \ngewisseld.Aanwijzingen\nBij de aanval coachen op:\n- het samenspelen vanuit een ruit vorm, \nwaarbij gebruik gemaakt moet worden van \nde vrije positie van de keeper (overtalsituatie)\n- het creëren van een twee tegen een situatie\n- het zo breed en diep mogelijk staan van de \ntwee buitenste spelers.\n- het rekening houden bij balverlies met \nomschakeling, ook bij het innemen van een \naanvallende positie.\nBij het verdedigen coachen op:\n- het knijpen, daar waar nodig\n- het coachen van elkaar ( het initiatief ligt bij \nde achterste speler).\n- het rekening houden bij balverovering met \nomschakeling.\nKeepers coachen op:\n- het altijd aanspeelbaar zijn bij balbezit\n- het coachen bij het verdedigen van je \nmedespelers\nOpmerkingen:\n- bij een partij op scherp mag men de bal vrij \nraken\n- accenten leggen op: individuele actie; \nscoren onder druk; snelle omschakeling;\n- in de organisatie aandacht voor: genoeg \nballen om het veld; strakke felle coaching"}], "session_b": [{"type": "warming_up", "title": "CLUBS / LANDENSPEL", "content": "Methodiek\nElke speler heeft een bal en dribbelt in het rond.\nIn de hoeken van het veld zijn vierkanten, die de namen dragen \nvan een voetbalclub of een land.\nBij het noemen van de naam van de club of het land moeten de \nspelers zo snel mogelijk naar het desbetreffende vak dribbelen en \ndaar met de voet op de bal blijven staan.\nDe laatst aangekomen speler krijgt een strafpunt.\nWinnaar is degene met de minste strafpunten.\nVariatie in aanbieden:\n- Met Kerst, Pasen of Sinterklaas gebruik je deze themagerichte \nnamen.\n- Spelers moeten de bal stoppen door b.v. op de bal te gaan zitten \nof iets anders te doen.Materialen\nAantal spelers: 4-10\nAantal ballen: elke speler 1 bal\nAantal pylonen: 16\nVeldafmeting: 20 bij 20 meter (incl. hoekvakken \nvan 4 bij 4 meter)Aanwijzingen\nSpelers coachen op:\n- De bal dichtbij je houden.\n- Probeer de bal zoveel mogelijk aan te raken.\n- Probeer bij iedere stap de bal een keer aan \nte raken.\n- Door het vele bal contact kunnen spelers \ngemakkelijker de bal sturen.\n- De bal moet onder de voet gestopt worden"}, {"type": "techniek", "title": "PARCOURS DRIBBELEN EN AFWERKEN", "content": "Methodiek\nDe spelers slalommen dribbelend het hele parcours door en werk \naf op doel.\nVariatie in aanbieden:\n- Varieer in uitvoeringssnelheid\n- Varieer onderlinge afstand pylonen.\n- Voer de oefening in wedstrijdvorm uit.Materialen\nAantal spelers: 4-10\nAantal ballen: elke speler 1 bal\nAantal pylonen: 8\nDoelen: 2\nOnderlinge afstand pylonen: 2 a 3 meterAanwijzingen\nSpelers coachen op:\n- Houdt de bal dichtbij je, maar niet onder je.\n- Probeer de bal zoveel mogelijk te raken.\n- Probeer de bal bij iedere stap te raken, dan \nkun je de bal ook beter sturen."}, {"type": "partijvorm", "title": "PARTIJVORM 4:4 + 2 KEEPERS", "content": "Methodiek\nVier aanvallers moeten d.m.v. samenspel/ individuele actie 4 \nverdedigers uitspelen, om daarna in het tegenoverstaande doel te \nscoren.\nDe verdedigers kunnen de afgepakte bal scoren door hetzelfde \naan de andere kant van het vak te doen.\nOpgelet! \nBal buiten het veld, dan start het andere team de partij opnieuw.\nVariatie in uitvoering:\nMet 3 teams wisselen naar eigen inzicht.Materialen\nAantal spelers:8(12)+2(3) keepers\nAantal ballen: 5\nAantal pylonen: 4\nAfstand tussen pylonen:\nF-pupillen: 25m bij 20m\nE-pupillen: 30m bij 25m\nD-pupillen: 30m bij 25m\nC-junioren: 35m bij 30m\nB-,A-junioren: 40m bij 35m\nDoel: 2\nF- en E-pupillen: 5m bij 2m\nD-,C-,B-,A-junioren: 7.32m bij 2.44\nDoordraaien: \nHet winnende team blijft staan en het \nverliezende team wisselt met het 3e team.\nAls er na twee minuten nog niet is gescoord, dan \nwordt de partij die het langst in het veld staat \ngewisseld.Aanwijzingen\nBij de aanval coachen op:\n- het samenspelen vanuit een ruit vorm, \nwaarbij gebruik gemaakt moet worden van \nde vrije positie van de keeper (overtalsituatie)\n- het creëren van een twee tegen een situatie\n- het zo breed en diep mogelijk staan van de \ntwee buitenste spelers.\n- het rekening houden bij balverlies met \nomschakeling, ook bij het innemen van een \naanvallende positie.\nBij het verdedigen coachen op:\n- het knijpen, daar waar nodig\n- het coachen van elkaar ( het initiatief ligt bij \nde achterste speler).\n- het rekening houden bij balverovering met \nomschakeling.\nKeepers coachen op:\n- het altijd aanspeelbaar zijn bij balbezit\n- het coachen bij het verdedigen van je \nmedespelers\nOpmerkingen:\n- bij een partij op scherp mag men de bal vrij \nraken\n- accenten leggen op: individuele actie; \nscoren onder druk; snelle omschakeling;\n- in de organisatie aandacht voor: genoeg \nballen om het veld; strakke felle coaching"}]}'::jsonb),
  ('O8', 16, '{"session_a": [{"type": "warming_up", "title": "DRIBBELTIKKERTJE", "content": "Methodiek\nAlle spelers, behalve de tikker, dribbelen met de bal aan de voet in het speelveld. \nDe tikker heeft zijn bal in de handen en moet nu met zijn bal proberen de bal van \neen dribbelende speler te tikken.\nAls dit is lukt, wordt de afgetikte speler de nieuwe tikker, etc. Materialen\nDuur:10-15 min\nDuur ronde: 1 a 2 min\nAantal: 6-12 spelers\nPylonen: 4 om het speelveld af te bakenen.\nAantal ballen: zoveel als nodig is voor het spel."}, {"type": "techniek", "title": "STAP 1: KONINGEN", "content": "Methodiek\nTweetallen, staan op 10 - 15 mtr. afstand tegenover elkaar naast \neen 1 mtr. breed doeltje. Zij moeten proberen in het doeltje van \nde tegenoverstaande speler te scoren. \nWie de meeste goals maakt, binnen een bepaalde tijd of bepaald \naantal keer, is de \"koning\"!Materialen\nAantal spelers: 2-10 \nAantal doeltjes: per tweetal 1 doeltje\nAantal ballen: per tweetal 1 bal\nDoelgrootte: 1 meter\nAfstand tussen de doeltjes: 10-15 meterAanwijzingen\nSpelers coachen op:\n- schieten met de binnenkant van de voet\n- speelbeen loodrecht op de speelrichting\n- voetzool parallel met de grond."}, {"type": "partijvorm", "title": "PARTIJVORM 5:5 (2)", "content": "Methodiek\nVijf aanvallers moeten d.m.v. samenspel/ individuele actie 5 \nverdedigers uitspelen, om daarna in het tegenoverstaande doel te \nscoren.\nDe verdedigers kunnen de afgepakte bal scoren door hetzelfde \naan de andere kant van het vak te doen.\nOpgelet! \nBal buiten het veld, dan start het andere team de partij opnieuw.\nVariatie in uitvoering:\nMet 3 teams wisselen naar eigen inzicht.Materialen\nAantal spelers: 10(15)+2(3) keepers\nAantal ballen: 5\nAantal pylonen: 4\nAfstand tussen pylonen:\nF-pupillen: 30m bij 25m\nE-pupillen: 30m bij 25m\nDoel: 2\nF- en E-junioren: 5m bij 2m\nDoordraaien: \n- het winnende team blijft staan en het \nverliezende team wisselt met het 3e team.\n- geen score na twee minuten, dan wordt de \nlangst staande partij gewisseld.Aanwijzingen\nBij de aanval coachen op:\n- het samenspelen vanuit een diamantvorm\n- het uiteen bewegen bij balbezit\n- het voorkomen van buitenspel\n- het maken van keuzes ( 1:1 of overspelen) \naan de bal\n- het rekening houden met omschakeling bij \nbalverlies en ook bij het innemen van een \naanvallende positie.\nBij het verdedigen coachen op:\n- het knijpen, daar waar nodig\n- het gebruik maken van de buitenspelregel\n- het coachen van elkaar (het initiatief ligt bij \nde achterste speler)\n- het rekening houden met omschakeling bij \nbalverovering.\nKeepers coachen op:\n- het altijd aanspeelbaar zijn bij balbezit\n- het coachen van je medespelers bij het \nverdedigen.\nOpmerkingen:\n- bij een partij op scherp mag men de bal vrij \nraken\n- leg accenten op: de individuele actie, het \nscoren onder druk, een snelle omschakeling, \nde conditionele (anaeroob- lactisch)/ mentale \nfactoren\n- houdt in de organisatie ook aandacht voor: \ngenoeg ballen om het veld, een strakke felle \ncoaching."}], "session_b": [{"type": "warming_up", "title": "FLUIT / NUMMERSPEL", "content": "Methodiek\nElke speler dribbelt met een bal door het vak. De trainer gebruikt de vooraf aan \ngegeven tekens.\nBij het fluiten of het roepen van een nummer moeten de spelers de daarbij \nbehorende afgesproken tekens uitvoeren, zoals:\n- Naar de zijkant dribbelen\n- Een kapbeweging maken\n- De bal stil leggen onder de voet\n- Een versnelling maken met de bal aan de voet\n- De bal hooghouden.\n- Op de bal zitten\n- Wisselen van bal met een andere speler.\nOpgelet!\nMaak er een puntenspel van.\nWie behaalt de minste strafpunten?Materialen\nTijd: 10-15 min\nRonde tijden: 1 a 2 min\nPylonen: 4 pylonen om het speelveld uit te zetten\nBallen: iedere speler heeft een bal."}, {"type": "techniek", "title": "PENALTY SCHIETEN", "content": "Methodiek\nIn het doel staan twee pylonen. De afstand tusssen de pylon en de \npaal is 2 meter.\nDe spelers proberen de bal in de rechter- of linkerhoek te schieten \ntussen de pylon en de paal.\nWie schiet de meeste penalties tussen de pylon en de paal?\nVariatie in uitvoering:\n- de afstand tussen de pylon en de paal verkleinen.\n- een keeper op doel zetten.Materialen\nAantal spelers: 4- 8 + (2 keepers)\nAantal ballen: ieder speler een bal\nAantal pylonen: 6\nSchietafstand:\nF- pupillen: 7m\nE-pupillen: 8m\nD-,C-,B-,A-junioren: 11m\nDoelen: 2\nF- en E-pupillen: 5m bij 2m\nD-,C-,B-,A-junioren: 7.32m bij 2.44m\nDoordraaien:\n- elke speler haalt, nadat hij geschoten heeft, \nzijn eigen bal op en sluit achter in de andere rij \naan.Aanwijzingen\nSpelers coachen op:\n- geef de bal de juiste snelheid mee.\n- bal in het hart raken.\n- spanning in de voet.\n- standbeen iets voorbij de bal, bal blijft laag."}, {"type": "partijvorm", "title": "PARTIJVORM 5:5 (2)", "content": "Methodiek\nVijf aanvallers moeten d.m.v. samenspel/ individuele actie 5 \nverdedigers uitspelen, om daarna in het tegenoverstaande doel te \nscoren.\nDe verdedigers kunnen de afgepakte bal scoren door hetzelfde \naan de andere kant van het vak te doen.\nOpgelet! \nBal buiten het veld, dan start het andere team de partij opnieuw.\nVariatie in uitvoering:\nMet 3 teams wisselen naar eigen inzicht.Materialen\nAantal spelers: 10(15)+2(3) keepers\nAantal ballen: 5\nAantal pylonen: 4\nAfstand tussen pylonen:\nF-pupillen: 30m bij 25m\nE-pupillen: 30m bij 25m\nDoel: 2\nF- en E-junioren: 5m bij 2m\nDoordraaien: \n- het winnende team blijft staan en het \nverliezende team wisselt met het 3e team.\n- geen score na twee minuten, dan wordt de \nlangst staande partij gewisseld.Aanwijzingen\nBij de aanval coachen op:\n- het samenspelen vanuit een diamantvorm\n- het uiteen bewegen bij balbezit\n- het voorkomen van buitenspel\n- het maken van keuzes ( 1:1 of overspelen) \naan de bal\n- het rekening houden met omschakeling bij \nbalverlies en ook bij het innemen van een \naanvallende positie.\nBij het verdedigen coachen op:\n- het knijpen, daar waar nodig\n- het gebruik maken van de buitenspelregel\n- het coachen van elkaar (het initiatief ligt bij \nde achterste speler)\n- het rekening houden met omschakeling bij \nbalverovering.\nKeepers coachen op:\n- het altijd aanspeelbaar zijn bij balbezit\n- het coachen van je medespelers bij het \nverdedigen.\nOpmerkingen:\n- bij een partij op scherp mag men de bal vrij \nraken\n- leg accenten op: de individuele actie, het \nscoren onder druk, een snelle omschakeling, \nde conditionele (anaeroob- lactisch)/ mentale \nfactoren\n- houdt in de organisatie ook aandacht voor: \ngenoeg ballen om het veld, een strakke felle \ncoaching."}]}'::jsonb),
  ('O8', 17, '{"session_a": [{"type": "warming_up", "title": "KETTINGTIKKERTJE", "content": "Methodiek\nBij dit spel staan alle spelers, met een bal aan de voet, in een vak. Twee spelers \nzijn de tikkers en moeten proberen de spelers uit te tikken door hun bal uit het \nspel te schieten.\nDe eerst afgetikte speler pakt, nadat zijn bal is uitgeschoten de hand van de \ntikker vast. Elke volgende afgetikte speler sluit daarna aan om zo een ketting te \nvormen. \nWelke verdediger behaalt de langste ketting (ofwel wie werken het beste samen?)\nOpmerking: \n- als tijdens het tkken de ketting breekt, dan mag de afgetikte speler gewoon \ndoorspelen.\nLet op: \n- de kettinggrootte mag niet groter worden dan 4 spelers (bij het vaststellen van \nhet resultaat wordt dan het totaal aantal afgetikte spelers geteld).Materialen\nPylonen: 4 pylonen om het speelveld uit te zetten.\nBallen: op een speler na heeft iedere speler een bal\nSpeeltijd: 10- 15 minuten"}, {"type": "techniek", "title": "STAP 1: RAAK DE BAL", "content": "Methodiek\n2 ploegen, waarvan elke speler een bal heeft, staan tegenover \nelkaar op de achterlijn met in het midden een \"opvallende bal\". \nDe 2 groepen proberen de \"opvallende bal\" vanaf hun achterlijn \nover de lijn van de tegenstander te schieten.\n- het team dat de bal het eerst over de lijn van de tegenstander \nkrijgt scoort 1 punt\n- na elke score wordt de bal weer in het midden gelegd en start \nhet spel opnieuw.Materialen\nAantal spelers: 6-10\nAantal ballen: elke speler 1 bal en 1 \"opvallende \nbal\".\nAantal pylonen: 4 \nAfstand tussen de pylonen: 20 bij 15 meterAanwijzingen\nSpelers coachen op:\n- schieten met de binnenkant van de voet\n- standbeen in de richting van de bal\n- het schietbeen op de bal richten\n- gaat de bal uit dan komt die terug in het \nmidden ten hoogte van de plek waar de bal \nuit ging."}, {"type": "partijvorm", "title": "PARTIJVORM 4:4 + 2 KEEPERS", "content": "Methodiek\nVier aanvallers moeten d.m.v. samenspel/ individuele actie 4 \nverdedigers uitspelen, om daarna in het tegenoverstaande doel te \nscoren.\nDe verdedigers kunnen de afgepakte bal scoren door hetzelfde \naan de andere kant van het vak te doen.\nOpgelet! \nBal buiten het veld, dan start het andere team de partij opnieuw.\nVariatie in uitvoering:\nMet 3 teams wisselen naar eigen inzicht.Materialen\nAantal spelers:8(12)+2(3) keepers\nAantal ballen: 5\nAantal pylonen: 4\nAfstand tussen pylonen:\nF-pupillen: 25m bij 20m\nE-pupillen: 30m bij 25m\nD-pupillen: 30m bij 25m\nC-junioren: 35m bij 30m\nB-,A-junioren: 40m bij 35m\nDoel: 2\nF- en E-pupillen: 5m bij 2m\nD-,C-,B-,A-junioren: 7.32m bij 2.44\nDoordraaien: \nHet winnende team blijft staan en het \nverliezende team wisselt met het 3e team.\nAls er na twee minuten nog niet is gescoord, dan \nwordt de partij die het langst in het veld staat \ngewisseld.Aanwijzingen\nBij de aanval coachen op:\n- het samenspelen vanuit een ruit vorm, \nwaarbij gebruik gemaakt moet worden van \nde vrije positie van de keeper (overtalsituatie)\n- het creëren van een twee tegen een situatie\n- het zo breed en diep mogelijk staan van de \ntwee buitenste spelers.\n- het rekening houden bij balverlies met \nomschakeling, ook bij het innemen van een \naanvallende positie.\nBij het verdedigen coachen op:\n- het knijpen, daar waar nodig\n- het coachen van elkaar ( het initiatief ligt bij \nde achterste speler).\n- het rekening houden bij balverovering met \nomschakeling.\nKeepers coachen op:\n- het altijd aanspeelbaar zijn bij balbezit\n- het coachen bij het verdedigen van je \nmedespelers\nOpmerkingen:\n- bij een partij op scherp mag men de bal vrij \nraken\n- accenten leggen op: individuele actie; \nscoren onder druk; snelle omschakeling;\n- in de organisatie aandacht voor: genoeg \nballen om het veld; strakke felle coaching"}], "session_b": [{"type": "warming_up", "title": "LIJNEN SPEL", "content": "Methodiek\nDe spelers staan met de bal aan de voet op een door de trainer \naangegeven lijn van het 16- meter gebied. Op zijn teken dribbelen \nde spelers naar een door de trainer aangegeven andere lijn.\nOpgelet!\nGeen 16- meter gebied beschikbaar, maak dan gebruik van \nverschillend gekleurde pylonen of hoedjes om daarmee lijnen te \nvormen\nMaak bij de\" jongste jeugd\" gebruik van nummers.\nVariatie:\n- Geef elke speler bij aanvang 3 punten en haal bij de laatste \ntelkens 1 punt af. Winnaar is ook nu weer degene die over blijft.\n- Laatste valt steeds af en winnaar is degene die over blijft (alleen \ndoen als afsluiting van een training).Materialen\nAantal spelers: 4-14\nAantal pylonen: 10 (om eventueel de lijnen aan \nte geven)\nAantal ballen: elke speler 1 balAanwijzingen\nSpelers coachen op:\n- Draai eerst proef.\n- De bal moet wel steeds op de lijn onder de \nvoet stil liggen."}, {"type": "techniek", "title": "IN STROOMVORM (1)", "content": "Methodiek\nDeze vorm wordt uitgevoerd met twee rijen spelers.\nA. Speler 1 of 2 speelt de bal met de binnenkant van de buitenste \nvoet in op de trainer en loopt daarna achter zijn bal aan.\nB. De trainer neemt de bal aan en legt de bal stil voor de \ninlopende speler 1 of 2.\nC. Speler 1 of 2 schiet vervolgens de stilliggende bal op doel, etc.\nVariatie in uitvoering: \nNa elk schot wisselen van rij.Materialen\nAantal spelers: 8- 10\nAantal ballen: elke speler heeft een bal\nAantal pylonen: 2\nDoelen: 1\nF-t/m E-pupillen: 5m bij 2m\nD-t/m A-junioren: 7.32m bij 2.44m\nAfstand trainer tot het doel:\n1 ste jaars F-pupillen: 5 m\n2e jaars F-pupillen: 8 m\n1e jaars E-pupillen: 10 m\n2e jaars E-pupillen: 12 m\nD-pupillen: 14 m\nC-,B-,A-junioren: >16 m\nDoordraaien:\nElke speler haalt, nadat hij geschoten heeft, zijn \neigen bal op en sluit weer achter in de rij aan.Aanwijzingen\nSpelers coachen op:\n- Bal in het hart raken\n- Spanning in de voet\n- Raakvlak: Binnenkant of volle wreef, \nafhankelijk van de situatie.\n- Standbeen iets voorbij de bal, bal blijft laag.\n- Standbeen iets achter de bal, bal aan de \nonderkant raken, bal gaat omhoog.\n- De overgang van het aan komen lopen naar \nhet schieten moet vloeiend verlopen."}, {"type": "partijvorm", "title": "PARTIJVORM 4:4 + 2 KEEPERS", "content": "Methodiek\nVier aanvallers moeten d.m.v. samenspel/ individuele actie 4 \nverdedigers uitspelen, om daarna in het tegenoverstaande doel te \nscoren.\nDe verdedigers kunnen de afgepakte bal scoren door hetzelfde \naan de andere kant van het vak te doen.\nOpgelet! \nBal buiten het veld, dan start het andere team de partij opnieuw.\nVariatie in uitvoering:\nMet 3 teams wisselen naar eigen inzicht.Materialen\nAantal spelers:8(12)+2(3) keepers\nAantal ballen: 5\nAantal pylonen: 4\nAfstand tussen pylonen:\nF-pupillen: 25m bij 20m\nE-pupillen: 30m bij 25m\nD-pupillen: 30m bij 25m\nC-junioren: 35m bij 30m\nB-,A-junioren: 40m bij 35m\nDoel: 2\nF- en E-pupillen: 5m bij 2m\nD-,C-,B-,A-junioren: 7.32m bij 2.44\nDoordraaien: \nHet winnende team blijft staan en het \nverliezende team wisselt met het 3e team.\nAls er na twee minuten nog niet is gescoord, dan \nwordt de partij die het langst in het veld staat \ngewisseld.Aanwijzingen\nBij de aanval coachen op:\n- het samenspelen vanuit een ruit vorm, \nwaarbij gebruik gemaakt moet worden van \nde vrije positie van de keeper (overtalsituatie)\n- het creëren van een twee tegen een situatie\n- het zo breed en diep mogelijk staan van de \ntwee buitenste spelers.\n- het rekening houden bij balverlies met \nomschakeling, ook bij het innemen van een \naanvallende positie.\nBij het verdedigen coachen op:\n- het knijpen, daar waar nodig\n- het coachen van elkaar ( het initiatief ligt bij \nde achterste speler).\n- het rekening houden bij balverovering met \nomschakeling.\nKeepers coachen op:\n- het altijd aanspeelbaar zijn bij balbezit\n- het coachen bij het verdedigen van je \nmedespelers\nOpmerkingen:\n- bij een partij op scherp mag men de bal vrij \nraken\n- accenten leggen op: individuele actie; \nscoren onder druk; snelle omschakeling;\n- in de organisatie aandacht voor: genoeg \nballen om het veld; strakke felle coaching"}]}'::jsonb),
  ('O8', 18, '{"session_a": [{"type": "warming_up", "title": "PANNA GAME", "content": "Methodiek\nElke speler, op een na heeft een bal. Op een teken van de trainer \nmoeten de speler zonder bal, binnen een vooraf aangegeven tijd, \nzoveel mogelijk ballen van de andere spelers buiten het speelveld \nte trappen.\nElke speler moet zijn weggetrapte bal direct weer ophalen en op \nde plaats waar de bal is uitgeschoten gaan staan met de benen \nwijd en de bal boven hun hoofd in hun handen. De andere spelers \ndie nog niet zijn uitgeschoten kunnen hun medespelers vrij maken \ndoor de bal door de benen van de afgeschoten spelers te spelen. \nAls de tijd voorbij is wordt het aantal spelers dat nog met hun bal \nboven hun hoofd staan geteld. Het spel is voorbij als de \nverdedigers alle spelers met de bal boven hun hoofd hebben \nstaan.\nWie haalt het hoogste aantal?\nVariatie:\n- meer verdedigers of minder verdedigers.Materialen\nTijd: 10-15 min\nRonde tijden: 1 a 2 min\nPylonen: 4 pylonen om het speelveld uit te zetten\nBallen: Op een speler na heeft iedere speler een \nbal.Aanwijzingen\nVoor de verdedigers:\n- samenwerken en samen afspreken waar je \nde ballen gaat uitschieten. Want waar je de \nballen uitschiet daar moeten de spelers gaan \nstaan met hun bal. Uiteindelijk krijg je dan \neen grote groep spelers bij elkaar waardoor 1 \nof 2 spelers deze kunnen verdedigen en de \nandere kunnen de rest gaan uitschieten. (dit \nis de enige mogelijkheid om iederee af te \nkrijgen.)\nVoor de aanvallers:\n- kijken waar de verdedigers zijn. Op snelheid \nde verdedigers passeren en proberen je \nmedespelers vrij proberen te maken."}, {"type": "techniek", "title": "STAP 1: VAK SCHIETEN", "content": "Methodiek\n2 ploegen, waarvan elke speler een bal heeft, staan achter elkaar \nbij het eerste hoedje. Vanaf dit punt moeten zij om beurten de bal \nin het vak proberen te spelen.\n- lukt dit, dan behaald men 1 punt. Bij 3 punten schuift men op \nnaar het tweede hoedje. Idem naar het derde en vierde hoedje.\nOpgelet!\n- bij drie opeenvolgende missers gaat men 1 plaats terug\n- winnaar is degene die het hele traject het eerst heeft afgelegd.\nVariatie:\n- bal met het andere been spelen.\n- vak vergroten/ verkleinen.\n- afstand naar het vak vergroten/ verkleinen.\nVariatie op organisatie vormen:\n- vanaf de middencircel in een klein vierkant proberen te schieten\n- vanaf de 16 meterlijn in een vierkant schieten\n- vanaf de 5 meterlijn de bal het dichst bij de 16 meter schieten \nen andersom.Materialen\nAantal spelers: 6-8\nAantal ballen: elke speler 1 bal.\nAantal pylonen: 8 (2 x 4 voor vierkant)\nAfstand tussen de pylonen: Vierkant 3 bij 2 meter\nHoedjes: 8 (2 x 4)\n1ste hoedje op 10 m\n2e hoedje op 15 m\n3e hoedje op 20 m\n4e hoedje op 25 mAanwijzingen\nSpelers coachen op:\n- schieten met de binnenkant van de voet\n- standbeen in de richting van het vak\n- het schietbeen hier loodrecht op gericht \nhouden."}, {"type": "partijvorm", "title": "PARTIJVORM 5:5 (2)", "content": "Methodiek\nVijf aanvallers moeten d.m.v. samenspel/ individuele actie 5 \nverdedigers uitspelen, om daarna in het tegenoverstaande doel te \nscoren.\nDe verdedigers kunnen de afgepakte bal scoren door hetzelfde \naan de andere kant van het vak te doen.\nOpgelet! \nBal buiten het veld, dan start het andere team de partij opnieuw.\nVariatie in uitvoering:\nMet 3 teams wisselen naar eigen inzicht.Materialen\nAantal spelers: 10(15)+2(3) keepers\nAantal ballen: 5\nAantal pylonen: 4\nAfstand tussen pylonen:\nF-pupillen: 30m bij 25m\nE-pupillen: 30m bij 25m\nDoel: 2\nF- en E-junioren: 5m bij 2m\nDoordraaien: \n- het winnende team blijft staan en het \nverliezende team wisselt met het 3e team.\n- geen score na twee minuten, dan wordt de \nlangst staande partij gewisseld.Aanwijzingen\nBij de aanval coachen op:\n- het samenspelen vanuit een diamantvorm\n- het uiteen bewegen bij balbezit\n- het voorkomen van buitenspel\n- het maken van keuzes ( 1:1 of overspelen) \naan de bal\n- het rekening houden met omschakeling bij \nbalverlies en ook bij het innemen van een \naanvallende positie.\nBij het verdedigen coachen op:\n- het knijpen, daar waar nodig\n- het gebruik maken van de buitenspelregel\n- het coachen van elkaar (het initiatief ligt bij \nde achterste speler)\n- het rekening houden met omschakeling bij \nbalverovering.\nKeepers coachen op:\n- het altijd aanspeelbaar zijn bij balbezit\n- het coachen van je medespelers bij het \nverdedigen.\nOpmerkingen:\n- bij een partij op scherp mag men de bal vrij \nraken\n- leg accenten op: de individuele actie, het \nscoren onder druk, een snelle omschakeling, \nde conditionele (anaeroob- lactisch)/ mentale \nfactoren\n- houdt in de organisatie ook aandacht voor: \ngenoeg ballen om het veld, een strakke felle \ncoaching."}], "session_b": [{"type": "warming_up", "title": "OVERSTEEK SPEL", "content": "Methodiek\nAlle spelers staan met de bal aan de voet aan één kant van het \nveld en één speler staat zonder bal in het midden. Op een teken \nvan de trainer mogen de spelers proberen het veld over te steken. \nDe tikker moet vervolgens proberen de ballen van de spelers \nbuiten het veld te schieten.\nDe spelers van een weggeschoten bal gaan ook in het midden \nstaan om de bal af te pakken.\nVariatie:\n- De spelers moeten zelf hun weggetrapte bal ophalen en weer bij \nde groep aansluiten.\n- Weggeschoten bal ophalen en dan wachten om te zien wie er \nover blijft. De winnaar mag de nieuwe tikker zijn of aanwijzen.\n- Twee of meerdere afpakkers.Materialen\nTijd: 10-15 min\nPylonen: \n4 pylonen om het speelveld uit te zetten.\n2 pylonen/hoedjes om de middenlijn uit te zetten.\nBallen: iedere speler een bal op de tikker na die \nde ballen gaat afpakken.Aanwijzingen\n- Zorg dat de spelers de bal dicht bij zich \nhouden zodat ze de bal goed kunnen sturen.\n- Laat de spelers telkens op het teken van de \ntrainer starten."}, {"type": "techniek", "title": "PARCOURS DRIBBELEN EN AFWERKEN", "content": "Methodiek\nDe spelers slalommen dribbelend het hele parcours door en werk \naf op doel.\nVariatie in aanbieden:\n- Varieer in uitvoeringssnelheid\n- Varieer onderlinge afstand pylonen.\n- Voer de oefening in wedstrijdvorm uit.Materialen\nAantal spelers: 4-10\nAantal ballen: elke speler 1 bal\nAantal pylonen: 8\nDoelen: 2\nOnderlinge afstand pylonen: 2 a 3 meterAanwijzingen\nSpelers coachen op:\n- Houdt de bal dichtbij je, maar niet onder je.\n- Probeer de bal zoveel mogelijk te raken.\n- Probeer de bal bij iedere stap te raken, dan \nkun je de bal ook beter sturen."}, {"type": "partijvorm", "title": "PARTIJVORM 5:5 (2)", "content": "Methodiek\nVijf aanvallers moeten d.m.v. samenspel/ individuele actie 5 \nverdedigers uitspelen, om daarna in het tegenoverstaande doel te \nscoren.\nDe verdedigers kunnen de afgepakte bal scoren door hetzelfde \naan de andere kant van het vak te doen.\nOpgelet! \nBal buiten het veld, dan start het andere team de partij opnieuw.\nVariatie in uitvoering:\nMet 3 teams wisselen naar eigen inzicht.Materialen\nAantal spelers: 10(15)+2(3) keepers\nAantal ballen: 5\nAantal pylonen: 4\nAfstand tussen pylonen:\nF-pupillen: 30m bij 25m\nE-pupillen: 30m bij 25m\nDoel: 2\nF- en E-junioren: 5m bij 2m\nDoordraaien: \n- het winnende team blijft staan en het \nverliezende team wisselt met het 3e team.\n- geen score na twee minuten, dan wordt de \nlangst staande partij gewisseld.Aanwijzingen\nBij de aanval coachen op:\n- het samenspelen vanuit een diamantvorm\n- het uiteen bewegen bij balbezit\n- het voorkomen van buitenspel\n- het maken van keuzes ( 1:1 of overspelen) \naan de bal\n- het rekening houden met omschakeling bij \nbalverlies en ook bij het innemen van een \naanvallende positie.\nBij het verdedigen coachen op:\n- het knijpen, daar waar nodig\n- het gebruik maken van de buitenspelregel\n- het coachen van elkaar (het initiatief ligt bij \nde achterste speler)\n- het rekening houden met omschakeling bij \nbalverovering.\nKeepers coachen op:\n- het altijd aanspeelbaar zijn bij balbezit\n- het coachen van je medespelers bij het \nverdedigen.\nOpmerkingen:\n- bij een partij op scherp mag men de bal vrij \nraken\n- leg accenten op: de individuele actie, het \nscoren onder druk, een snelle omschakeling, \nde conditionele (anaeroob- lactisch)/ mentale \nfactoren\n- houdt in de organisatie ook aandacht voor: \ngenoeg ballen om het veld, een strakke felle \ncoaching."}]}'::jsonb),
  ('O8', 19, '{"session_a": [{"type": "warming_up", "title": "GEWOON TIKKERTJE", "content": "Methodiek\nElke speler heeft een bal aan zijn voet, behalve de tikker. De \ntikker probeert zo veel mogelijk spelers te tikken.\nVariatie:\n- De tikker heeft ook een bal.\n- De tikker kan spelers aftikken door hun bal weg te schoppen\nOpgelet!\nJe mag weer deelnemen als een \"vrije speler\" je weer \"vrij\" getikt \nheeft.Materialen\nDuur spel:10-15 min\nDuur ronde: 1 a 2 min\nAantal: 6-8 of meer spelers\nPylonen: 4 om het speelveld af te bakenen.\nBallen: voor iedere speler een balAanwijzingen\nWedstrijdopties:\nOptie 1: Tel het aantal getikte spelers.\nOptie 2: De getikte speler gaat aan de kant \nstaan.\nOptie 3: De getikte speler wordt de nieuwe \ntikker."}, {"type": "techniek", "title": "STAP 1: VAK SCHIETEN MET DRIBBELEN", "content": "Methodiek\n2 ploegen, bestaande uit 3 spelers met bal, staan bij de eerste \npylon.\nA. - de spelers moeten vanaf dit punt met de bal dribbelen naar \nde tweede pylon.\nB. - vervolgens in één keer schieten in het vak.\nLukt dit, dan behaald men 1 punt.\nOpgelet!\n- dribbelen en schieten moet in één beweging\n- winnaar is de ploeg met de meeste punten.\nVariatie:\n- bal met het andere been spelen\n- vak vergroten/ verkleinen\n- afstand naar het vak vergroten/ verkleinen.Materialen\nAantal spelers: 6-10\nAantal ballen: elke speler 1 bal\nAantal pylonen: 12\nAfstand tussen de pylonen:\n- Vierkant 3 bij 2 meter\n- Schietafstand:10, 15 of 20 meter\n- Dribbelafstand; 6 meterAanwijzingen\nSpelers coachen op:\n- schieten met de binnenkant van de voet\n- speelbeen loodrecht op de speelrichting\n- de overgang van de dribbel naar het \nschieten moet vloeiend verlopen."}, {"type": "partijvorm", "title": "PARTIJVORM 4:4 + 2 KEEPERS", "content": "Methodiek\nVier aanvallers moeten d.m.v. samenspel/ individuele actie 4 \nverdedigers uitspelen, om daarna in het tegenoverstaande doel te \nscoren.\nDe verdedigers kunnen de afgepakte bal scoren door hetzelfde \naan de andere kant van het vak te doen.\nOpgelet! \nBal buiten het veld, dan start het andere team de partij opnieuw.\nVariatie in uitvoering:\nMet 3 teams wisselen naar eigen inzicht.Materialen\nAantal spelers:8(12)+2(3) keepers\nAantal ballen: 5\nAantal pylonen: 4\nAfstand tussen pylonen:\nF-pupillen: 25m bij 20m\nE-pupillen: 30m bij 25m\nD-pupillen: 30m bij 25m\nC-junioren: 35m bij 30m\nB-,A-junioren: 40m bij 35m\nDoel: 2\nF- en E-pupillen: 5m bij 2m\nD-,C-,B-,A-junioren: 7.32m bij 2.44\nDoordraaien: \nHet winnende team blijft staan en het \nverliezende team wisselt met het 3e team.\nAls er na twee minuten nog niet is gescoord, dan \nwordt de partij die het langst in het veld staat \ngewisseld.Aanwijzingen\nBij de aanval coachen op:\n- het samenspelen vanuit een ruit vorm, \nwaarbij gebruik gemaakt moet worden van \nde vrije positie van de keeper (overtalsituatie)\n- het creëren van een twee tegen een situatie\n- het zo breed en diep mogelijk staan van de \ntwee buitenste spelers.\n- het rekening houden bij balverlies met \nomschakeling, ook bij het innemen van een \naanvallende positie.\nBij het verdedigen coachen op:\n- het knijpen, daar waar nodig\n- het coachen van elkaar ( het initiatief ligt bij \nde achterste speler).\n- het rekening houden bij balverovering met \nomschakeling.\nKeepers coachen op:\n- het altijd aanspeelbaar zijn bij balbezit\n- het coachen bij het verdedigen van je \nmedespelers\nOpmerkingen:\n- bij een partij op scherp mag men de bal vrij \nraken\n- accenten leggen op: individuele actie; \nscoren onder druk; snelle omschakeling;\n- in de organisatie aandacht voor: genoeg \nballen om het veld; strakke felle coaching"}], "session_b": [{"type": "warming_up", "title": "PAPEGAAIEN", "content": "Methodiek\nElk tweetal heeft één bal. Eén speler, zonder bal, loopt voorop en \nbepaald de koers door het vak. De andere speler, met bal, \nprobeert hem overal te volgen.\nOpgelet!\nBewaak de onderlinge afstand van circa 2 mtr.Materialen\nTijd: 10-15 min\nRonde tijden: 1 a 2 min\nPylonen: 4 pylonen om het speelveld uit te zetten\nBallen: per tweetal een balAanwijzingen\n- Maak makkelijke loopacties en maak het \nlater moeilijker\n- Maak het speelveld groter/ kleiner om het \nvoor de spelers makkelijker/ moeilijker te \nmaken. \n- Een kleiner speelveld is moeilijker omdat de \nspelers dichter op elkaar lopen."}, {"type": "techniek", "title": "PENALTY SCHIETEN", "content": "Methodiek\nIn het doel staan twee pylonen. De afstand tusssen de pylon en de \npaal is 2 meter.\nDe spelers proberen de bal in de rechter- of linkerhoek te schieten \ntussen de pylon en de paal.\nWie schiet de meeste penalties tussen de pylon en de paal?\nVariatie in uitvoering:\n- de afstand tussen de pylon en de paal verkleinen.\n- een keeper op doel zetten.Materialen\nAantal spelers: 4- 8 + (2 keepers)\nAantal ballen: ieder speler een bal\nAantal pylonen: 6\nSchietafstand:\nF- pupillen: 7m\nE-pupillen: 8m\nD-,C-,B-,A-junioren: 11m\nDoelen: 2\nF- en E-pupillen: 5m bij 2m\nD-,C-,B-,A-junioren: 7.32m bij 2.44m\nDoordraaien:\n- elke speler haalt, nadat hij geschoten heeft, \nzijn eigen bal op en sluit achter in de andere rij \naan.Aanwijzingen\nSpelers coachen op:\n- geef de bal de juiste snelheid mee.\n- bal in het hart raken.\n- spanning in de voet.\n- standbeen iets voorbij de bal, bal blijft laag."}, {"type": "partijvorm", "title": "PARTIJVORM 4:4 + 2 KEEPERS", "content": "Methodiek\nVier aanvallers moeten d.m.v. samenspel/ individuele actie 4 \nverdedigers uitspelen, om daarna in het tegenoverstaande doel te \nscoren.\nDe verdedigers kunnen de afgepakte bal scoren door hetzelfde \naan de andere kant van het vak te doen.\nOpgelet! \nBal buiten het veld, dan start het andere team de partij opnieuw.\nVariatie in uitvoering:\nMet 3 teams wisselen naar eigen inzicht.Materialen\nAantal spelers:8(12)+2(3) keepers\nAantal ballen: 5\nAantal pylonen: 4\nAfstand tussen pylonen:\nF-pupillen: 25m bij 20m\nE-pupillen: 30m bij 25m\nD-pupillen: 30m bij 25m\nC-junioren: 35m bij 30m\nB-,A-junioren: 40m bij 35m\nDoel: 2\nF- en E-pupillen: 5m bij 2m\nD-,C-,B-,A-junioren: 7.32m bij 2.44\nDoordraaien: \nHet winnende team blijft staan en het \nverliezende team wisselt met het 3e team.\nAls er na twee minuten nog niet is gescoord, dan \nwordt de partij die het langst in het veld staat \ngewisseld.Aanwijzingen\nBij de aanval coachen op:\n- het samenspelen vanuit een ruit vorm, \nwaarbij gebruik gemaakt moet worden van \nde vrije positie van de keeper (overtalsituatie)\n- het creëren van een twee tegen een situatie\n- het zo breed en diep mogelijk staan van de \ntwee buitenste spelers.\n- het rekening houden bij balverlies met \nomschakeling, ook bij het innemen van een \naanvallende positie.\nBij het verdedigen coachen op:\n- het knijpen, daar waar nodig\n- het coachen van elkaar ( het initiatief ligt bij \nde achterste speler).\n- het rekening houden bij balverovering met \nomschakeling.\nKeepers coachen op:\n- het altijd aanspeelbaar zijn bij balbezit\n- het coachen bij het verdedigen van je \nmedespelers\nOpmerkingen:\n- bij een partij op scherp mag men de bal vrij \nraken\n- accenten leggen op: individuele actie; \nscoren onder druk; snelle omschakeling;\n- in de organisatie aandacht voor: genoeg \nballen om het veld; strakke felle coaching"}]}'::jsonb),
  ('O8', 20, '{"session_a": [{"type": "warming_up", "title": "POORT TIKKERTJE", "content": "Methodiek\n1 speler probeert als tikker de anderen te tikken. Een getikte speler blijft \nwijdbeens staan. Elke \"vrije speler\" kan hen weer \"vrij\" tikken door de bal onder \nhun poortje door te spelen en direct weer onder controle mee te nemen.Materialen\nDuur:10-15 min\nDuur ronde: 1 a 2 min\nAantal: 6-8 of meer spelers\nPylonen: 4 om het speelveld af te bakenen.\nBallen: iedere speler een bal."}, {"type": "techniek", "title": "STAP 1: VOETBAL CURLING", "content": "Methodiek\nVerdeel het speelveld in 5 vakken van elk 1 meter breed. De \nspelers schieten de bal op een afstand van 10 meter vanaf het \nmiddelste vak. \nHet behaalde aantal punten van de 3 pogingen wordt bij elkaar \nopgeteld.\nT.b.v. puntentelling:\n- middelste vak 5 punten\n- de vakken daarnaast 3 punten\n- buitenste vak 1 punt\n- daarbuiten 0\n- winnaar is degene met de meeste punten.\nVariatie:\n- schietafstand vergroten tot 15 en/ of 20 meter.Materialen\nAantal spelers: 2-4\nAantal pylonen: 20\nAantal ballen: elke speler 1 bal\nSchietafstand: 10, 15 en 20 meterAanwijzingen\nSpelers coachen op:\n- schieten met de binnenkant van de voet.\n- standbeen in de richting van het vak.\n- het schietbeen hier loodrecht op gericht \nhouden."}, {"type": "partijvorm", "title": "PARTIJVORM 5:5 (2)", "content": "Methodiek\nVijf aanvallers moeten d.m.v. samenspel/ individuele actie 5 \nverdedigers uitspelen, om daarna in het tegenoverstaande doel te \nscoren.\nDe verdedigers kunnen de afgepakte bal scoren door hetzelfde \naan de andere kant van het vak te doen.\nOpgelet! \nBal buiten het veld, dan start het andere team de partij opnieuw.\nVariatie in uitvoering:\nMet 3 teams wisselen naar eigen inzicht.Materialen\nAantal spelers: 10(15)+2(3) keepers\nAantal ballen: 5\nAantal pylonen: 4\nAfstand tussen pylonen:\nF-pupillen: 30m bij 25m\nE-pupillen: 30m bij 25m\nDoel: 2\nF- en E-junioren: 5m bij 2m\nDoordraaien: \n- het winnende team blijft staan en het \nverliezende team wisselt met het 3e team.\n- geen score na twee minuten, dan wordt de \nlangst staande partij gewisseld.Aanwijzingen\nBij de aanval coachen op:\n- het samenspelen vanuit een diamantvorm\n- het uiteen bewegen bij balbezit\n- het voorkomen van buitenspel\n- het maken van keuzes ( 1:1 of overspelen) \naan de bal\n- het rekening houden met omschakeling bij \nbalverlies en ook bij het innemen van een \naanvallende positie.\nBij het verdedigen coachen op:\n- het knijpen, daar waar nodig\n- het gebruik maken van de buitenspelregel\n- het coachen van elkaar (het initiatief ligt bij \nde achterste speler)\n- het rekening houden met omschakeling bij \nbalverovering.\nKeepers coachen op:\n- het altijd aanspeelbaar zijn bij balbezit\n- het coachen van je medespelers bij het \nverdedigen.\nOpmerkingen:\n- bij een partij op scherp mag men de bal vrij \nraken\n- leg accenten op: de individuele actie, het \nscoren onder druk, een snelle omschakeling, \nde conditionele (anaeroob- lactisch)/ mentale \nfactoren\n- houdt in de organisatie ook aandacht voor: \ngenoeg ballen om het veld, een strakke felle \ncoaching."}], "session_b": [{"type": "warming_up", "title": "SIGNAAL SPEL", "content": "Methodiek\nAlle spelers staan met een bal naast elkaar in één rij voor de \ntrainer. Vooraf spreekt de trainer met de spelers bepaalde tekens \naf. Op een teken van de trainer voeren de spelers bijbehorende \nopdracht uit.\nVoorbeelden zijn:\n- dribbelen op de plaats door de bal links rechts te tikken\n- dribbelen naar links of rechts.\n- voor uit of achteruit te dribbelen.\n- voeten beurtlinks links rechts op de bal zetten.\n- etc.Materialen\nTijd: 10-15 min\nPylonen: gebruik hiervoor de ruimte die u voor u \ntraining ter beschikking heeft.\nBallen: voor iedere speler een bal.Aanwijzingen\n- zorg dat elke speler voldoende ruimte heeft \nvoor het uitvoeren van de oefening.\n- houdt controle over de bal. Let er op dat de \nspelers de bal dichtbij zich houden.\n- doe eerst oefeningen zonder bal."}, {"type": "techniek", "title": "IN STROOMVORM (1)", "content": "Methodiek\nDeze vorm wordt uitgevoerd met twee rijen spelers.\nA. Speler 1 of 2 speelt de bal met de binnenkant van de buitenste \nvoet in op de trainer en loopt daarna achter zijn bal aan.\nB. De trainer neemt de bal aan en legt de bal stil voor de \ninlopende speler 1 of 2.\nC. Speler 1 of 2 schiet vervolgens de stilliggende bal op doel, etc.\nVariatie in uitvoering: \nNa elk schot wisselen van rij.Materialen\nAantal spelers: 8- 10\nAantal ballen: elke speler heeft een bal\nAantal pylonen: 2\nDoelen: 1\nF-t/m E-pupillen: 5m bij 2m\nD-t/m A-junioren: 7.32m bij 2.44m\nAfstand trainer tot het doel:\n1 ste jaars F-pupillen: 5 m\n2e jaars F-pupillen: 8 m\n1e jaars E-pupillen: 10 m\n2e jaars E-pupillen: 12 m\nD-pupillen: 14 m\nC-,B-,A-junioren: >16 m\nDoordraaien:\nElke speler haalt, nadat hij geschoten heeft, zijn \neigen bal op en sluit weer achter in de rij aan.Aanwijzingen\nSpelers coachen op:\n- Bal in het hart raken\n- Spanning in de voet\n- Raakvlak: Binnenkant of volle wreef, \nafhankelijk van de situatie.\n- Standbeen iets voorbij de bal, bal blijft laag.\n- Standbeen iets achter de bal, bal aan de \nonderkant raken, bal gaat omhoog.\n- De overgang van het aan komen lopen naar \nhet schieten moet vloeiend verlopen."}, {"type": "partijvorm", "title": "PARTIJVORM 5:5 (2)", "content": "Methodiek\nVijf aanvallers moeten d.m.v. samenspel/ individuele actie 5 \nverdedigers uitspelen, om daarna in het tegenoverstaande doel te \nscoren.\nDe verdedigers kunnen de afgepakte bal scoren door hetzelfde \naan de andere kant van het vak te doen.\nOpgelet! \nBal buiten het veld, dan start het andere team de partij opnieuw.\nVariatie in uitvoering:\nMet 3 teams wisselen naar eigen inzicht.Materialen\nAantal spelers: 10(15)+2(3) keepers\nAantal ballen: 5\nAantal pylonen: 4\nAfstand tussen pylonen:\nF-pupillen: 30m bij 25m\nE-pupillen: 30m bij 25m\nDoel: 2\nF- en E-junioren: 5m bij 2m\nDoordraaien: \n- het winnende team blijft staan en het \nverliezende team wisselt met het 3e team.\n- geen score na twee minuten, dan wordt de \nlangst staande partij gewisseld.Aanwijzingen\nBij de aanval coachen op:\n- het samenspelen vanuit een diamantvorm\n- het uiteen bewegen bij balbezit\n- het voorkomen van buitenspel\n- het maken van keuzes ( 1:1 of overspelen) \naan de bal\n- het rekening houden met omschakeling bij \nbalverlies en ook bij het innemen van een \naanvallende positie.\nBij het verdedigen coachen op:\n- het knijpen, daar waar nodig\n- het gebruik maken van de buitenspelregel\n- het coachen van elkaar (het initiatief ligt bij \nde achterste speler)\n- het rekening houden met omschakeling bij \nbalverovering.\nKeepers coachen op:\n- het altijd aanspeelbaar zijn bij balbezit\n- het coachen van je medespelers bij het \nverdedigen.\nOpmerkingen:\n- bij een partij op scherp mag men de bal vrij \nraken\n- leg accenten op: de individuele actie, het \nscoren onder druk, een snelle omschakeling, \nde conditionele (anaeroob- lactisch)/ mentale \nfactoren\n- houdt in de organisatie ook aandacht voor: \ngenoeg ballen om het veld, een strakke felle \ncoaching."}]}'::jsonb),
  ('O8', 21, '{"session_a": [{"type": "warming_up", "title": "OVERLOOPSPEL", "content": "Methodiek\nAlle spelers staan, op één speler na, met een bal aan de voet aan één zijde van \nhet speelveld.\nDe tikker staat ook met een bal aan de voet in het speelveld.\nOp een teken moeten de spelers de bal naar de overkant dribbelen. De tikker \nprobeert nu met de bal zoveel mogelijk spelers onderweg af te tikken.\nWie tikt de meeste spelers af in 2 beurten?\nOpgelet!\n- als je de bal niet bij je houdt dan ben je ook af.\nVariatie:\n- ook de tikker heeft de bal aan de voet\n- opvoeren van het aantal beurten. Materialen\nDuur:10-15 min\nDuur ronde: 1 a 2 min\nAantal: 6-12 spelers\nPylonen: 4 om het speelveld af te bakenen."}, {"type": "techniek", "title": "STAP 1: DOOR DE BENEN SCHIETEN", "content": "Methodiek\nTweetallen, staan op 10 - 15 mtr. afstand tegenover elkaar met \nhun benen wijdt. Zij moeten proberen tussen de benen door van \nhun maatje te scoren. Wie de meeste goals maakt, binnen een \nbepaalde tijd of bepaald aantal keer, is de \"winnaar\".Materialen\nAantal spelers: 2-10 \nAantal ballen: per tweetal 1 bal\nAfstand tussen de spelers: 10-15 meterAanwijzingen\nSpelers coachen op:\n- schieten met de binnenkant van de voet.\n- speelbeen loodrecht op de speelrichting.\n- voetzool parallel met de grond."}, {"type": "partijvorm", "title": "PARTIJVORM 4:4 + 2 KEEPERS", "content": "Methodiek\nVier aanvallers moeten d.m.v. samenspel/ individuele actie 4 \nverdedigers uitspelen, om daarna in het tegenoverstaande doel te \nscoren.\nDe verdedigers kunnen de afgepakte bal scoren door hetzelfde \naan de andere kant van het vak te doen.\nOpgelet! \nBal buiten het veld, dan start het andere team de partij opnieuw.\nVariatie in uitvoering:\nMet 3 teams wisselen naar eigen inzicht.Materialen\nAantal spelers:8(12)+2(3) keepers\nAantal ballen: 5\nAantal pylonen: 4\nAfstand tussen pylonen:\nF-pupillen: 25m bij 20m\nE-pupillen: 30m bij 25m\nD-pupillen: 30m bij 25m\nC-junioren: 35m bij 30m\nB-,A-junioren: 40m bij 35m\nDoel: 2\nF- en E-pupillen: 5m bij 2m\nD-,C-,B-,A-junioren: 7.32m bij 2.44\nDoordraaien: \nHet winnende team blijft staan en het \nverliezende team wisselt met het 3e team.\nAls er na twee minuten nog niet is gescoord, dan \nwordt de partij die het langst in het veld staat \ngewisseld.Aanwijzingen\nBij de aanval coachen op:\n- het samenspelen vanuit een ruit vorm, \nwaarbij gebruik gemaakt moet worden van \nde vrije positie van de keeper (overtalsituatie)\n- het creëren van een twee tegen een situatie\n- het zo breed en diep mogelijk staan van de \ntwee buitenste spelers.\n- het rekening houden bij balverlies met \nomschakeling, ook bij het innemen van een \naanvallende positie.\nBij het verdedigen coachen op:\n- het knijpen, daar waar nodig\n- het coachen van elkaar ( het initiatief ligt bij \nde achterste speler).\n- het rekening houden bij balverovering met \nomschakeling.\nKeepers coachen op:\n- het altijd aanspeelbaar zijn bij balbezit\n- het coachen bij het verdedigen van je \nmedespelers\nOpmerkingen:\n- bij een partij op scherp mag men de bal vrij \nraken\n- accenten leggen op: individuele actie; \nscoren onder druk; snelle omschakeling;\n- in de organisatie aandacht voor: genoeg \nballen om het veld; strakke felle coaching"}], "session_b": [{"type": "warming_up", "title": "DRIBBEL KAP (RECHTHOEK)", "content": "Methodiek\nElke speler heeft een bal en dribbelt de bal naar het midden van \nde linker pylonen van het eerste vierkant. Daar aangekomen \nneemt hij de bal met een kapbeweging mee naar de eerste \nrechter pylon.\nIdem, in het tweede vierkant.\nDaarna dribbelt hij de bal terug en sluit achter in de rij aan.\nVariatie in aanbieden:\nVarieer de snelheid.Materialen\nAantal spelers: 4-14\nAantal ballen: elke speler 1 bal\nAantal pylonen: 6\nAfstand tussen de pylonen: 12 á 15 meter.Aanwijzingen\nSpelers coachen op:\n- Houdt de bal dichtbij je, maar niet onder je.\n- Let goed op de uitvoering van de techniek.\n- De volgende speler kan starten als de \nvoorgaande speler start met het tweede deel."}, {"type": "techniek", "title": "PARCOURS DRIBBELEN EN AFWERKEN", "content": "Methodiek\nDe spelers slalommen dribbelend het hele parcours door en werk \naf op doel.\nVariatie in aanbieden:\n- Varieer in uitvoeringssnelheid\n- Varieer onderlinge afstand pylonen.\n- Voer de oefening in wedstrijdvorm uit.Materialen\nAantal spelers: 4-10\nAantal ballen: elke speler 1 bal\nAantal pylonen: 8\nDoelen: 2\nOnderlinge afstand pylonen: 2 a 3 meterAanwijzingen\nSpelers coachen op:\n- Houdt de bal dichtbij je, maar niet onder je.\n- Probeer de bal zoveel mogelijk te raken.\n- Probeer de bal bij iedere stap te raken, dan \nkun je de bal ook beter sturen."}, {"type": "partijvorm", "title": "PARTIJVORM 4:4 + 2 KEEPERS", "content": "Methodiek\nVier aanvallers moeten d.m.v. samenspel/ individuele actie 4 \nverdedigers uitspelen, om daarna in het tegenoverstaande doel te \nscoren.\nDe verdedigers kunnen de afgepakte bal scoren door hetzelfde \naan de andere kant van het vak te doen.\nOpgelet! \nBal buiten het veld, dan start het andere team de partij opnieuw.\nVariatie in uitvoering:\nMet 3 teams wisselen naar eigen inzicht.Materialen\nAantal spelers:8(12)+2(3) keepers\nAantal ballen: 5\nAantal pylonen: 4\nAfstand tussen pylonen:\nF-pupillen: 25m bij 20m\nE-pupillen: 30m bij 25m\nD-pupillen: 30m bij 25m\nC-junioren: 35m bij 30m\nB-,A-junioren: 40m bij 35m\nDoel: 2\nF- en E-pupillen: 5m bij 2m\nD-,C-,B-,A-junioren: 7.32m bij 2.44\nDoordraaien: \nHet winnende team blijft staan en het \nverliezende team wisselt met het 3e team.\nAls er na twee minuten nog niet is gescoord, dan \nwordt de partij die het langst in het veld staat \ngewisseld.Aanwijzingen\nBij de aanval coachen op:\n- het samenspelen vanuit een ruit vorm, \nwaarbij gebruik gemaakt moet worden van \nde vrije positie van de keeper (overtalsituatie)\n- het creëren van een twee tegen een situatie\n- het zo breed en diep mogelijk staan van de \ntwee buitenste spelers.\n- het rekening houden bij balverlies met \nomschakeling, ook bij het innemen van een \naanvallende positie.\nBij het verdedigen coachen op:\n- het knijpen, daar waar nodig\n- het coachen van elkaar ( het initiatief ligt bij \nde achterste speler).\n- het rekening houden bij balverovering met \nomschakeling.\nKeepers coachen op:\n- het altijd aanspeelbaar zijn bij balbezit\n- het coachen bij het verdedigen van je \nmedespelers\nOpmerkingen:\n- bij een partij op scherp mag men de bal vrij \nraken\n- accenten leggen op: individuele actie; \nscoren onder druk; snelle omschakeling;\n- in de organisatie aandacht voor: genoeg \nballen om het veld; strakke felle coaching"}]}'::jsonb),
  ('O8', 22, '{"session_a": [{"type": "warming_up", "title": "DRIBBELTIKKERTJE", "content": "Methodiek\nAlle spelers, behalve de tikker, dribbelen met de bal aan de voet in het speelveld. \nDe tikker heeft zijn bal in de handen en moet nu met zijn bal proberen de bal van \neen dribbelende speler te tikken.\nAls dit is lukt, wordt de afgetikte speler de nieuwe tikker, etc. Materialen\nDuur:10-15 min\nDuur ronde: 1 a 2 min\nAantal: 6-12 spelers\nPylonen: 4 om het speelveld af te bakenen.\nAantal ballen: zoveel als nodig is voor het spel.\nDRIBBELEN MET DE BAL, MET LINKS, RECHTS EN TUSSEN DE VOETEN\nMethodiek\nElke speler heeft een bal. De spelers dribbelen de bal met links, \nrechts en tussen de voeten, het uitgezette vierkant rond.\nA. Dribbelen met de buitenkant van de linker voet.\nB. Dribbelen met de bal tussen de voeten; links rechts heen en \nweer.\nC. Dribbelen met de buitenkant van rechter voet.\nD. Dribbelen met de bal tussen de voeten; links rechts heen en \nweer.\nVariatie:\n- Varieer onderlinge afstand pylonen\n- Varieer in uitvoeringssnelheid.Materialen\nAantal spelers: 4-10\nAantal ballen: elke speler 1 bal\nAantal pylonen: 4\nOnderling afstand pylonen: 10 a 12 meterAanwijzingen\nSpelers coachen op:\n- De bal dichtbij je houden, maar niet onder \nje.\n- Probeer de bal zoveel mogelijk te raken.\n- Probeer de bal bij iedere stap te raken, dan \nkun je de bal ook beter sturen."}, {"type": "techniek", "title": "STAP 1: PYLONEN KONING", "content": "Methodiek\nTweetallen staan op 10 - 15 mtr. afstand tegenover elkaar achter \nhun pylon. Zij moeten proberen elkaars pylon omver te schieten.\n- wie de meeste pylonen raakt, heeft gewonnenMaterialen\nAantal spelers: 2-10 \nAantal doeltjes: elke speler een pylon\nAantal ballen: per tweetal 1 bal\nAfstand tussen de doeltjes: 10-15 meterAanwijzingen\nSpelers coachen op:\n- schieten met de binnenkant van de voet\n- speelbeen loodrecht op de speelrichting\n- voetzool parallel met de grond."}, {"type": "partijvorm", "title": "PARTIJVORM 5:5 (2)", "content": "Methodiek\nVijf aanvallers moeten d.m.v. samenspel/ individuele actie 5 \nverdedigers uitspelen, om daarna in het tegenoverstaande doel te \nscoren.\nDe verdedigers kunnen de afgepakte bal scoren door hetzelfde \naan de andere kant van het vak te doen.\nOpgelet! \nBal buiten het veld, dan start het andere team de partij opnieuw.\nVariatie in uitvoering:\nMet 3 teams wisselen naar eigen inzicht.Materialen\nAantal spelers: 10(15)+2(3) keepers\nAantal ballen: 5\nAantal pylonen: 4\nAfstand tussen pylonen:\nF-pupillen: 30m bij 25m\nE-pupillen: 30m bij 25m\nDoel: 2\nF- en E-junioren: 5m bij 2m\nDoordraaien: \n- het winnende team blijft staan en het \nverliezende team wisselt met het 3e team.\n- geen score na twee minuten, dan wordt de \nlangst staande partij gewisseld.Aanwijzingen\nBij de aanval coachen op:\n- het samenspelen vanuit een diamantvorm\n- het uiteen bewegen bij balbezit\n- het voorkomen van buitenspel\n- het maken van keuzes ( 1:1 of overspelen) \naan de bal\n- het rekening houden met omschakeling bij \nbalverlies en ook bij het innemen van een \naanvallende positie.\nBij het verdedigen coachen op:\n- het knijpen, daar waar nodig\n- het gebruik maken van de buitenspelregel\n- het coachen van elkaar (het initiatief ligt bij \nde achterste speler)\n- het rekening houden met omschakeling bij \nbalverovering.\nKeepers coachen op:\n- het altijd aanspeelbaar zijn bij balbezit\n- het coachen van je medespelers bij het \nverdedigen.\nOpmerkingen:\n- bij een partij op scherp mag men de bal vrij \nraken\n- leg accenten op: de individuele actie, het \nscoren onder druk, een snelle omschakeling, \nde conditionele (anaeroob- lactisch)/ mentale \nfactoren\n- houdt in de organisatie ook aandacht voor: \ngenoeg ballen om het veld, een strakke felle \ncoaching."}], "session_b": [{"type": "warming_up", "title": "DRIBBELTIKKERTJE", "content": "Methodiek\nAlle spelers, behalve de tikker, dribbelen met de bal aan de voet in het speelveld. \nDe tikker heeft zijn bal in de handen en moet nu met zijn bal proberen de bal van \neen dribbelende speler te tikken.\nAls dit is lukt, wordt de afgetikte speler de nieuwe tikker, etc. Materialen\nDuur:10-15 min\nDuur ronde: 1 a 2 min\nAantal: 6-12 spelers\nPylonen: 4 om het speelveld af te bakenen.\nAantal ballen: zoveel als nodig is voor het spel.\nDRIBBELEN MET DE BAL, MET LINKS, RECHTS EN TUSSEN DE VOETEN\nMethodiek\nElke speler heeft een bal. De spelers dribbelen de bal met links, \nrechts en tussen de voeten, het uitgezette vierkant rond.\nA. Dribbelen met de buitenkant van de linker voet.\nB. Dribbelen met de bal tussen de voeten; links rechts heen en \nweer.\nC. Dribbelen met de buitenkant van rechter voet.\nD. Dribbelen met de bal tussen de voeten; links rechts heen en \nweer.\nVariatie:\n- Varieer onderlinge afstand pylonen\n- Varieer in uitvoeringssnelheid.Materialen\nAantal spelers: 4-10\nAantal ballen: elke speler 1 bal\nAantal pylonen: 4\nOnderling afstand pylonen: 10 a 12 meterAanwijzingen\nSpelers coachen op:\n- De bal dichtbij je houden, maar niet onder \nje.\n- Probeer de bal zoveel mogelijk te raken.\n- Probeer de bal bij iedere stap te raken, dan \nkun je de bal ook beter sturen."}, {"type": "techniek", "title": "PENALTY SCHIETEN", "content": "Methodiek\nIn het doel staan twee pylonen. De afstand tusssen de pylon en de \npaal is 2 meter.\nDe spelers proberen de bal in de rechter- of linkerhoek te schieten \ntussen de pylon en de paal.\nWie schiet de meeste penalties tussen de pylon en de paal?\nVariatie in uitvoering:\n- de afstand tussen de pylon en de paal verkleinen.\n- een keeper op doel zetten.Materialen\nAantal spelers: 4- 8 + (2 keepers)\nAantal ballen: ieder speler een bal\nAantal pylonen: 6\nSchietafstand:\nF- pupillen: 7m\nE-pupillen: 8m\nD-,C-,B-,A-junioren: 11m\nDoelen: 2\nF- en E-pupillen: 5m bij 2m\nD-,C-,B-,A-junioren: 7.32m bij 2.44m\nDoordraaien:\n- elke speler haalt, nadat hij geschoten heeft, \nzijn eigen bal op en sluit achter in de andere rij \naan.Aanwijzingen\nSpelers coachen op:\n- geef de bal de juiste snelheid mee.\n- bal in het hart raken.\n- spanning in de voet.\n- standbeen iets voorbij de bal, bal blijft laag."}, {"type": "partijvorm", "title": "PARTIJVORM 5:5 (2)", "content": "Methodiek\nVijf aanvallers moeten d.m.v. samenspel/ individuele actie 5 \nverdedigers uitspelen, om daarna in het tegenoverstaande doel te \nscoren.\nDe verdedigers kunnen de afgepakte bal scoren door hetzelfde \naan de andere kant van het vak te doen.\nOpgelet! \nBal buiten het veld, dan start het andere team de partij opnieuw.\nVariatie in uitvoering:\nMet 3 teams wisselen naar eigen inzicht.Materialen\nAantal spelers: 10(15)+2(3) keepers\nAantal ballen: 5\nAantal pylonen: 4\nAfstand tussen pylonen:\nF-pupillen: 30m bij 25m\nE-pupillen: 30m bij 25m\nDoel: 2\nF- en E-junioren: 5m bij 2m\nDoordraaien: \n- het winnende team blijft staan en het \nverliezende team wisselt met het 3e team.\n- geen score na twee minuten, dan wordt de \nlangst staande partij gewisseld.Aanwijzingen\nBij de aanval coachen op:\n- het samenspelen vanuit een diamantvorm\n- het uiteen bewegen bij balbezit\n- het voorkomen van buitenspel\n- het maken van keuzes ( 1:1 of overspelen) \naan de bal\n- het rekening houden met omschakeling bij \nbalverlies en ook bij het innemen van een \naanvallende positie.\nBij het verdedigen coachen op:\n- het knijpen, daar waar nodig\n- het gebruik maken van de buitenspelregel\n- het coachen van elkaar (het initiatief ligt bij \nde achterste speler)\n- het rekening houden met omschakeling bij \nbalverovering.\nKeepers coachen op:\n- het altijd aanspeelbaar zijn bij balbezit\n- het coachen van je medespelers bij het \nverdedigen.\nOpmerkingen:\n- bij een partij op scherp mag men de bal vrij \nraken\n- leg accenten op: de individuele actie, het \nscoren onder druk, een snelle omschakeling, \nde conditionele (anaeroob- lactisch)/ mentale \nfactoren\n- houdt in de organisatie ook aandacht voor: \ngenoeg ballen om het veld, een strakke felle \ncoaching."}]}'::jsonb),
  ('O8', 23, '{"session_a": [{"type": "warming_up", "title": "HOND EN BAL", "content": "Methodiek\nDe spelers staan aan weerszijden van het speelveld tegenover elkaar. In het \nmidden van het speelveld ligt een bal, welke door één van de spelers gepakt \ngaat worden.\nWie durft dit aan?\nDegene (de hond) die de bal heeft moet door de andere speler worden getikt, \nvoordat hij de bal over zijn achterlijn heeft gebracht.\nWie krijgt de bal over zijn achterlijn?Materialen\nDuur:10-15 min\nDuur ronde: 2 a 3 min\nAantal: 6-12 spelers\nPylonen: 4 om het speelveld af te bakenen.\nAantal ballen: 1 bal per tweetal."}, {"type": "techniek", "title": "HEEN/TERUG (ENE EN ANDERE BEEN) IN LIJNVORM", "content": "Methodiek\nA. Speler 1 speelt naar speler 2:\n- speler 1 speelt de bal met de binnenkant van de linker- of \nrechter voet\n- speler 2 neemt de bal met de binnenkant van de linker- of \nrechter voet aan.\nB. Speler 2 speelt naar speler 1:\n- speler 2 speelt de bal met de binnenkant van de linker- of \nrechter voet.\n- speler 1 neemt de bal met de binnenkant van de linker- of \nrechter voet aan, etc.\nVariatie:\n- direct terugspelen.\nOpgelet!\n- spreek in kindertaal\n- speel de bal met de voet waarmee je aanneemt terugs of speel \nde bal met de andere voet terug of speel de bal direct terug met \nde voet waar je de bal op krijgt.Materialen\nAantal spelers: 2\nAantal ballen: 1 \nAantal pylonen: 2\nAfstand van pylonen: 1e en 2e jaars F-pupillen: \n2/3 m.Aanwijzingen\nAannemen:\n- bal moet binnen je bereik voor je liggen\n- houd snelheid na de aanname voor de \nvolgende actie\nSpelen binnenkant voet:\n- speel de bal met de juiste snelheid en op \nhet goede been aan\n- speel strak en met gevoel in\n- laat het schietbeen doorzwaaien\n- raak de bal in het hart\n- houd spanning in de voet."}, {"type": "partijvorm", "title": "PARTIJVORM 4:4", "content": "Methodiek\nVier aanvallers moeten d.m.v. samenspel/ individuele actie 4 \nverdedigers uitspelen, om daarna in één van de twee aan de \nandere kant van het vak staande doeltjes te scoren.\nDe verdedigers kunnen de afgepakte bal scoren door hetzelfde \naan de andere kant van het vak te doen.\nOpgelet! \nBal buiten het veld, dan start het andere team de partij opnieuwMaterialen\nAantal spelers: 8\nAantal ballen: 5\nAantal pylonen: 12\nAfstand tussen pylonen:\nF-pupillen: 12m bij 18m\nE-pupillen: 15m bij 20m\nD-pupillen: 20m bij 25m\nC-junioren: 25m bij 30m\nB-,A-junioren: 30m bij 35m\nDoel: 4 (2mtr.)Aanwijzingen\nBij de aanval coachen op:\n- het samenspelen vanuit een ruit vorm.\n- het voorkomen van buitenspel\n- het maken van keuzes aan de bal( 1:1 of \noverspelen)\n- het rekening houden bij balverlies met \nomschakeling, ook bij het innemen van een \naanvallende positie.\nBij het verdedigen coachen op:\n- het rekening houden met een goed zicht op \nbeide aanvallers bij het innemen van een \nverdedigende positie\n- het isoleren van de aanvaller in balbezit \nnaar de zijkant van het veld\n- het gebruik maken van de buitenspelregel\n- het rekening houden bij balverovering met \nomschakeling.\n- het aanzetten tot het maken van \npasseeracties. Pas als dit goed gaat kijk je of \nde juiste keuzes gemaakt worden \n(passeeractie of overspelen)\n- het eventueel wisselen van tegenstander na \n10 minuten."}], "session_b": [{"type": "warming_up", "title": "DRIBBELKONING", "content": "Methodiek\nElke speler heeft een bal en dribbelt door het vierkant. Twee \n\"balafpakkers\" proberen de ballen van de andere spelers de bal \nuit het vak te schieten.\nBal kwijt, dan wordt je ook \"balafpakker\".\nDe speler die overblijft is dribbelkoning.\nVariatie:\nBij een te kleine groep volstaat 1 \"balafpakker\".Materialen\nAantal spelers: 6-8\nAantal ballen: elke speler 1 bal, behalve 2 \nbalafpakkers\nHesjes: de balafpakkers\nAantal pylonen: 4\nAfstand tussen de pylonen: speelveld: ongeveer \n10 bij 15 meterAanwijzingen\nSpelers coachen op:\n- De bal dichtbij je houden.\n- De bal goed afschermen.\n- Een andere kant opgaan als de afpakker \nnaar je toekomt."}, {"type": "techniek", "title": "IN STROOMVORM (1)", "content": "Methodiek\nDeze vorm wordt uitgevoerd met twee rijen spelers.\nA. Speler 1 of 2 speelt de bal met de binnenkant van de buitenste \nvoet in op de trainer en loopt daarna achter zijn bal aan.\nB. De trainer neemt de bal aan en legt de bal stil voor de \ninlopende speler 1 of 2.\nC. Speler 1 of 2 schiet vervolgens de stilliggende bal op doel, etc.\nVariatie in uitvoering: \nNa elk schot wisselen van rij.Materialen\nAantal spelers: 8- 10\nAantal ballen: elke speler heeft een bal\nAantal pylonen: 2\nDoelen: 1\nF-t/m E-pupillen: 5m bij 2m\nD-t/m A-junioren: 7.32m bij 2.44m\nAfstand trainer tot het doel:\n1 ste jaars F-pupillen: 5 m\n2e jaars F-pupillen: 8 m\n1e jaars E-pupillen: 10 m\n2e jaars E-pupillen: 12 m\nD-pupillen: 14 m\nC-,B-,A-junioren: >16 m\nDoordraaien:\nElke speler haalt, nadat hij geschoten heeft, zijn \neigen bal op en sluit weer achter in de rij aan.Aanwijzingen\nSpelers coachen op:\n- Bal in het hart raken\n- Spanning in de voet\n- Raakvlak: Binnenkant of volle wreef, \nafhankelijk van de situatie.\n- Standbeen iets voorbij de bal, bal blijft laag.\n- Standbeen iets achter de bal, bal aan de \nonderkant raken, bal gaat omhoog.\n- De overgang van het aan komen lopen naar \nhet schieten moet vloeiend verlopen."}, {"type": "partijvorm", "title": "PARTIJVORM 4:4", "content": "Methodiek\nVier aanvallers moeten d.m.v. samenspel/ individuele actie 4 \nverdedigers uitspelen, om daarna in één van de twee aan de \nandere kant van het vak staande doeltjes te scoren.\nDe verdedigers kunnen de afgepakte bal scoren door hetzelfde \naan de andere kant van het vak te doen.\nOpgelet! \nBal buiten het veld, dan start het andere team de partij opnieuwMaterialen\nAantal spelers: 8\nAantal ballen: 5\nAantal pylonen: 12\nAfstand tussen pylonen:\nF-pupillen: 12m bij 18m\nE-pupillen: 15m bij 20m\nD-pupillen: 20m bij 25m\nC-junioren: 25m bij 30m\nB-,A-junioren: 30m bij 35m\nDoel: 4 (2mtr.)Aanwijzingen\nBij de aanval coachen op:\n- het samenspelen vanuit een ruit vorm.\n- het voorkomen van buitenspel\n- het maken van keuzes aan de bal( 1:1 of \noverspelen)\n- het rekening houden bij balverlies met \nomschakeling, ook bij het innemen van een \naanvallende positie.\nBij het verdedigen coachen op:\n- het rekening houden met een goed zicht op \nbeide aanvallers bij het innemen van een \nverdedigende positie\n- het isoleren van de aanvaller in balbezit \nnaar de zijkant van het veld\n- het gebruik maken van de buitenspelregel\n- het rekening houden bij balverovering met \nomschakeling.\n- het aanzetten tot het maken van \npasseeracties. Pas als dit goed gaat kijk je of \nde juiste keuzes gemaakt worden \n(passeeractie of overspelen)\n- het eventueel wisselen van tegenstander na \n10 minuten."}]}'::jsonb),
  ('O8', 24, '{"session_a": [{"type": "warming_up", "title": "PANNA GAME", "content": "Methodiek\nElke speler, op een na heeft een bal. Op een teken van de trainer \nmoeten de speler zonder bal, binnen een vooraf aangegeven tijd, \nzoveel mogelijk ballen van de andere spelers buiten het speelveld \nte trappen.\nElke speler moet zijn weggetrapte bal direct weer ophalen en op \nde plaats waar de bal is uitgeschoten gaan staan met de benen \nwijd en de bal boven hun hoofd in hun handen. De andere spelers \ndie nog niet zijn uitgeschoten kunnen hun medespelers vrij maken \ndoor de bal door de benen van de afgeschoten spelers te spelen. \nAls de tijd voorbij is wordt het aantal spelers dat nog met hun bal \nboven hun hoofd staan geteld. Het spel is voorbij als de \nverdedigers alle spelers met de bal boven hun hoofd hebben \nstaan.\nWie haalt het hoogste aantal?\nVariatie:\n- meer verdedigers of minder verdedigers.Materialen\nTijd: 10-15 min\nRonde tijden: 1 a 2 min\nPylonen: 4 pylonen om het speelveld uit te zetten\nBallen: Op een speler na heeft iedere speler een \nbal.Aanwijzingen\nVoor de verdedigers:\n- samenwerken en samen afspreken waar je \nde ballen gaat uitschieten. Want waar je de \nballen uitschiet daar moeten de spelers gaan \nstaan met hun bal. Uiteindelijk krijg je dan \neen grote groep spelers bij elkaar waardoor 1 \nof 2 spelers deze kunnen verdedigen en de \nandere kunnen de rest gaan uitschieten. (dit \nis de enige mogelijkheid om iederee af te \nkrijgen.)\nVoor de aanvallers:\n- kijken waar de verdedigers zijn. Op snelheid \nde verdedigers passeren en proberen je \nmedespelers vrij proberen te maken."}, {"type": "techniek", "title": "STAP 1: HOEDJE TRAP", "content": "Methodiek\n2 ploegen, waarvan elke speler een bal heeft, proberen de over \nhet hele veld verspreid staande rode en gele hoedjes van de \npylonen te schieten.\nDe ploeg die dit het eerst voor elkaar krijgt, is de winnaar.\nVariatie:\n- inzet van een verdediger, die probeert de bal van de \ntegenstander te onderscheppen, voordat deze het hoedje raakt.Materialen\nAantal spelers: 6-10\nAantal hoedjes: 10 rode en 10 gele.\nAantal ballen: elke speler 1 bal.\nHesjes: 2 kleuren en voldoende voor iedere partij.\nAantal pylonen: 24 (4 voor het speelveld en 20 \nvoor het spel)\nAfstand tussen de pylonen:\n- Speelveld: 10 bij 10 meter\n- Pylonen met hoedjes naar eigen inzicht.Aanwijzingen\nSpelers coachen op:\n- met de binnenkant van de voet schieten\n- van dichtbij schieten\n- niet te zacht schieten\n- de bal snel pakken en de volgende \nomschieten."}, {"type": "partijvorm", "title": "PARTIJVORM 5:5 (2)", "content": "Methodiek\nVijf aanvallers moeten d.m.v. samenspel/ individuele actie 5 \nverdedigers uitspelen, om daarna in het tegenoverstaande doel te \nscoren.\nDe verdedigers kunnen de afgepakte bal scoren door hetzelfde \naan de andere kant van het vak te doen.\nOpgelet! \nBal buiten het veld, dan start het andere team de partij opnieuw.\nVariatie in uitvoering:\nMet 3 teams wisselen naar eigen inzicht.Materialen\nAantal spelers: 10(15)+2(3) keepers\nAantal ballen: 5\nAantal pylonen: 4\nAfstand tussen pylonen:\nF-pupillen: 30m bij 25m\nE-pupillen: 30m bij 25m\nDoel: 2\nF- en E-junioren: 5m bij 2m\nDoordraaien: \n- het winnende team blijft staan en het \nverliezende team wisselt met het 3e team.\n- geen score na twee minuten, dan wordt de \nlangst staande partij gewisseld.Aanwijzingen\nBij de aanval coachen op:\n- het samenspelen vanuit een diamantvorm\n- het uiteen bewegen bij balbezit\n- het voorkomen van buitenspel\n- het maken van keuzes ( 1:1 of overspelen) \naan de bal\n- het rekening houden met omschakeling bij \nbalverlies en ook bij het innemen van een \naanvallende positie.\nBij het verdedigen coachen op:\n- het knijpen, daar waar nodig\n- het gebruik maken van de buitenspelregel\n- het coachen van elkaar (het initiatief ligt bij \nde achterste speler)\n- het rekening houden met omschakeling bij \nbalverovering.\nKeepers coachen op:\n- het altijd aanspeelbaar zijn bij balbezit\n- het coachen van je medespelers bij het \nverdedigen.\nOpmerkingen:\n- bij een partij op scherp mag men de bal vrij \nraken\n- leg accenten op: de individuele actie, het \nscoren onder druk, een snelle omschakeling, \nde conditionele (anaeroob- lactisch)/ mentale \nfactoren\n- houdt in de organisatie ook aandacht voor: \ngenoeg ballen om het veld, een strakke felle \ncoaching."}], "session_b": [{"type": "warming_up", "title": "KONINGSPEL MET STOPPEN VAN DE BAL", "content": "Methodiek\nElke speler heeft een bal en op een teken van de trainer dribbelen \nde spelers de bal vanuit het beginvak naar het eindvak aan de \noverkant. Onderweg probeert de \"balafpakker\" de ballen van de \nandere spelers uit het vierkant te schieten.\nBal kwijt dan wordt je ook \"balafpakker\".\nWinnaar is de speler die overblijft.\nVariatie in aanbieden:\n- Elke speler start met 3 punten. \n- Bij balverlies gaat er telkens 1 punt af. \n- Bij 0 punten is de speler af.\nWinnaar is degene die over blijft.Materialen\nAantal spelers: 6-8\nHoedjes: 6\nAantal ballen: elke speler 1 bal, behalve de \nbalafpakker\nAantal pylonen: 6\nAfstand tussen de pylonen: speelveld: ongeveer \n10 bij 15 meterAanwijzingen\nSpelers coachen op:\n- De bal dichtbij je houden.\n- De bal goed afschermen.\n- Een andere kant opgaan als de tikker naar \nje toekomt.\n- Probeer snel de overkant te bereiken.\n- Afkappen over de achterlijn."}, {"type": "techniek", "title": "PARCOURS DRIBBELEN EN AFWERKEN", "content": "Methodiek\nDe spelers slalommen dribbelend het hele parcours door en werk \naf op doel.\nVariatie in aanbieden:\n- Varieer in uitvoeringssnelheid\n- Varieer onderlinge afstand pylonen.\n- Voer de oefening in wedstrijdvorm uit.Materialen\nAantal spelers: 4-10\nAantal ballen: elke speler 1 bal\nAantal pylonen: 8\nDoelen: 2\nOnderlinge afstand pylonen: 2 a 3 meterAanwijzingen\nSpelers coachen op:\n- Houdt de bal dichtbij je, maar niet onder je.\n- Probeer de bal zoveel mogelijk te raken.\n- Probeer de bal bij iedere stap te raken, dan \nkun je de bal ook beter sturen."}, {"type": "partijvorm", "title": "PARTIJVORM 5:5 (2)", "content": "Methodiek\nVijf aanvallers moeten d.m.v. samenspel/ individuele actie 5 \nverdedigers uitspelen, om daarna in het tegenoverstaande doel te \nscoren.\nDe verdedigers kunnen de afgepakte bal scoren door hetzelfde \naan de andere kant van het vak te doen.\nOpgelet! \nBal buiten het veld, dan start het andere team de partij opnieuw.\nVariatie in uitvoering:\nMet 3 teams wisselen naar eigen inzicht.Materialen\nAantal spelers: 10(15)+2(3) keepers\nAantal ballen: 5\nAantal pylonen: 4\nAfstand tussen pylonen:\nF-pupillen: 30m bij 25m\nE-pupillen: 30m bij 25m\nDoel: 2\nF- en E-junioren: 5m bij 2m\nDoordraaien: \n- het winnende team blijft staan en het \nverliezende team wisselt met het 3e team.\n- geen score na twee minuten, dan wordt de \nlangst staande partij gewisseld.Aanwijzingen\nBij de aanval coachen op:\n- het samenspelen vanuit een diamantvorm\n- het uiteen bewegen bij balbezit\n- het voorkomen van buitenspel\n- het maken van keuzes ( 1:1 of overspelen) \naan de bal\n- het rekening houden met omschakeling bij \nbalverlies en ook bij het innemen van een \naanvallende positie.\nBij het verdedigen coachen op:\n- het knijpen, daar waar nodig\n- het gebruik maken van de buitenspelregel\n- het coachen van elkaar (het initiatief ligt bij \nde achterste speler)\n- het rekening houden met omschakeling bij \nbalverovering.\nKeepers coachen op:\n- het altijd aanspeelbaar zijn bij balbezit\n- het coachen van je medespelers bij het \nverdedigen.\nOpmerkingen:\n- bij een partij op scherp mag men de bal vrij \nraken\n- leg accenten op: de individuele actie, het \nscoren onder druk, een snelle omschakeling, \nde conditionele (anaeroob- lactisch)/ mentale \nfactoren\n- houdt in de organisatie ook aandacht voor: \ngenoeg ballen om het veld, een strakke felle \ncoaching."}]}'::jsonb),
  ('O8', 25, '{"session_a": [{"type": "warming_up", "title": "GEWOON TIKKERTJE", "content": "Methodiek\nElke speler heeft een bal aan zijn voet, behalve de tikker. De \ntikker probeert zo veel mogelijk spelers te tikken.\nVariatie:\n- De tikker heeft ook een bal.\n- De tikker kan spelers aftikken door hun bal weg te schoppen\nOpgelet!\nJe mag weer deelnemen als een \"vrije speler\" je weer \"vrij\" getikt \nheeft.Materialen\nDuur spel:10-15 min\nDuur ronde: 1 a 2 min\nAantal: 6-8 of meer spelers\nPylonen: 4 om het speelveld af te bakenen.\nBallen: voor iedere speler een balAanwijzingen\nWedstrijdopties:\nOptie 1: Tel het aantal getikte spelers.\nOptie 2: De getikte speler gaat aan de kant \nstaan.\nOptie 3: De getikte speler wordt de nieuwe \ntikker."}, {"type": "techniek", "title": "STAP 1: JEU DE VOETBAL", "content": "Methodiek\nDeze oefening wordt gespeelt met 2 spelers, die ieder met 3 \nballen bij een hoedje staan op de achterlijn.\nZij proberen nu de bal vanaf het hoedje zo dicht mogelijk, bij de, \nop 12 - 15 mtr. afstand geplaatste pylon, te spelen.\nDe winnaar is degene die de meeste ballen dichtbij de pylon weet \nte krijgen.\nVariatie:\n- afstand vergrotenMaterialen\nAantal spelers: 2\nAantal ballen: elke speler heeft 3 ballen\nHoedje: per tweetal 1 hoedje\nAantal pylonen: per tweetal één pylon\nAfstand tussen pylon en hoedje: 12-15 meterAanwijzingen\nSpelers coachen op:\n- schieten met de binnenkant van de voet.\n- standbeen in de richting van de pylon \nplaatsen\n- het schietbeen op de bal richten.\n- let goed op welke bal bij welke speler hoort"}, {"type": "partijvorm", "title": "PARTIJVORM 4:4 + 2 KEEPERS", "content": "Methodiek\nVier aanvallers moeten d.m.v. samenspel/ individuele actie 4 \nverdedigers uitspelen, om daarna in het tegenoverstaande doel te \nscoren.\nDe verdedigers kunnen de afgepakte bal scoren door hetzelfde \naan de andere kant van het vak te doen.\nOpgelet! \nBal buiten het veld, dan start het andere team de partij opnieuw.\nVariatie in uitvoering:\nMet 3 teams wisselen naar eigen inzicht.Materialen\nAantal spelers:8(12)+2(3) keepers\nAantal ballen: 5\nAantal pylonen: 4\nAfstand tussen pylonen:\nF-pupillen: 25m bij 20m\nE-pupillen: 30m bij 25m\nD-pupillen: 30m bij 25m\nC-junioren: 35m bij 30m\nB-,A-junioren: 40m bij 35m\nDoel: 2\nF- en E-pupillen: 5m bij 2m\nD-,C-,B-,A-junioren: 7.32m bij 2.44\nDoordraaien: \nHet winnende team blijft staan en het \nverliezende team wisselt met het 3e team.\nAls er na twee minuten nog niet is gescoord, dan \nwordt de partij die het langst in het veld staat \ngewisseld.Aanwijzingen\nBij de aanval coachen op:\n- het samenspelen vanuit een ruit vorm, \nwaarbij gebruik gemaakt moet worden van \nde vrije positie van de keeper (overtalsituatie)\n- het creëren van een twee tegen een situatie\n- het zo breed en diep mogelijk staan van de \ntwee buitenste spelers.\n- het rekening houden bij balverlies met \nomschakeling, ook bij het innemen van een \naanvallende positie.\nBij het verdedigen coachen op:\n- het knijpen, daar waar nodig\n- het coachen van elkaar ( het initiatief ligt bij \nde achterste speler).\n- het rekening houden bij balverovering met \nomschakeling.\nKeepers coachen op:\n- het altijd aanspeelbaar zijn bij balbezit\n- het coachen bij het verdedigen van je \nmedespelers\nOpmerkingen:\n- bij een partij op scherp mag men de bal vrij \nraken\n- accenten leggen op: individuele actie; \nscoren onder druk; snelle omschakeling;\n- in de organisatie aandacht voor: genoeg \nballen om het veld; strakke felle coaching"}], "session_b": [{"type": "warming_up", "title": "PARCOURS DRIBBELEN", "content": "Methodiek\nDe spelers slalommen dribbelend het hele parcours door.\nVariatie in aanbieden:\n- Varieer in uitvoeringssnelheid\n- Varieer onderlinge afstand pylonen.\n- Voer de oefening in wedstrijdvorm uit.Materialen\nAantal spelers: 4-10\nAantal ballen: elke speler 1 bal\nAantal pylonen: 8\nOnderlinge afstand pylonen: 2 a 3 meterAanwijzingen\nSpelers coachen op:\n- Houdt de bal dichtbij je, maar niet onder je.\n- Probeer de bal zoveel mogelijk te raken.\n- Probeer de bal bij iedere stap te raken, dan \nkun je de bal ook beter sturen."}, {"type": "techniek", "title": "PENALTY SCHIETEN", "content": "Methodiek\nIn het doel staan twee pylonen. De afstand tusssen de pylon en de \npaal is 2 meter.\nDe spelers proberen de bal in de rechter- of linkerhoek te schieten \ntussen de pylon en de paal.\nWie schiet de meeste penalties tussen de pylon en de paal?\nVariatie in uitvoering:\n- de afstand tussen de pylon en de paal verkleinen.\n- een keeper op doel zetten.Materialen\nAantal spelers: 4- 8 + (2 keepers)\nAantal ballen: ieder speler een bal\nAantal pylonen: 6\nSchietafstand:\nF- pupillen: 7m\nE-pupillen: 8m\nD-,C-,B-,A-junioren: 11m\nDoelen: 2\nF- en E-pupillen: 5m bij 2m\nD-,C-,B-,A-junioren: 7.32m bij 2.44m\nDoordraaien:\n- elke speler haalt, nadat hij geschoten heeft, \nzijn eigen bal op en sluit achter in de andere rij \naan.Aanwijzingen\nSpelers coachen op:\n- geef de bal de juiste snelheid mee.\n- bal in het hart raken.\n- spanning in de voet.\n- standbeen iets voorbij de bal, bal blijft laag."}, {"type": "partijvorm", "title": "PARTIJVORM 4:4 + 2 KEEPERS", "content": "Methodiek\nVier aanvallers moeten d.m.v. samenspel/ individuele actie 4 \nverdedigers uitspelen, om daarna in het tegenoverstaande doel te \nscoren.\nDe verdedigers kunnen de afgepakte bal scoren door hetzelfde \naan de andere kant van het vak te doen.\nOpgelet! \nBal buiten het veld, dan start het andere team de partij opnieuw.\nVariatie in uitvoering:\nMet 3 teams wisselen naar eigen inzicht.Materialen\nAantal spelers:8(12)+2(3) keepers\nAantal ballen: 5\nAantal pylonen: 4\nAfstand tussen pylonen:\nF-pupillen: 25m bij 20m\nE-pupillen: 30m bij 25m\nD-pupillen: 30m bij 25m\nC-junioren: 35m bij 30m\nB-,A-junioren: 40m bij 35m\nDoel: 2\nF- en E-pupillen: 5m bij 2m\nD-,C-,B-,A-junioren: 7.32m bij 2.44\nDoordraaien: \nHet winnende team blijft staan en het \nverliezende team wisselt met het 3e team.\nAls er na twee minuten nog niet is gescoord, dan \nwordt de partij die het langst in het veld staat \ngewisseld.Aanwijzingen\nBij de aanval coachen op:\n- het samenspelen vanuit een ruit vorm, \nwaarbij gebruik gemaakt moet worden van \nde vrije positie van de keeper (overtalsituatie)\n- het creëren van een twee tegen een situatie\n- het zo breed en diep mogelijk staan van de \ntwee buitenste spelers.\n- het rekening houden bij balverlies met \nomschakeling, ook bij het innemen van een \naanvallende positie.\nBij het verdedigen coachen op:\n- het knijpen, daar waar nodig\n- het coachen van elkaar ( het initiatief ligt bij \nde achterste speler).\n- het rekening houden bij balverovering met \nomschakeling.\nKeepers coachen op:\n- het altijd aanspeelbaar zijn bij balbezit\n- het coachen bij het verdedigen van je \nmedespelers\nOpmerkingen:\n- bij een partij op scherp mag men de bal vrij \nraken\n- accenten leggen op: individuele actie; \nscoren onder druk; snelle omschakeling;\n- in de organisatie aandacht voor: genoeg \nballen om het veld; strakke felle coaching"}]}'::jsonb),
  ('O8', 26, '{"session_a": [{"type": "warming_up", "title": "POORT TIKKERTJE", "content": "Methodiek\n1 speler probeert als tikker de anderen te tikken. Een getikte speler blijft \nwijdbeens staan. Elke \"vrije speler\" kan hen weer \"vrij\" tikken door de bal onder \nhun poortje door te spelen en direct weer onder controle mee te nemen.Materialen\nDuur:10-15 min\nDuur ronde: 1 a 2 min\nAantal: 6-8 of meer spelers\nPylonen: 4 om het speelveld af te bakenen.\nBallen: iedere speler een bal."}, {"type": "techniek", "title": "STAP 1: KEGELEN 2", "content": "Methodiek\n2 ploegen, iedere speler met 1 bal, staan ieder in hun \"eigen vak\" \ntegenover elkaar, met op de achterlijn pylonen met daarop rode \nof gele hoedjes.\nDe spelers moeten, vanaf hun achterlijn, de gele of rode hoedjes \nvan de pylonen schieten.\n- de ploeg die dit het eerst voor elkaar krijgt, is winnaar.Materialen\nAantal spelers: 6-10\nAantal hoedjes: 10 rode en 10 gele.\nAantal ballen: elke speler 1 bal.\nHesjes: 2 kleuren en voldoende voor iedere partij\nAantal pylonen: 24 (4 voor het speelveld en 20 \nvoor het spel)\nAfstand tussen de pylonen:\n- speelveld 25 bij 15 meter\n- pylonen met hoedjes naar eigen inzichtAanwijzingen\nSpelers coachen op:\n- met de binnenkant van de voet schieten\n- niet te zacht schieten\n- langs de pillonen schieten\n- minder pylonen maakt het voor de spelers \nmakkelijker\n- meer pylonen maakt het voor de spelers \nmoeilijker."}, {"type": "partijvorm", "title": "PARTIJVORM 5:5 (2)", "content": "Methodiek\nVijf aanvallers moeten d.m.v. samenspel/ individuele actie 5 \nverdedigers uitspelen, om daarna in het tegenoverstaande doel te \nscoren.\nDe verdedigers kunnen de afgepakte bal scoren door hetzelfde \naan de andere kant van het vak te doen.\nOpgelet! \nBal buiten het veld, dan start het andere team de partij opnieuw.\nVariatie in uitvoering:\nMet 3 teams wisselen naar eigen inzicht.Materialen\nAantal spelers: 10(15)+2(3) keepers\nAantal ballen: 5\nAantal pylonen: 4\nAfstand tussen pylonen:\nF-pupillen: 30m bij 25m\nE-pupillen: 30m bij 25m\nDoel: 2\nF- en E-junioren: 5m bij 2m\nDoordraaien: \n- het winnende team blijft staan en het \nverliezende team wisselt met het 3e team.\n- geen score na twee minuten, dan wordt de \nlangst staande partij gewisseld.Aanwijzingen\nBij de aanval coachen op:\n- het samenspelen vanuit een diamantvorm\n- het uiteen bewegen bij balbezit\n- het voorkomen van buitenspel\n- het maken van keuzes ( 1:1 of overspelen) \naan de bal\n- het rekening houden met omschakeling bij \nbalverlies en ook bij het innemen van een \naanvallende positie.\nBij het verdedigen coachen op:\n- het knijpen, daar waar nodig\n- het gebruik maken van de buitenspelregel\n- het coachen van elkaar (het initiatief ligt bij \nde achterste speler)\n- het rekening houden met omschakeling bij \nbalverovering.\nKeepers coachen op:\n- het altijd aanspeelbaar zijn bij balbezit\n- het coachen van je medespelers bij het \nverdedigen.\nOpmerkingen:\n- bij een partij op scherp mag men de bal vrij \nraken\n- leg accenten op: de individuele actie, het \nscoren onder druk, een snelle omschakeling, \nde conditionele (anaeroob- lactisch)/ mentale \nfactoren\n- houdt in de organisatie ook aandacht voor: \ngenoeg ballen om het veld, een strakke felle \ncoaching."}], "session_b": [{"type": "warming_up", "title": "PARCOURS DRIBBELEN/DRIJVEN", "content": "Methodiek\nDe spelers slalommen dribbelend het hele parcours door en het \nrechte stuk leggen ze dribbelend/ drijvend af.\nVariatie in aanbieden:\n- Varieer in uitvoeringssnelheid\n- Varieer onderlinge afstand pylonen.\n- Voer de oefening in wedstrijdvorm uit.\nLet op!\nSpeler 2 start wanneer speler 1 voorbij de tweede pylon is, enz.Materialen\nAantal spelers: 4-10 spelers\nAantal pylonen: 7\nAantal ballen: elke speler 1 bal\nOnderlinge afstand pylonen: 3 a 5 meterAanwijzingen\nSpelers coachen op:\n- Houdt de bal dichtbij je, maar niet onder je.\n- Probeer de bal zoveel mogelijk te raken.\n- Probeer de bal bij iedere stap te raken, dan \nkun je de bal ook beter sturen.\n- Bij het drijven op het rechte stuk mag de \nbal iets verder vooruit gespeeld worden. Niet \nte ver, behoud wel de controle over de bal."}, {"type": "techniek", "title": "IN STROOMVORM (1)", "content": "Methodiek\nDeze vorm wordt uitgevoerd met twee rijen spelers.\nA. Speler 1 of 2 speelt de bal met de binnenkant van de buitenste \nvoet in op de trainer en loopt daarna achter zijn bal aan.\nB. De trainer neemt de bal aan en legt de bal stil voor de \ninlopende speler 1 of 2.\nC. Speler 1 of 2 schiet vervolgens de stilliggende bal op doel, etc.\nVariatie in uitvoering: \nNa elk schot wisselen van rij.Materialen\nAantal spelers: 8- 10\nAantal ballen: elke speler heeft een bal\nAantal pylonen: 2\nDoelen: 1\nF-t/m E-pupillen: 5m bij 2m\nD-t/m A-junioren: 7.32m bij 2.44m\nAfstand trainer tot het doel:\n1 ste jaars F-pupillen: 5 m\n2e jaars F-pupillen: 8 m\n1e jaars E-pupillen: 10 m\n2e jaars E-pupillen: 12 m\nD-pupillen: 14 m\nC-,B-,A-junioren: >16 m\nDoordraaien:\nElke speler haalt, nadat hij geschoten heeft, zijn \neigen bal op en sluit weer achter in de rij aan.Aanwijzingen\nSpelers coachen op:\n- Bal in het hart raken\n- Spanning in de voet\n- Raakvlak: Binnenkant of volle wreef, \nafhankelijk van de situatie.\n- Standbeen iets voorbij de bal, bal blijft laag.\n- Standbeen iets achter de bal, bal aan de \nonderkant raken, bal gaat omhoog.\n- De overgang van het aan komen lopen naar \nhet schieten moet vloeiend verlopen."}, {"type": "partijvorm", "title": "PARTIJVORM 5:5 (2)", "content": "Methodiek\nVijf aanvallers moeten d.m.v. samenspel/ individuele actie 5 \nverdedigers uitspelen, om daarna in het tegenoverstaande doel te \nscoren.\nDe verdedigers kunnen de afgepakte bal scoren door hetzelfde \naan de andere kant van het vak te doen.\nOpgelet! \nBal buiten het veld, dan start het andere team de partij opnieuw.\nVariatie in uitvoering:\nMet 3 teams wisselen naar eigen inzicht.Materialen\nAantal spelers: 10(15)+2(3) keepers\nAantal ballen: 5\nAantal pylonen: 4\nAfstand tussen pylonen:\nF-pupillen: 30m bij 25m\nE-pupillen: 30m bij 25m\nDoel: 2\nF- en E-junioren: 5m bij 2m\nDoordraaien: \n- het winnende team blijft staan en het \nverliezende team wisselt met het 3e team.\n- geen score na twee minuten, dan wordt de \nlangst staande partij gewisseld.Aanwijzingen\nBij de aanval coachen op:\n- het samenspelen vanuit een diamantvorm\n- het uiteen bewegen bij balbezit\n- het voorkomen van buitenspel\n- het maken van keuzes ( 1:1 of overspelen) \naan de bal\n- het rekening houden met omschakeling bij \nbalverlies en ook bij het innemen van een \naanvallende positie.\nBij het verdedigen coachen op:\n- het knijpen, daar waar nodig\n- het gebruik maken van de buitenspelregel\n- het coachen van elkaar (het initiatief ligt bij \nde achterste speler)\n- het rekening houden met omschakeling bij \nbalverovering.\nKeepers coachen op:\n- het altijd aanspeelbaar zijn bij balbezit\n- het coachen van je medespelers bij het \nverdedigen.\nOpmerkingen:\n- bij een partij op scherp mag men de bal vrij \nraken\n- leg accenten op: de individuele actie, het \nscoren onder druk, een snelle omschakeling, \nde conditionele (anaeroob- lactisch)/ mentale \nfactoren\n- houdt in de organisatie ook aandacht voor: \ngenoeg ballen om het veld, een strakke felle \ncoaching."}]}'::jsonb),
  ('O8', 27, '{"session_a": [{"type": "warming_up", "title": "OVERLOOPSPEL", "content": "Methodiek\nAlle spelers staan, op één speler na, met een bal aan de voet aan één zijde van \nhet speelveld.\nDe tikker staat ook met een bal aan de voet in het speelveld.\nOp een teken moeten de spelers de bal naar de overkant dribbelen. De tikker \nprobeert nu met de bal zoveel mogelijk spelers onderweg af te tikken.\nWie tikt de meeste spelers af in 2 beurten?\nOpgelet!\n- als je de bal niet bij je houdt dan ben je ook af.\nVariatie:\n- ook de tikker heeft de bal aan de voet\n- opvoeren van het aantal beurten. Materialen\nDuur:10-15 min\nDuur ronde: 1 a 2 min\nAantal: 6-12 spelers\nPylonen: 4 om het speelveld af te bakenen."}, {"type": "techniek", "title": "STAP 1: KONINGEN", "content": "Methodiek\nTweetallen, staan op 10 - 15 mtr. afstand tegenover elkaar naast \neen 1 mtr. breed doeltje. Zij moeten proberen in het doeltje van \nde tegenoverstaande speler te scoren. \nWie de meeste goals maakt, binnen een bepaalde tijd of bepaald \naantal keer, is de \"koning\"!Materialen\nAantal spelers: 2-10 \nAantal doeltjes: per tweetal 1 doeltje\nAantal ballen: per tweetal 1 bal\nDoelgrootte: 1 meter\nAfstand tussen de doeltjes: 10-15 meterAanwijzingen\nSpelers coachen op:\n- schieten met de binnenkant van de voet\n- speelbeen loodrecht op de speelrichting\n- voetzool parallel met de grond."}, {"type": "partijvorm", "title": "PARTIJVORM 4:4 + 2 KEEPERS", "content": "Methodiek\nVier aanvallers moeten d.m.v. samenspel/ individuele actie 4 \nverdedigers uitspelen, om daarna in het tegenoverstaande doel te \nscoren.\nDe verdedigers kunnen de afgepakte bal scoren door hetzelfde \naan de andere kant van het vak te doen.\nOpgelet! \nBal buiten het veld, dan start het andere team de partij opnieuw.\nVariatie in uitvoering:\nMet 3 teams wisselen naar eigen inzicht.Materialen\nAantal spelers:8(12)+2(3) keepers\nAantal ballen: 5\nAantal pylonen: 4\nAfstand tussen pylonen:\nF-pupillen: 25m bij 20m\nE-pupillen: 30m bij 25m\nD-pupillen: 30m bij 25m\nC-junioren: 35m bij 30m\nB-,A-junioren: 40m bij 35m\nDoel: 2\nF- en E-pupillen: 5m bij 2m\nD-,C-,B-,A-junioren: 7.32m bij 2.44\nDoordraaien: \nHet winnende team blijft staan en het \nverliezende team wisselt met het 3e team.\nAls er na twee minuten nog niet is gescoord, dan \nwordt de partij die het langst in het veld staat \ngewisseld.Aanwijzingen\nBij de aanval coachen op:\n- het samenspelen vanuit een ruit vorm, \nwaarbij gebruik gemaakt moet worden van \nde vrije positie van de keeper (overtalsituatie)\n- het creëren van een twee tegen een situatie\n- het zo breed en diep mogelijk staan van de \ntwee buitenste spelers.\n- het rekening houden bij balverlies met \nomschakeling, ook bij het innemen van een \naanvallende positie.\nBij het verdedigen coachen op:\n- het knijpen, daar waar nodig\n- het coachen van elkaar ( het initiatief ligt bij \nde achterste speler).\n- het rekening houden bij balverovering met \nomschakeling.\nKeepers coachen op:\n- het altijd aanspeelbaar zijn bij balbezit\n- het coachen bij het verdedigen van je \nmedespelers\nOpmerkingen:\n- bij een partij op scherp mag men de bal vrij \nraken\n- accenten leggen op: individuele actie; \nscoren onder druk; snelle omschakeling;\n- in de organisatie aandacht voor: genoeg \nballen om het veld; strakke felle coaching"}], "session_b": [{"type": "warming_up", "title": "VOLGSPEL", "content": "Methodiek\nElk tweetal heeft een bal. De speler \"met bal\" probeert de speler \n\"zonder bal\" op een afstand van ca 1 - 2 mtr. overal binnen het \nvierkant te volgen.\nVariatie in aanbieden:\nMaak gebruik van tempowisselingen\nSpeler met bal loopt vooropMaterialen\nAantal spelers: 4-10\nAantal ballen: per tweetal 1 bal\nAantal pylonen: 4\nOnderlinge afstand pylonen: ongeveer 10 bij 15 \nmeter\nDoordraaien: \nWisselen van functie na een aantal minuten.Aanwijzingen\nSpelers coachen op:\n- Probeer zo goed mogelijk de voorste man te \nvolgen.\n- Houdt de bal dichtbij je, maar niet onder je.\n- Probeer de bal zoveel mogelijk te raken.\n- Probeer de bal bij elke stap te raken, dan \nkun je de bal ook beter sturen"}, {"type": "techniek", "title": "PARCOURS DRIBBELEN EN AFWERKEN", "content": "Methodiek\nDe spelers slalommen dribbelend het hele parcours door en werk \naf op doel.\nVariatie in aanbieden:\n- Varieer in uitvoeringssnelheid\n- Varieer onderlinge afstand pylonen.\n- Voer de oefening in wedstrijdvorm uit.Materialen\nAantal spelers: 4-10\nAantal ballen: elke speler 1 bal\nAantal pylonen: 8\nDoelen: 2\nOnderlinge afstand pylonen: 2 a 3 meterAanwijzingen\nSpelers coachen op:\n- Houdt de bal dichtbij je, maar niet onder je.\n- Probeer de bal zoveel mogelijk te raken.\n- Probeer de bal bij iedere stap te raken, dan \nkun je de bal ook beter sturen."}, {"type": "partijvorm", "title": "PARTIJVORM 4:4 + 2 KEEPERS", "content": "Methodiek\nVier aanvallers moeten d.m.v. samenspel/ individuele actie 4 \nverdedigers uitspelen, om daarna in het tegenoverstaande doel te \nscoren.\nDe verdedigers kunnen de afgepakte bal scoren door hetzelfde \naan de andere kant van het vak te doen.\nOpgelet! \nBal buiten het veld, dan start het andere team de partij opnieuw.\nVariatie in uitvoering:\nMet 3 teams wisselen naar eigen inzicht.Materialen\nAantal spelers:8(12)+2(3) keepers\nAantal ballen: 5\nAantal pylonen: 4\nAfstand tussen pylonen:\nF-pupillen: 25m bij 20m\nE-pupillen: 30m bij 25m\nD-pupillen: 30m bij 25m\nC-junioren: 35m bij 30m\nB-,A-junioren: 40m bij 35m\nDoel: 2\nF- en E-pupillen: 5m bij 2m\nD-,C-,B-,A-junioren: 7.32m bij 2.44\nDoordraaien: \nHet winnende team blijft staan en het \nverliezende team wisselt met het 3e team.\nAls er na twee minuten nog niet is gescoord, dan \nwordt de partij die het langst in het veld staat \ngewisseld.Aanwijzingen\nBij de aanval coachen op:\n- het samenspelen vanuit een ruit vorm, \nwaarbij gebruik gemaakt moet worden van \nde vrije positie van de keeper (overtalsituatie)\n- het creëren van een twee tegen een situatie\n- het zo breed en diep mogelijk staan van de \ntwee buitenste spelers.\n- het rekening houden bij balverlies met \nomschakeling, ook bij het innemen van een \naanvallende positie.\nBij het verdedigen coachen op:\n- het knijpen, daar waar nodig\n- het coachen van elkaar ( het initiatief ligt bij \nde achterste speler).\n- het rekening houden bij balverovering met \nomschakeling.\nKeepers coachen op:\n- het altijd aanspeelbaar zijn bij balbezit\n- het coachen bij het verdedigen van je \nmedespelers\nOpmerkingen:\n- bij een partij op scherp mag men de bal vrij \nraken\n- accenten leggen op: individuele actie; \nscoren onder druk; snelle omschakeling;\n- in de organisatie aandacht voor: genoeg \nballen om het veld; strakke felle coaching"}]}'::jsonb),
  ('O8', 28, '{"session_a": [{"type": "warming_up", "title": "DRIBBELTIKKERTJE", "content": "Methodiek\nAlle spelers, behalve de tikker, dribbelen met de bal aan de voet in het speelveld. \nDe tikker heeft zijn bal in de handen en moet nu met zijn bal proberen de bal van \neen dribbelende speler te tikken.\nAls dit is lukt, wordt de afgetikte speler de nieuwe tikker, etc. Materialen\nDuur:10-15 min\nDuur ronde: 1 a 2 min\nAantal: 6-12 spelers\nPylonen: 4 om het speelveld af te bakenen.\nAantal ballen: zoveel als nodig is voor het spel."}, {"type": "techniek", "title": "STAP 1: RAAK DE BAL", "content": "Methodiek\n2 ploegen, waarvan elke speler een bal heeft, staan tegenover \nelkaar op de achterlijn met in het midden een \"opvallende bal\". \nDe 2 groepen proberen de \"opvallende bal\" vanaf hun achterlijn \nover de lijn van de tegenstander te schieten.\n- het team dat de bal het eerst over de lijn van de tegenstander \nkrijgt scoort 1 punt\n- na elke score wordt de bal weer in het midden gelegd en start \nhet spel opnieuw.Materialen\nAantal spelers: 6-10\nAantal ballen: elke speler 1 bal en 1 \"opvallende \nbal\".\nAantal pylonen: 4 \nAfstand tussen de pylonen: 20 bij 15 meterAanwijzingen\nSpelers coachen op:\n- schieten met de binnenkant van de voet\n- standbeen in de richting van de bal\n- het schietbeen op de bal richten\n- gaat de bal uit dan komt die terug in het \nmidden ten hoogte van de plek waar de bal \nuit ging."}, {"type": "partijvorm", "title": "PARTIJVORM 5:5 (2)", "content": "Methodiek\nVijf aanvallers moeten d.m.v. samenspel/ individuele actie 5 \nverdedigers uitspelen, om daarna in het tegenoverstaande doel te \nscoren.\nDe verdedigers kunnen de afgepakte bal scoren door hetzelfde \naan de andere kant van het vak te doen.\nOpgelet! \nBal buiten het veld, dan start het andere team de partij opnieuw.\nVariatie in uitvoering:\nMet 3 teams wisselen naar eigen inzicht.Materialen\nAantal spelers: 10(15)+2(3) keepers\nAantal ballen: 5\nAantal pylonen: 4\nAfstand tussen pylonen:\nF-pupillen: 30m bij 25m\nE-pupillen: 30m bij 25m\nDoel: 2\nF- en E-junioren: 5m bij 2m\nDoordraaien: \n- het winnende team blijft staan en het \nverliezende team wisselt met het 3e team.\n- geen score na twee minuten, dan wordt de \nlangst staande partij gewisseld.Aanwijzingen\nBij de aanval coachen op:\n- het samenspelen vanuit een diamantvorm\n- het uiteen bewegen bij balbezit\n- het voorkomen van buitenspel\n- het maken van keuzes ( 1:1 of overspelen) \naan de bal\n- het rekening houden met omschakeling bij \nbalverlies en ook bij het innemen van een \naanvallende positie.\nBij het verdedigen coachen op:\n- het knijpen, daar waar nodig\n- het gebruik maken van de buitenspelregel\n- het coachen van elkaar (het initiatief ligt bij \nde achterste speler)\n- het rekening houden met omschakeling bij \nbalverovering.\nKeepers coachen op:\n- het altijd aanspeelbaar zijn bij balbezit\n- het coachen van je medespelers bij het \nverdedigen.\nOpmerkingen:\n- bij een partij op scherp mag men de bal vrij \nraken\n- leg accenten op: de individuele actie, het \nscoren onder druk, een snelle omschakeling, \nde conditionele (anaeroob- lactisch)/ mentale \nfactoren\n- houdt in de organisatie ook aandacht voor: \ngenoeg ballen om het veld, een strakke felle \ncoaching."}], "session_b": [{"type": "warming_up", "title": "LIJNORGANISATIE IN WEDSTRIJDVORM", "content": "Methodiek\nEén van de stappen van de onderstaande technieken dient, heen \nen terug tussen de lange zijden van de rechthoek, uitgevoerd te \nworden.\n- Heen d.m.v. Tippen voorwaarts, Aaien links of Lambada\n- Terug d.m.v. Tippen achterwaarts, Aaien rechts of Lambada\nWie doet dit het snelst? \nOpgelet! \nDeze oefening kan pas toegepast worden bij voldoende \nbeheersing van de technieken.\nDe technieken moeten wel goed worden uitgevoerd.Materialen\nAantal spelers: 1-8\nAantal ballen: elke speler 1 bal \nAantal pylonen: 2-16 (per speler twee pylonen)\nTwee rijen pylonen op een onderlinge afstand \nvan 8 mtr.\nOrganisatie:\nDe trainer geeft eerst een beeld van de oefening \nen controleert daarna de uitvoering.Aanwijzingen\nVoor de beschrijving van de techniek zie \ntechnieklijst."}, {"type": "techniek", "title": "PENALTY SCHIETEN", "content": "Methodiek\nIn het doel staan twee pylonen. De afstand tusssen de pylon en de \npaal is 2 meter.\nDe spelers proberen de bal in de rechter- of linkerhoek te schieten \ntussen de pylon en de paal.\nWie schiet de meeste penalties tussen de pylon en de paal?\nVariatie in uitvoering:\n- de afstand tussen de pylon en de paal verkleinen.\n- een keeper op doel zetten.Materialen\nAantal spelers: 4- 8 + (2 keepers)\nAantal ballen: ieder speler een bal\nAantal pylonen: 6\nSchietafstand:\nF- pupillen: 7m\nE-pupillen: 8m\nD-,C-,B-,A-junioren: 11m\nDoelen: 2\nF- en E-pupillen: 5m bij 2m\nD-,C-,B-,A-junioren: 7.32m bij 2.44m\nDoordraaien:\n- elke speler haalt, nadat hij geschoten heeft, \nzijn eigen bal op en sluit achter in de andere rij \naan.Aanwijzingen\nSpelers coachen op:\n- geef de bal de juiste snelheid mee.\n- bal in het hart raken.\n- spanning in de voet.\n- standbeen iets voorbij de bal, bal blijft laag."}, {"type": "partijvorm", "title": "PARTIJVORM 5:5 (2)", "content": "Methodiek\nVijf aanvallers moeten d.m.v. samenspel/ individuele actie 5 \nverdedigers uitspelen, om daarna in het tegenoverstaande doel te \nscoren.\nDe verdedigers kunnen de afgepakte bal scoren door hetzelfde \naan de andere kant van het vak te doen.\nOpgelet! \nBal buiten het veld, dan start het andere team de partij opnieuw.\nVariatie in uitvoering:\nMet 3 teams wisselen naar eigen inzicht.Materialen\nAantal spelers: 10(15)+2(3) keepers\nAantal ballen: 5\nAantal pylonen: 4\nAfstand tussen pylonen:\nF-pupillen: 30m bij 25m\nE-pupillen: 30m bij 25m\nDoel: 2\nF- en E-junioren: 5m bij 2m\nDoordraaien: \n- het winnende team blijft staan en het \nverliezende team wisselt met het 3e team.\n- geen score na twee minuten, dan wordt de \nlangst staande partij gewisseld.Aanwijzingen\nBij de aanval coachen op:\n- het samenspelen vanuit een diamantvorm\n- het uiteen bewegen bij balbezit\n- het voorkomen van buitenspel\n- het maken van keuzes ( 1:1 of overspelen) \naan de bal\n- het rekening houden met omschakeling bij \nbalverlies en ook bij het innemen van een \naanvallende positie.\nBij het verdedigen coachen op:\n- het knijpen, daar waar nodig\n- het gebruik maken van de buitenspelregel\n- het coachen van elkaar (het initiatief ligt bij \nde achterste speler)\n- het rekening houden met omschakeling bij \nbalverovering.\nKeepers coachen op:\n- het altijd aanspeelbaar zijn bij balbezit\n- het coachen van je medespelers bij het \nverdedigen.\nOpmerkingen:\n- bij een partij op scherp mag men de bal vrij \nraken\n- leg accenten op: de individuele actie, het \nscoren onder druk, een snelle omschakeling, \nde conditionele (anaeroob- lactisch)/ mentale \nfactoren\n- houdt in de organisatie ook aandacht voor: \ngenoeg ballen om het veld, een strakke felle \ncoaching."}]}'::jsonb),
  ('O8', 29, '{"session_a": [{"type": "warming_up", "title": "KETTINGTIKKERTJE", "content": "Methodiek\nBij dit spel staan alle spelers, met een bal aan de voet, in een vak. Twee spelers \nzijn de tikkers en moeten proberen de spelers uit te tikken door hun bal uit het \nspel te schieten.\nDe eerst afgetikte speler pakt, nadat zijn bal is uitgeschoten de hand van de \ntikker vast. Elke volgende afgetikte speler sluit daarna aan om zo een ketting te \nvormen. \nWelke verdediger behaalt de langste ketting (ofwel wie werken het beste samen?)\nOpmerking: \n- als tijdens het tkken de ketting breekt, dan mag de afgetikte speler gewoon \ndoorspelen.\nLet op: \n- de kettinggrootte mag niet groter worden dan 4 spelers (bij het vaststellen van \nhet resultaat wordt dan het totaal aantal afgetikte spelers geteld).Materialen\nPylonen: 4 pylonen om het speelveld uit te zetten.\nBallen: op een speler na heeft iedere speler een bal\nSpeeltijd: 10- 15 minuten"}, {"type": "techniek", "title": "STAP 1: VAK SCHIETEN", "content": "Methodiek\n2 ploegen, waarvan elke speler een bal heeft, staan achter elkaar \nbij het eerste hoedje. Vanaf dit punt moeten zij om beurten de bal \nin het vak proberen te spelen.\n- lukt dit, dan behaald men 1 punt. Bij 3 punten schuift men op \nnaar het tweede hoedje. Idem naar het derde en vierde hoedje.\nOpgelet!\n- bij drie opeenvolgende missers gaat men 1 plaats terug\n- winnaar is degene die het hele traject het eerst heeft afgelegd.\nVariatie:\n- bal met het andere been spelen.\n- vak vergroten/ verkleinen.\n- afstand naar het vak vergroten/ verkleinen.\nVariatie op organisatie vormen:\n- vanaf de middencircel in een klein vierkant proberen te schieten\n- vanaf de 16 meterlijn in een vierkant schieten\n- vanaf de 5 meterlijn de bal het dichst bij de 16 meter schieten \nen andersom.Materialen\nAantal spelers: 6-8\nAantal ballen: elke speler 1 bal.\nAantal pylonen: 8 (2 x 4 voor vierkant)\nAfstand tussen de pylonen: Vierkant 3 bij 2 meter\nHoedjes: 8 (2 x 4)\n1ste hoedje op 10 m\n2e hoedje op 15 m\n3e hoedje op 20 m\n4e hoedje op 25 mAanwijzingen\nSpelers coachen op:\n- schieten met de binnenkant van de voet\n- standbeen in de richting van het vak\n- het schietbeen hier loodrecht op gericht \nhouden."}, {"type": "partijvorm", "title": "PARTIJVORM 4:4 + 2 KEEPERS", "content": "Methodiek\nVier aanvallers moeten d.m.v. samenspel/ individuele actie 4 \nverdedigers uitspelen, om daarna in het tegenoverstaande doel te \nscoren.\nDe verdedigers kunnen de afgepakte bal scoren door hetzelfde \naan de andere kant van het vak te doen.\nOpgelet! \nBal buiten het veld, dan start het andere team de partij opnieuw.\nVariatie in uitvoering:\nMet 3 teams wisselen naar eigen inzicht.Materialen\nAantal spelers:8(12)+2(3) keepers\nAantal ballen: 5\nAantal pylonen: 4\nAfstand tussen pylonen:\nF-pupillen: 25m bij 20m\nE-pupillen: 30m bij 25m\nD-pupillen: 30m bij 25m\nC-junioren: 35m bij 30m\nB-,A-junioren: 40m bij 35m\nDoel: 2\nF- en E-pupillen: 5m bij 2m\nD-,C-,B-,A-junioren: 7.32m bij 2.44\nDoordraaien: \nHet winnende team blijft staan en het \nverliezende team wisselt met het 3e team.\nAls er na twee minuten nog niet is gescoord, dan \nwordt de partij die het langst in het veld staat \ngewisseld.Aanwijzingen\nBij de aanval coachen op:\n- het samenspelen vanuit een ruit vorm, \nwaarbij gebruik gemaakt moet worden van \nde vrije positie van de keeper (overtalsituatie)\n- het creëren van een twee tegen een situatie\n- het zo breed en diep mogelijk staan van de \ntwee buitenste spelers.\n- het rekening houden bij balverlies met \nomschakeling, ook bij het innemen van een \naanvallende positie.\nBij het verdedigen coachen op:\n- het knijpen, daar waar nodig\n- het coachen van elkaar ( het initiatief ligt bij \nde achterste speler).\n- het rekening houden bij balverovering met \nomschakeling.\nKeepers coachen op:\n- het altijd aanspeelbaar zijn bij balbezit\n- het coachen bij het verdedigen van je \nmedespelers\nOpmerkingen:\n- bij een partij op scherp mag men de bal vrij \nraken\n- accenten leggen op: individuele actie; \nscoren onder druk; snelle omschakeling;\n- in de organisatie aandacht voor: genoeg \nballen om het veld; strakke felle coaching"}], "session_b": [{"type": "warming_up", "title": "CLUBS / LANDENSPEL", "content": "Methodiek\nElke speler heeft een bal en dribbelt in het rond.\nIn de hoeken van het veld zijn vierkanten, die de namen dragen \nvan een voetbalclub of een land.\nBij het noemen van de naam van de club of het land moeten de \nspelers zo snel mogelijk naar het desbetreffende vak dribbelen en \ndaar met de voet op de bal blijven staan.\nDe laatst aangekomen speler krijgt een strafpunt.\nWinnaar is degene met de minste strafpunten.\nVariatie in aanbieden:\n- Met Kerst, Pasen of Sinterklaas gebruik je deze themagerichte \nnamen.\n- Spelers moeten de bal stoppen door b.v. op de bal te gaan zitten \nof iets anders te doen.Materialen\nAantal spelers: 4-10\nAantal ballen: elke speler 1 bal\nAantal pylonen: 16\nVeldafmeting: 20 bij 20 meter (incl. hoekvakken \nvan 4 bij 4 meter)Aanwijzingen\nSpelers coachen op:\n- De bal dichtbij je houden.\n- Probeer de bal zoveel mogelijk aan te raken.\n- Probeer bij iedere stap de bal een keer aan \nte raken.\n- Door het vele bal contact kunnen spelers \ngemakkelijker de bal sturen.\n- De bal moet onder de voet gestopt worden"}, {"type": "techniek", "title": "IN STROOMVORM (1)", "content": "Methodiek\nDeze vorm wordt uitgevoerd met twee rijen spelers.\nA. Speler 1 of 2 speelt de bal met de binnenkant van de buitenste \nvoet in op de trainer en loopt daarna achter zijn bal aan.\nB. De trainer neemt de bal aan en legt de bal stil voor de \ninlopende speler 1 of 2.\nC. Speler 1 of 2 schiet vervolgens de stilliggende bal op doel, etc.\nVariatie in uitvoering: \nNa elk schot wisselen van rij.Materialen\nAantal spelers: 8- 10\nAantal ballen: elke speler heeft een bal\nAantal pylonen: 2\nDoelen: 1\nF-t/m E-pupillen: 5m bij 2m\nD-t/m A-junioren: 7.32m bij 2.44m\nAfstand trainer tot het doel:\n1 ste jaars F-pupillen: 5 m\n2e jaars F-pupillen: 8 m\n1e jaars E-pupillen: 10 m\n2e jaars E-pupillen: 12 m\nD-pupillen: 14 m\nC-,B-,A-junioren: >16 m\nDoordraaien:\nElke speler haalt, nadat hij geschoten heeft, zijn \neigen bal op en sluit weer achter in de rij aan.Aanwijzingen\nSpelers coachen op:\n- Bal in het hart raken\n- Spanning in de voet\n- Raakvlak: Binnenkant of volle wreef, \nafhankelijk van de situatie.\n- Standbeen iets voorbij de bal, bal blijft laag.\n- Standbeen iets achter de bal, bal aan de \nonderkant raken, bal gaat omhoog.\n- De overgang van het aan komen lopen naar \nhet schieten moet vloeiend verlopen."}, {"type": "partijvorm", "title": "PARTIJVORM 4:4 + 2 KEEPERS", "content": "Methodiek\nVier aanvallers moeten d.m.v. samenspel/ individuele actie 4 \nverdedigers uitspelen, om daarna in het tegenoverstaande doel te \nscoren.\nDe verdedigers kunnen de afgepakte bal scoren door hetzelfde \naan de andere kant van het vak te doen.\nOpgelet! \nBal buiten het veld, dan start het andere team de partij opnieuw.\nVariatie in uitvoering:\nMet 3 teams wisselen naar eigen inzicht.Materialen\nAantal spelers:8(12)+2(3) keepers\nAantal ballen: 5\nAantal pylonen: 4\nAfstand tussen pylonen:\nF-pupillen: 25m bij 20m\nE-pupillen: 30m bij 25m\nD-pupillen: 30m bij 25m\nC-junioren: 35m bij 30m\nB-,A-junioren: 40m bij 35m\nDoel: 2\nF- en E-pupillen: 5m bij 2m\nD-,C-,B-,A-junioren: 7.32m bij 2.44\nDoordraaien: \nHet winnende team blijft staan en het \nverliezende team wisselt met het 3e team.\nAls er na twee minuten nog niet is gescoord, dan \nwordt de partij die het langst in het veld staat \ngewisseld.Aanwijzingen\nBij de aanval coachen op:\n- het samenspelen vanuit een ruit vorm, \nwaarbij gebruik gemaakt moet worden van \nde vrije positie van de keeper (overtalsituatie)\n- het creëren van een twee tegen een situatie\n- het zo breed en diep mogelijk staan van de \ntwee buitenste spelers.\n- het rekening houden bij balverlies met \nomschakeling, ook bij het innemen van een \naanvallende positie.\nBij het verdedigen coachen op:\n- het knijpen, daar waar nodig\n- het coachen van elkaar ( het initiatief ligt bij \nde achterste speler).\n- het rekening houden bij balverovering met \nomschakeling.\nKeepers coachen op:\n- het altijd aanspeelbaar zijn bij balbezit\n- het coachen bij het verdedigen van je \nmedespelers\nOpmerkingen:\n- bij een partij op scherp mag men de bal vrij \nraken\n- accenten leggen op: individuele actie; \nscoren onder druk; snelle omschakeling;\n- in de organisatie aandacht voor: genoeg \nballen om het veld; strakke felle coaching"}]}'::jsonb),
  ('O8', 30, '{"session_a": [{"type": "warming_up", "title": "PANNA GAME", "content": "Methodiek\nElke speler, op een na heeft een bal. Op een teken van de trainer \nmoeten de speler zonder bal, binnen een vooraf aangegeven tijd, \nzoveel mogelijk ballen van de andere spelers buiten het speelveld \nte trappen.\nElke speler moet zijn weggetrapte bal direct weer ophalen en op \nde plaats waar de bal is uitgeschoten gaan staan met de benen \nwijd en de bal boven hun hoofd in hun handen. De andere spelers \ndie nog niet zijn uitgeschoten kunnen hun medespelers vrij maken \ndoor de bal door de benen van de afgeschoten spelers te spelen. \nAls de tijd voorbij is wordt het aantal spelers dat nog met hun bal \nboven hun hoofd staan geteld. Het spel is voorbij als de \nverdedigers alle spelers met de bal boven hun hoofd hebben \nstaan.\nWie haalt het hoogste aantal?\nVariatie:\n- meer verdedigers of minder verdedigers.Materialen\nTijd: 10-15 min\nRonde tijden: 1 a 2 min\nPylonen: 4 pylonen om het speelveld uit te zetten\nBallen: Op een speler na heeft iedere speler een \nbal.Aanwijzingen\nVoor de verdedigers:\n- samenwerken en samen afspreken waar je \nde ballen gaat uitschieten. Want waar je de \nballen uitschiet daar moeten de spelers gaan \nstaan met hun bal. Uiteindelijk krijg je dan \neen grote groep spelers bij elkaar waardoor 1 \nof 2 spelers deze kunnen verdedigen en de \nandere kunnen de rest gaan uitschieten. (dit \nis de enige mogelijkheid om iederee af te \nkrijgen.)\nVoor de aanvallers:\n- kijken waar de verdedigers zijn. Op snelheid \nde verdedigers passeren en proberen je \nmedespelers vrij proberen te maken."}, {"type": "techniek", "title": "STAP 1: VAK SCHIETEN MET DRIBBELEN", "content": "Methodiek\n2 ploegen, bestaande uit 3 spelers met bal, staan bij de eerste \npylon.\nA. - de spelers moeten vanaf dit punt met de bal dribbelen naar \nde tweede pylon.\nB. - vervolgens in één keer schieten in het vak.\nLukt dit, dan behaald men 1 punt.\nOpgelet!\n- dribbelen en schieten moet in één beweging\n- winnaar is de ploeg met de meeste punten.\nVariatie:\n- bal met het andere been spelen\n- vak vergroten/ verkleinen\n- afstand naar het vak vergroten/ verkleinen.Materialen\nAantal spelers: 6-10\nAantal ballen: elke speler 1 bal\nAantal pylonen: 12\nAfstand tussen de pylonen:\n- Vierkant 3 bij 2 meter\n- Schietafstand:10, 15 of 20 meter\n- Dribbelafstand; 6 meterAanwijzingen\nSpelers coachen op:\n- schieten met de binnenkant van de voet\n- speelbeen loodrecht op de speelrichting\n- de overgang van de dribbel naar het \nschieten moet vloeiend verlopen."}, {"type": "partijvorm", "title": "PARTIJVORM 5:5 (2)", "content": "Methodiek\nVijf aanvallers moeten d.m.v. samenspel/ individuele actie 5 \nverdedigers uitspelen, om daarna in het tegenoverstaande doel te \nscoren.\nDe verdedigers kunnen de afgepakte bal scoren door hetzelfde \naan de andere kant van het vak te doen.\nOpgelet! \nBal buiten het veld, dan start het andere team de partij opnieuw.\nVariatie in uitvoering:\nMet 3 teams wisselen naar eigen inzicht.Materialen\nAantal spelers: 10(15)+2(3) keepers\nAantal ballen: 5\nAantal pylonen: 4\nAfstand tussen pylonen:\nF-pupillen: 30m bij 25m\nE-pupillen: 30m bij 25m\nDoel: 2\nF- en E-junioren: 5m bij 2m\nDoordraaien: \n- het winnende team blijft staan en het \nverliezende team wisselt met het 3e team.\n- geen score na twee minuten, dan wordt de \nlangst staande partij gewisseld.Aanwijzingen\nBij de aanval coachen op:\n- het samenspelen vanuit een diamantvorm\n- het uiteen bewegen bij balbezit\n- het voorkomen van buitenspel\n- het maken van keuzes ( 1:1 of overspelen) \naan de bal\n- het rekening houden met omschakeling bij \nbalverlies en ook bij het innemen van een \naanvallende positie.\nBij het verdedigen coachen op:\n- het knijpen, daar waar nodig\n- het gebruik maken van de buitenspelregel\n- het coachen van elkaar (het initiatief ligt bij \nde achterste speler)\n- het rekening houden met omschakeling bij \nbalverovering.\nKeepers coachen op:\n- het altijd aanspeelbaar zijn bij balbezit\n- het coachen van je medespelers bij het \nverdedigen.\nOpmerkingen:\n- bij een partij op scherp mag men de bal vrij \nraken\n- leg accenten op: de individuele actie, het \nscoren onder druk, een snelle omschakeling, \nde conditionele (anaeroob- lactisch)/ mentale \nfactoren\n- houdt in de organisatie ook aandacht voor: \ngenoeg ballen om het veld, een strakke felle \ncoaching."}], "session_b": [{"type": "warming_up", "title": "FLUIT / NUMMERSPEL", "content": "Methodiek\nElke speler dribbelt met een bal door het vak. De trainer gebruikt de vooraf aan \ngegeven tekens.\nBij het fluiten of het roepen van een nummer moeten de spelers de daarbij \nbehorende afgesproken tekens uitvoeren, zoals:\n- Naar de zijkant dribbelen\n- Een kapbeweging maken\n- De bal stil leggen onder de voet\n- Een versnelling maken met de bal aan de voet\n- De bal hooghouden.\n- Op de bal zitten\n- Wisselen van bal met een andere speler.\nOpgelet!\nMaak er een puntenspel van.\nWie behaalt de minste strafpunten?Materialen\nTijd: 10-15 min\nRonde tijden: 1 a 2 min\nPylonen: 4 pylonen om het speelveld uit te zetten\nBallen: iedere speler heeft een bal."}, {"type": "techniek", "title": "PARCOURS DRIBBELEN EN AFWERKEN", "content": "Methodiek\nDe spelers slalommen dribbelend het hele parcours door en werk \naf op doel.\nVariatie in aanbieden:\n- Varieer in uitvoeringssnelheid\n- Varieer onderlinge afstand pylonen.\n- Voer de oefening in wedstrijdvorm uit.Materialen\nAantal spelers: 4-10\nAantal ballen: elke speler 1 bal\nAantal pylonen: 8\nDoelen: 2\nOnderlinge afstand pylonen: 2 a 3 meterAanwijzingen\nSpelers coachen op:\n- Houdt de bal dichtbij je, maar niet onder je.\n- Probeer de bal zoveel mogelijk te raken.\n- Probeer de bal bij iedere stap te raken, dan \nkun je de bal ook beter sturen."}, {"type": "partijvorm", "title": "PARTIJVORM 5:5 (2)", "content": "Methodiek\nVijf aanvallers moeten d.m.v. samenspel/ individuele actie 5 \nverdedigers uitspelen, om daarna in het tegenoverstaande doel te \nscoren.\nDe verdedigers kunnen de afgepakte bal scoren door hetzelfde \naan de andere kant van het vak te doen.\nOpgelet! \nBal buiten het veld, dan start het andere team de partij opnieuw.\nVariatie in uitvoering:\nMet 3 teams wisselen naar eigen inzicht.Materialen\nAantal spelers: 10(15)+2(3) keepers\nAantal ballen: 5\nAantal pylonen: 4\nAfstand tussen pylonen:\nF-pupillen: 30m bij 25m\nE-pupillen: 30m bij 25m\nDoel: 2\nF- en E-junioren: 5m bij 2m\nDoordraaien: \n- het winnende team blijft staan en het \nverliezende team wisselt met het 3e team.\n- geen score na twee minuten, dan wordt de \nlangst staande partij gewisseld.Aanwijzingen\nBij de aanval coachen op:\n- het samenspelen vanuit een diamantvorm\n- het uiteen bewegen bij balbezit\n- het voorkomen van buitenspel\n- het maken van keuzes ( 1:1 of overspelen) \naan de bal\n- het rekening houden met omschakeling bij \nbalverlies en ook bij het innemen van een \naanvallende positie.\nBij het verdedigen coachen op:\n- het knijpen, daar waar nodig\n- het gebruik maken van de buitenspelregel\n- het coachen van elkaar (het initiatief ligt bij \nde achterste speler)\n- het rekening houden met omschakeling bij \nbalverovering.\nKeepers coachen op:\n- het altijd aanspeelbaar zijn bij balbezit\n- het coachen van je medespelers bij het \nverdedigen.\nOpmerkingen:\n- bij een partij op scherp mag men de bal vrij \nraken\n- leg accenten op: de individuele actie, het \nscoren onder druk, een snelle omschakeling, \nde conditionele (anaeroob- lactisch)/ mentale \nfactoren\n- houdt in de organisatie ook aandacht voor: \ngenoeg ballen om het veld, een strakke felle \ncoaching."}]}'::jsonb),
  ('O8', 31, '{"session_a": [{"type": "warming_up", "title": "GEWOON TIKKERTJE", "content": "Methodiek\nElke speler heeft een bal aan zijn voet, behalve de tikker. De \ntikker probeert zo veel mogelijk spelers te tikken.\nVariatie:\n- De tikker heeft ook een bal.\n- De tikker kan spelers aftikken door hun bal weg te schoppen\nOpgelet!\nJe mag weer deelnemen als een \"vrije speler\" je weer \"vrij\" getikt \nheeft.Materialen\nDuur spel:10-15 min\nDuur ronde: 1 a 2 min\nAantal: 6-8 of meer spelers\nPylonen: 4 om het speelveld af te bakenen.\nBallen: voor iedere speler een balAanwijzingen\nWedstrijdopties:\nOptie 1: Tel het aantal getikte spelers.\nOptie 2: De getikte speler gaat aan de kant \nstaan.\nOptie 3: De getikte speler wordt de nieuwe \ntikker."}, {"type": "techniek", "title": "STAP 1: VOETBAL CURLING", "content": "Methodiek\nVerdeel het speelveld in 5 vakken van elk 1 meter breed. De \nspelers schieten de bal op een afstand van 10 meter vanaf het \nmiddelste vak. \nHet behaalde aantal punten van de 3 pogingen wordt bij elkaar \nopgeteld.\nT.b.v. puntentelling:\n- middelste vak 5 punten\n- de vakken daarnaast 3 punten\n- buitenste vak 1 punt\n- daarbuiten 0\n- winnaar is degene met de meeste punten.\nVariatie:\n- schietafstand vergroten tot 15 en/ of 20 meter.Materialen\nAantal spelers: 2-4\nAantal pylonen: 20\nAantal ballen: elke speler 1 bal\nSchietafstand: 10, 15 en 20 meterAanwijzingen\nSpelers coachen op:\n- schieten met de binnenkant van de voet.\n- standbeen in de richting van het vak.\n- het schietbeen hier loodrecht op gericht \nhouden."}, {"type": "partijvorm", "title": "PARTIJVORM 4:4 + 2 KEEPERS", "content": "Methodiek\nVier aanvallers moeten d.m.v. samenspel/ individuele actie 4 \nverdedigers uitspelen, om daarna in het tegenoverstaande doel te \nscoren.\nDe verdedigers kunnen de afgepakte bal scoren door hetzelfde \naan de andere kant van het vak te doen.\nOpgelet! \nBal buiten het veld, dan start het andere team de partij opnieuw.\nVariatie in uitvoering:\nMet 3 teams wisselen naar eigen inzicht.Materialen\nAantal spelers:8(12)+2(3) keepers\nAantal ballen: 5\nAantal pylonen: 4\nAfstand tussen pylonen:\nF-pupillen: 25m bij 20m\nE-pupillen: 30m bij 25m\nD-pupillen: 30m bij 25m\nC-junioren: 35m bij 30m\nB-,A-junioren: 40m bij 35m\nDoel: 2\nF- en E-pupillen: 5m bij 2m\nD-,C-,B-,A-junioren: 7.32m bij 2.44\nDoordraaien: \nHet winnende team blijft staan en het \nverliezende team wisselt met het 3e team.\nAls er na twee minuten nog niet is gescoord, dan \nwordt de partij die het langst in het veld staat \ngewisseld.Aanwijzingen\nBij de aanval coachen op:\n- het samenspelen vanuit een ruit vorm, \nwaarbij gebruik gemaakt moet worden van \nde vrije positie van de keeper (overtalsituatie)\n- het creëren van een twee tegen een situatie\n- het zo breed en diep mogelijk staan van de \ntwee buitenste spelers.\n- het rekening houden bij balverlies met \nomschakeling, ook bij het innemen van een \naanvallende positie.\nBij het verdedigen coachen op:\n- het knijpen, daar waar nodig\n- het coachen van elkaar ( het initiatief ligt bij \nde achterste speler).\n- het rekening houden bij balverovering met \nomschakeling.\nKeepers coachen op:\n- het altijd aanspeelbaar zijn bij balbezit\n- het coachen bij het verdedigen van je \nmedespelers\nOpmerkingen:\n- bij een partij op scherp mag men de bal vrij \nraken\n- accenten leggen op: individuele actie; \nscoren onder druk; snelle omschakeling;\n- in de organisatie aandacht voor: genoeg \nballen om het veld; strakke felle coaching"}], "session_b": [{"type": "warming_up", "title": "LIJNEN SPEL", "content": "Methodiek\nDe spelers staan met de bal aan de voet op een door de trainer \naangegeven lijn van het 16- meter gebied. Op zijn teken dribbelen \nde spelers naar een door de trainer aangegeven andere lijn.\nOpgelet!\nGeen 16- meter gebied beschikbaar, maak dan gebruik van \nverschillend gekleurde pylonen of hoedjes om daarmee lijnen te \nvormen\nMaak bij de\" jongste jeugd\" gebruik van nummers.\nVariatie:\n- Geef elke speler bij aanvang 3 punten en haal bij de laatste \ntelkens 1 punt af. Winnaar is ook nu weer degene die over blijft.\n- Laatste valt steeds af en winnaar is degene die over blijft (alleen \ndoen als afsluiting van een training).Materialen\nAantal spelers: 4-14\nAantal pylonen: 10 (om eventueel de lijnen aan \nte geven)\nAantal ballen: elke speler 1 balAanwijzingen\nSpelers coachen op:\n- Draai eerst proef.\n- De bal moet wel steeds op de lijn onder de \nvoet stil liggen."}, {"type": "techniek", "title": "PENALTY SCHIETEN", "content": "Methodiek\nIn het doel staan twee pylonen. De afstand tusssen de pylon en de \npaal is 2 meter.\nDe spelers proberen de bal in de rechter- of linkerhoek te schieten \ntussen de pylon en de paal.\nWie schiet de meeste penalties tussen de pylon en de paal?\nVariatie in uitvoering:\n- de afstand tussen de pylon en de paal verkleinen.\n- een keeper op doel zetten.Materialen\nAantal spelers: 4- 8 + (2 keepers)\nAantal ballen: ieder speler een bal\nAantal pylonen: 6\nSchietafstand:\nF- pupillen: 7m\nE-pupillen: 8m\nD-,C-,B-,A-junioren: 11m\nDoelen: 2\nF- en E-pupillen: 5m bij 2m\nD-,C-,B-,A-junioren: 7.32m bij 2.44m\nDoordraaien:\n- elke speler haalt, nadat hij geschoten heeft, \nzijn eigen bal op en sluit achter in de andere rij \naan.Aanwijzingen\nSpelers coachen op:\n- geef de bal de juiste snelheid mee.\n- bal in het hart raken.\n- spanning in de voet.\n- standbeen iets voorbij de bal, bal blijft laag."}, {"type": "partijvorm", "title": "PARTIJVORM 4:4 + 2 KEEPERS", "content": "Methodiek\nVier aanvallers moeten d.m.v. samenspel/ individuele actie 4 \nverdedigers uitspelen, om daarna in het tegenoverstaande doel te \nscoren.\nDe verdedigers kunnen de afgepakte bal scoren door hetzelfde \naan de andere kant van het vak te doen.\nOpgelet! \nBal buiten het veld, dan start het andere team de partij opnieuw.\nVariatie in uitvoering:\nMet 3 teams wisselen naar eigen inzicht.Materialen\nAantal spelers:8(12)+2(3) keepers\nAantal ballen: 5\nAantal pylonen: 4\nAfstand tussen pylonen:\nF-pupillen: 25m bij 20m\nE-pupillen: 30m bij 25m\nD-pupillen: 30m bij 25m\nC-junioren: 35m bij 30m\nB-,A-junioren: 40m bij 35m\nDoel: 2\nF- en E-pupillen: 5m bij 2m\nD-,C-,B-,A-junioren: 7.32m bij 2.44\nDoordraaien: \nHet winnende team blijft staan en het \nverliezende team wisselt met het 3e team.\nAls er na twee minuten nog niet is gescoord, dan \nwordt de partij die het langst in het veld staat \ngewisseld.Aanwijzingen\nBij de aanval coachen op:\n- het samenspelen vanuit een ruit vorm, \nwaarbij gebruik gemaakt moet worden van \nde vrije positie van de keeper (overtalsituatie)\n- het creëren van een twee tegen een situatie\n- het zo breed en diep mogelijk staan van de \ntwee buitenste spelers.\n- het rekening houden bij balverlies met \nomschakeling, ook bij het innemen van een \naanvallende positie.\nBij het verdedigen coachen op:\n- het knijpen, daar waar nodig\n- het coachen van elkaar ( het initiatief ligt bij \nde achterste speler).\n- het rekening houden bij balverovering met \nomschakeling.\nKeepers coachen op:\n- het altijd aanspeelbaar zijn bij balbezit\n- het coachen bij het verdedigen van je \nmedespelers\nOpmerkingen:\n- bij een partij op scherp mag men de bal vrij \nraken\n- accenten leggen op: individuele actie; \nscoren onder druk; snelle omschakeling;\n- in de organisatie aandacht voor: genoeg \nballen om het veld; strakke felle coaching"}]}'::jsonb),
  ('O8', 32, '{"session_a": [{"type": "warming_up", "title": "POORT TIKKERTJE", "content": "Methodiek\n1 speler probeert als tikker de anderen te tikken. Een getikte speler blijft \nwijdbeens staan. Elke \"vrije speler\" kan hen weer \"vrij\" tikken door de bal onder \nhun poortje door te spelen en direct weer onder controle mee te nemen.Materialen\nDuur:10-15 min\nDuur ronde: 1 a 2 min\nAantal: 6-8 of meer spelers\nPylonen: 4 om het speelveld af te bakenen.\nBallen: iedere speler een bal."}, {"type": "techniek", "title": "STAP 1: VER GOOIEN", "content": "Methodiek\nIs een spel waarbij men probeert de bal, op een correcte wijze, zo \nver mogelijk langs de uitgezette lijn pylonen in te gooien.\nA. Speler 1 staat bij de pylon, op 2 mtr. afstand van de uitgezette \nreeks pylonen en probeert de bal met een inworp zo ver mogelijk \nin te gooien.\nB. Speler 2 staat naast de rij pylonen en pakt de ingegooide bal op \nen wisselt van functie met speler 1, etc.\nOpgelet!\n- waar de bal de grond raakt, bepaald de afstand.\n- winnaar is degene die na 10 wissels het verst heeft gegooid.Materialen\nAantal spelers: 2\nAantal pylonen:8\nAantal ballen: 1\nAfstand tussen de pylonen: 1 meter\nDoordraaien:\n- na elke worp wisselen van functie.Aanwijzingen\n- gezicht naar de persoon naar wie hij gaat \ngooien.\n- beiden voeten houden contact met de \ngrond.\n- de bal achter het hoofd loslaten\n- beide handen op de bal houden.\n- voeten in de richting van het gooien."}, {"type": "partijvorm", "title": "PARTIJVORM 5:5 (2)", "content": "Methodiek\nVijf aanvallers moeten d.m.v. samenspel/ individuele actie 5 \nverdedigers uitspelen, om daarna in het tegenoverstaande doel te \nscoren.\nDe verdedigers kunnen de afgepakte bal scoren door hetzelfde \naan de andere kant van het vak te doen.\nOpgelet! \nBal buiten het veld, dan start het andere team de partij opnieuw.\nVariatie in uitvoering:\nMet 3 teams wisselen naar eigen inzicht.Materialen\nAantal spelers: 10(15)+2(3) keepers\nAantal ballen: 5\nAantal pylonen: 4\nAfstand tussen pylonen:\nF-pupillen: 30m bij 25m\nE-pupillen: 30m bij 25m\nDoel: 2\nF- en E-junioren: 5m bij 2m\nDoordraaien: \n- het winnende team blijft staan en het \nverliezende team wisselt met het 3e team.\n- geen score na twee minuten, dan wordt de \nlangst staande partij gewisseld.Aanwijzingen\nBij de aanval coachen op:\n- het samenspelen vanuit een diamantvorm\n- het uiteen bewegen bij balbezit\n- het voorkomen van buitenspel\n- het maken van keuzes ( 1:1 of overspelen) \naan de bal\n- het rekening houden met omschakeling bij \nbalverlies en ook bij het innemen van een \naanvallende positie.\nBij het verdedigen coachen op:\n- het knijpen, daar waar nodig\n- het gebruik maken van de buitenspelregel\n- het coachen van elkaar (het initiatief ligt bij \nde achterste speler)\n- het rekening houden met omschakeling bij \nbalverovering.\nKeepers coachen op:\n- het altijd aanspeelbaar zijn bij balbezit\n- het coachen van je medespelers bij het \nverdedigen.\nOpmerkingen:\n- bij een partij op scherp mag men de bal vrij \nraken\n- leg accenten op: de individuele actie, het \nscoren onder druk, een snelle omschakeling, \nde conditionele (anaeroob- lactisch)/ mentale \nfactoren\n- houdt in de organisatie ook aandacht voor: \ngenoeg ballen om het veld, een strakke felle \ncoaching."}], "session_b": [{"type": "warming_up", "title": "OVERSTEEK SPEL", "content": "Methodiek\nAlle spelers staan met de bal aan de voet aan één kant van het \nveld en één speler staat zonder bal in het midden. Op een teken \nvan de trainer mogen de spelers proberen het veld over te steken. \nDe tikker moet vervolgens proberen de ballen van de spelers \nbuiten het veld te schieten.\nDe spelers van een weggeschoten bal gaan ook in het midden \nstaan om de bal af te pakken.\nVariatie:\n- De spelers moeten zelf hun weggetrapte bal ophalen en weer bij \nde groep aansluiten.\n- Weggeschoten bal ophalen en dan wachten om te zien wie er \nover blijft. De winnaar mag de nieuwe tikker zijn of aanwijzen.\n- Twee of meerdere afpakkers.Materialen\nTijd: 10-15 min\nPylonen: \n4 pylonen om het speelveld uit te zetten.\n2 pylonen/hoedjes om de middenlijn uit te zetten.\nBallen: iedere speler een bal op de tikker na die \nde ballen gaat afpakken.Aanwijzingen\n- Zorg dat de spelers de bal dicht bij zich \nhouden zodat ze de bal goed kunnen sturen.\n- Laat de spelers telkens op het teken van de \ntrainer starten."}, {"type": "techniek", "title": "IN STROOMVORM (1)", "content": "Methodiek\nDeze vorm wordt uitgevoerd met twee rijen spelers.\nA. Speler 1 of 2 speelt de bal met de binnenkant van de buitenste \nvoet in op de trainer en loopt daarna achter zijn bal aan.\nB. De trainer neemt de bal aan en legt de bal stil voor de \ninlopende speler 1 of 2.\nC. Speler 1 of 2 schiet vervolgens de stilliggende bal op doel, etc.\nVariatie in uitvoering: \nNa elk schot wisselen van rij.Materialen\nAantal spelers: 8- 10\nAantal ballen: elke speler heeft een bal\nAantal pylonen: 2\nDoelen: 1\nF-t/m E-pupillen: 5m bij 2m\nD-t/m A-junioren: 7.32m bij 2.44m\nAfstand trainer tot het doel:\n1 ste jaars F-pupillen: 5 m\n2e jaars F-pupillen: 8 m\n1e jaars E-pupillen: 10 m\n2e jaars E-pupillen: 12 m\nD-pupillen: 14 m\nC-,B-,A-junioren: >16 m\nDoordraaien:\nElke speler haalt, nadat hij geschoten heeft, zijn \neigen bal op en sluit weer achter in de rij aan.Aanwijzingen\nSpelers coachen op:\n- Bal in het hart raken\n- Spanning in de voet\n- Raakvlak: Binnenkant of volle wreef, \nafhankelijk van de situatie.\n- Standbeen iets voorbij de bal, bal blijft laag.\n- Standbeen iets achter de bal, bal aan de \nonderkant raken, bal gaat omhoog.\n- De overgang van het aan komen lopen naar \nhet schieten moet vloeiend verlopen."}, {"type": "partijvorm", "title": "PARTIJVORM 5:5 (2)", "content": "Methodiek\nVijf aanvallers moeten d.m.v. samenspel/ individuele actie 5 \nverdedigers uitspelen, om daarna in het tegenoverstaande doel te \nscoren.\nDe verdedigers kunnen de afgepakte bal scoren door hetzelfde \naan de andere kant van het vak te doen.\nOpgelet! \nBal buiten het veld, dan start het andere team de partij opnieuw.\nVariatie in uitvoering:\nMet 3 teams wisselen naar eigen inzicht.Materialen\nAantal spelers: 10(15)+2(3) keepers\nAantal ballen: 5\nAantal pylonen: 4\nAfstand tussen pylonen:\nF-pupillen: 30m bij 25m\nE-pupillen: 30m bij 25m\nDoel: 2\nF- en E-junioren: 5m bij 2m\nDoordraaien: \n- het winnende team blijft staan en het \nverliezende team wisselt met het 3e team.\n- geen score na twee minuten, dan wordt de \nlangst staande partij gewisseld.Aanwijzingen\nBij de aanval coachen op:\n- het samenspelen vanuit een diamantvorm\n- het uiteen bewegen bij balbezit\n- het voorkomen van buitenspel\n- het maken van keuzes ( 1:1 of overspelen) \naan de bal\n- het rekening houden met omschakeling bij \nbalverlies en ook bij het innemen van een \naanvallende positie.\nBij het verdedigen coachen op:\n- het knijpen, daar waar nodig\n- het gebruik maken van de buitenspelregel\n- het coachen van elkaar (het initiatief ligt bij \nde achterste speler)\n- het rekening houden met omschakeling bij \nbalverovering.\nKeepers coachen op:\n- het altijd aanspeelbaar zijn bij balbezit\n- het coachen van je medespelers bij het \nverdedigen.\nOpmerkingen:\n- bij een partij op scherp mag men de bal vrij \nraken\n- leg accenten op: de individuele actie, het \nscoren onder druk, een snelle omschakeling, \nde conditionele (anaeroob- lactisch)/ mentale \nfactoren\n- houdt in de organisatie ook aandacht voor: \ngenoeg ballen om het veld, een strakke felle \ncoaching."}]}'::jsonb);
